fn persist_product_runtime_if_expected<T>(
    runtime: Option<T>,
    expected: bool,
    persist: impl FnOnce(T) -> Result<(), String>,
) -> Result<(), String> {
    match runtime {
        Some(runtime) => persist(runtime),
        None if expected => Err("session_store_unavailable".into()),
        None => Ok(()),
    }
}

