trait PairingRecoveryTransport {
    type Versioned;

    fn load_optional(&self, pair_id: &str) -> Result<Option<Self::Versioned>, String>;
    fn descriptor(value: &Self::Versioned) -> &isyncyou_agent::PairingDescriptorV2;
    fn compare_and_swap(
        &self,
        current: &Self::Versioned,
        next: &isyncyou_agent::PairingDescriptorV2,
    ) -> Result<Option<Self::Versioned>, String>;
    fn delete(&self, current: &Self::Versioned) -> Result<bool, String>;
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl PairingRecoveryTransport for isyncyou_agent::OneDrivePairingTransportV2 {
    type Versioned = isyncyou_agent::VersionedPairingDescriptorV2;

    fn load_optional(&self, pair_id: &str) -> Result<Option<Self::Versioned>, String> {
        isyncyou_agent::OneDrivePairingTransportV2::load_optional(self, pair_id)
            .map_err(|error| error.to_string())
    }

    fn descriptor(value: &Self::Versioned) -> &isyncyou_agent::PairingDescriptorV2 {
        &value.descriptor
    }

    fn compare_and_swap(
        &self,
        current: &Self::Versioned,
        next: &isyncyou_agent::PairingDescriptorV2,
    ) -> Result<Option<Self::Versioned>, String> {
        isyncyou_agent::OneDrivePairingTransportV2::compare_and_swap(self, current, next)
            .map_err(|error| error.to_string())
    }

    fn delete(&self, current: &Self::Versioned) -> Result<bool, String> {
        isyncyou_agent::OneDrivePairingTransportV2::delete(self, current)
            .map_err(|error| error.to_string())
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl LifecycleMaintenanceRuntime {
    fn spawn(context: LifecycleMaintenanceContext) -> Self {
        Self::spawn_with_interval(context, std::time::Duration::from_secs(60))
    }

    fn spawn_with_interval(
        context: LifecycleMaintenanceContext,
        interval: std::time::Duration,
    ) -> Self {
        let (tx, rx) = std::sync::mpsc::channel();
        let join = std::thread::Builder::new()
            .name("agent-account-lifecycle-maintenance".into())
            .spawn(move || {
                run_account_maintenance_once(
                    &context,
                    AccountMaintenancePass::DeferredWorkerStartup,
                );
                loop {
                    match rx.recv_timeout(interval) {
                        Ok(()) | Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => break,
                        Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {
                            run_account_maintenance_once(
                                &context,
                                AccountMaintenancePass::Periodic,
                            );
                        }
                    }
                }
                run_account_maintenance_once(&context, AccountMaintenancePass::Periodic);
            })
            .ok();
        Self {
            stop: Some(tx),
            join,
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Clone, Copy)]
enum AccountMaintenancePass {
    StartupRecovery,
    DeferredWorkerStartup,
    Periodic,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl AccountMaintenancePass {
    fn recover_interrupted_exchange(self) -> bool {
        matches!(self, Self::StartupRecovery)
    }

    fn includes_lifecycle_recovery(self) -> bool {
        !matches!(self, Self::DeferredWorkerStartup)
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn run_account_maintenance_once(
    context: &LifecycleMaintenanceContext,
    pass: AccountMaintenancePass,
) {
    let recover_interrupted_exchange = pass.recover_interrupted_exchange();
    let _ = context.oauth.reap_expired();
    if let Some(store) = &context.control_store {
        let _ = store.reap_expired(unix_now_ms(), 256);
        reconcile_pending_cancel_projections(&context.cfg, &context.oauth_dir, store, 8);
        reconcile_pending_confirm_projections(&context.cfg, &context.oauth_dir, store, 8);
    }
    if let Ok(mut attempts) = context.oauth_attempts.lock() {
        let expired = reap_oauth_attempts(&mut attempts, &context.oauth_dir);
        if let Ok(mut bindings) = context.oauth_lifecycle_bindings.lock() {
            for attempt_id in expired {
                bindings.remove(&attempt_id);
            }
        }
    }
    reap_onboarding_journals_at(&context.oauth_dir, now_ms());
    let maintenance_now_ms = unix_now_ms();
    if product_session_maintenance_due_for_pass(
        &context.session_maintenance_last_ms,
        maintenance_now_ms,
        recover_interrupted_exchange,
    ) {
        run_product_session_maintenance_once(context);
    }
    if pass.includes_lifecycle_recovery() {
        run_lifecycle_maintenance_once_at_with_recovery(
            &context.cfg,
            &context.oauth_dir,
            &context.provider_leases,
            &context.product_runtime_gate,
            &context.last_usage,
            now_ms(),
            recover_interrupted_exchange,
        );
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn product_session_maintenance_due_for_pass(
    last_ms: &AtomicU64,
    now_ms: u64,
    startup_recovery: bool,
) -> bool {
    // Provider-backed session compaction and pairing descriptor cleanup can involve
    // multiple bounded network requests. The owned maintenance thread runs its first
    // pass immediately, so construction performs only fail-closed local/account
    // lifecycle recovery and cannot delay binding the product listener.
    !startup_recovery && product_session_maintenance_due(last_ms, now_ms, false)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn product_session_maintenance_due(last_ms: &AtomicU64, now_ms: u64, force: bool) -> bool {
    if force {
        last_ms.store(now_ms, Ordering::Release);
        return true;
    }
    loop {
        let last = last_ms.load(Ordering::Acquire);
        if now_ms.saturating_sub(last) < PRODUCT_SESSION_MAINTENANCE_INTERVAL_MS {
            return false;
        }
        if last_ms
            .compare_exchange(last, now_ms, Ordering::AcqRel, Ordering::Acquire)
            .is_ok()
        {
            return true;
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn run_product_session_maintenance_once(context: &LifecycleMaintenanceContext) {
    let Some(control_store) = context.control_store.as_ref() else {
        return;
    };
    let Ok(credential_store) = agent_credential_store(&context.oauth_dir) else {
        return;
    };
    let registry = product_session::ProductSessionRegistry::new(&credential_store);
    let maintenance_now_ms = unix_now_ms();
    if let Ok(repository) = account_lifecycle_repository(&context.oauth_dir) {
        if let Ok(Some(installation)) = repository.load_existing() {
            recover_pairing_claims_once(
                &context.cfg,
                control_store,
                &registry,
                installation.principal(),
                maintenance_now_ms,
            );
        }
    }
    cleanup_pairing_claim_descriptors_once(&context.cfg, control_store, maintenance_now_ms);
    let Ok(targets) = registry.maintenance_targets() else {
        return;
    };
    cleanup_pairing_descriptors_once(&context.cfg, control_store, &targets, maintenance_now_ms);
    if targets.is_empty() {
        let _ = control_store.claim_session_maintenance_offset(0, 0);
        return;
    }
    let Ok(offset) = control_store
        .claim_session_maintenance_offset(targets.len(), PRODUCT_SESSION_MAINTENANCE_BATCH)
    else {
        return;
    };
    for target in targets
        .iter()
        .cycle()
        .skip(offset)
        .take(PRODUCT_SESSION_MAINTENANCE_BATCH.min(targets.len()))
    {
        let Ok(token) =
            isyncyou_engine::auth::resolve_cached_sync_token(&context.cfg, &target.local_account)
        else {
            continue;
        };
        let _ = registry.maintain_remote_session(&token, target, PRODUCT_SESSION_COMPACTION_BATCH);
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn recover_pairing_claims_once(
    cfg: &Config,
    control_store: &agent_control_store::AgentControlStore,
    registry: &product_session::ProductSessionRegistry<'_>,
    installation_principal: &str,
    now_ms: u64,
) {
    let Ok(targets) =
        control_store.pairing_claim_recovery_targets(PAIRING_CLAIM_RECOVERY_BATCH, now_ms)
    else {
        return;
    };
    for target in targets {
        let Ok(token) =
            isyncyou_engine::auth::resolve_cached_sync_token(cfg, &target.local_account)
        else {
            continue;
        };
        let transport = isyncyou_agent::OneDrivePairingTransportV2::new(token);
        let _ = recover_pairing_claim_target(
            control_store,
            registry,
            &target,
            installation_principal,
            now_ms,
            &transport,
        );
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn recover_pairing_claim_target<T: PairingRecoveryTransport>(
    control_store: &agent_control_store::AgentControlStore,
    registry: &product_session::ProductSessionRegistry<'_>,
    target: &agent_control_store::PairingClaimRecoveryTarget,
    installation_principal: &str,
    now_ms: u64,
    transport: &T,
) -> Result<(), String> {
    let (code, claim) =
        control_store.load_pairing_claim(&target.operation_id, installation_principal, now_ms)?;
    if target.state == "claimed" {
        let current = transport
            .load_optional(code.pair_id())?
            .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
        if let Some(next) = claim
            .claim_transition(T::descriptor(&current))
            .map_err(|error| error.to_string())?
        {
            let published = transport
                .compare_and_swap(&current, &next)?
                .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
            if T::descriptor(&published) != &next {
                return Err("pairing_outcome_unknown".into());
            }
        }
        let session = registry.import_pairing_payload(
            &target.request_id,
            &target.local_account,
            &claim.payload,
            now_ms,
        )?;
        control_store.mark_pairing_claim_installed(&target.operation_id, &session.session_id)?;
    }

    if !control_store
        .pairing_claim_remote_consumed(&target.operation_id, &target.finalize_request_id)?
    {
        let current = transport
            .load_optional(code.pair_id())?
            .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
        let consumed = claim
            .finalize(T::descriptor(&current))
            .map_err(|error| error.to_string())?;
        let terminal = if &consumed == T::descriptor(&current) {
            current
        } else {
            let published = transport
                .compare_and_swap(&current, &consumed)?
                .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
            if T::descriptor(&published) != &consumed {
                return Err("pairing_outcome_unknown".into());
            }
            published
        };
        control_store.mark_pairing_claim_remote_consumed(
            &target.operation_id,
            &target.finalize_request_id,
        )?;
        if transport.delete(&terminal).is_ok_and(|deleted| deleted) {
            let _ =
                control_store.mark_pairing_claim_descriptor_cleanup_complete(&target.operation_id);
        }
    } else {
        match transport.load_optional(code.pair_id()) {
            Ok(None) => {
                let _ = control_store
                    .mark_pairing_claim_descriptor_cleanup_complete(&target.operation_id);
            }
            Ok(Some(current)) => {
                if claim
                    .finalize(T::descriptor(&current))
                    .is_ok_and(|descriptor| &descriptor == T::descriptor(&current))
                    && transport.delete(&current).is_ok_and(|deleted| deleted)
                {
                    let _ = control_store
                        .mark_pairing_claim_descriptor_cleanup_complete(&target.operation_id);
                }
            }
            Err(_) => {}
        }
    }
    control_store.complete_pairing_claim(&target.operation_id, &target.finalize_request_id, now_ms)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn cleanup_pairing_claim_descriptors_once(
    cfg: &Config,
    control_store: &agent_control_store::AgentControlStore,
    now_ms: u64,
) {
    let Ok(targets) =
        control_store.pairing_claim_descriptor_cleanup_targets(PAIRING_DESCRIPTOR_CLEANUP_BATCH)
    else {
        return;
    };
    for target in targets {
        let Ok(token) =
            isyncyou_engine::auth::resolve_cached_sync_token(cfg, &target.local_account)
        else {
            continue;
        };
        let transport = isyncyou_agent::OneDrivePairingTransportV2::new(token);
        let _ = cleanup_pairing_claim_descriptor_target(control_store, &target, now_ms, &transport);
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn cleanup_pairing_claim_descriptor_target<T: PairingRecoveryTransport>(
    control_store: &agent_control_store::AgentControlStore,
    target: &agent_control_store::PairingClaimDescriptorCleanupTarget,
    now_ms: u64,
    transport: &T,
) -> Result<(), String> {
    if let Some(current) = transport.load_optional(&target.pair_id)? {
        let descriptor = T::descriptor(&current);
        if descriptor.pair_id != target.pair_id {
            return Err("pairing_outcome_unknown".into());
        }
        let valid_state = match target.state.as_str() {
            "consumed" => descriptor.state == isyncyou_agent::PairingRemoteStateV2::Consumed,
            "claimed_expired" => true,
            _ => false,
        };
        if !valid_state || !descriptor.cleanup_eligible_at(now_ms).unwrap_or(false) {
            return Err("pairing_outcome_unknown".into());
        }
        if !transport.delete(&current)? {
            return Err("pairing_outcome_unknown".into());
        }
    }
    control_store.mark_pairing_claim_descriptor_cleanup_complete(&target.operation_id)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn cleanup_pairing_source_descriptor_target<T: PairingRecoveryTransport>(
    control_store: &agent_control_store::AgentControlStore,
    target: &agent_control_store::PairingDescriptorCleanupTarget,
    now_ms: u64,
    transport: &T,
) -> Result<(), String> {
    let Some(current) = transport.load_optional(&target.pair_id)? else {
        return control_store.mark_pairing_source_descriptor_cleanup_complete(&target.pair_id);
    };
    let descriptor = T::descriptor(&current);
    if descriptor.pair_id != target.pair_id {
        return Err("pairing_outcome_unknown".into());
    }
    if !descriptor.cleanup_eligible_at(now_ms).unwrap_or(false) {
        return Ok(());
    }
    if !transport.delete(&current)? {
        return Err("pairing_outcome_unknown".into());
    }
    control_store.mark_pairing_source_descriptor_cleanup_complete(&target.pair_id)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn cleanup_pairing_descriptors_once(
    cfg: &Config,
    control_store: &agent_control_store::AgentControlStore,
    session_targets: &[product_session::ProductSessionMaintenanceTarget],
    now_ms: u64,
) {
    let Ok(cleanup_targets) =
        control_store.pairing_descriptor_cleanup_targets(PAIRING_DESCRIPTOR_CLEANUP_BATCH)
    else {
        return;
    };
    for cleanup in cleanup_targets {
        let Some(session) = session_targets
            .iter()
            .find(|target| target.session_id == cleanup.session_id)
        else {
            continue;
        };
        let Ok(token) =
            isyncyou_engine::auth::resolve_cached_sync_token(cfg, &session.local_account)
        else {
            continue;
        };
        let transport = isyncyou_agent::OneDrivePairingTransportV2::new(token);
        let _ =
            cleanup_pairing_source_descriptor_target(control_store, &cleanup, now_ms, &transport);
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn reconcile_pending_cancel_projections(
    cfg: &Config,
    oauth_dir: &Path,
    store: &agent_control_store::AgentControlStore,
    limit: usize,
) {
    let Ok(projections) = store.pending_cancel_projections(limit) else {
        return;
    };
    for projection in projections {
        if project_pending_cancel(cfg, oauth_dir, &projection).is_ok() {
            let _ = store.complete_pending_cancel_projection(&projection.pending_id);
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn reconcile_pending_confirm_projections(
    cfg: &Config,
    oauth_dir: &Path,
    store: &agent_control_store::AgentControlStore,
    limit: usize,
) {
    let Ok(projections) = store.pending_confirm_projections(limit) else {
        return;
    };
    for projection in projections {
        if project_pending_confirm(cfg, oauth_dir, &projection).is_ok() {
            let _ = store.complete_pending_confirm_projection(&projection.pending_id);
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn project_pending_cancel(
    cfg: &Config,
    oauth_dir: &Path,
    projection: &agent_control_store::PendingCancelProjection,
) -> Result<(), String> {
    if projection.owner.session_id == "legacy-local" {
        return Ok(());
    }
    let token = isyncyou_engine::auth::resolve_cached_sync_token(cfg, &projection.owner.account)
        .map_err(|_| "session_transport_unavailable".to_string())?;
    let credential_store =
        agent_credential_store(oauth_dir).map_err(|_| "session_store_unavailable".to_string())?;
    let repository = account_lifecycle_repository(oauth_dir)?;
    let installation = repository
        .load_existing()
        .map_err(|_| "session_store_unavailable".to_string())?
        .ok_or_else(|| "session_store_unavailable".to_string())?;
    product_session::ProductSessionRegistry::new(&credential_store).append_pending_cancelled(
        &token,
        &projection.owner,
        installation.principal(),
        projection.created_at_ms,
    )
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn project_pending_confirm(
    cfg: &Config,
    oauth_dir: &Path,
    projection: &agent_control_store::PendingConfirmProjection,
) -> Result<(), String> {
    if projection.owner.session_id == "legacy-local" {
        return Ok(());
    }
    let token = isyncyou_engine::auth::resolve_cached_sync_token(cfg, &projection.owner.account)
        .map_err(|_| "session_transport_unavailable".to_string())?;
    let credential_store =
        agent_credential_store(oauth_dir).map_err(|_| "session_store_unavailable".to_string())?;
    let repository = account_lifecycle_repository(oauth_dir)?;
    let installation = repository
        .load_existing()
        .map_err(|_| "session_store_unavailable".to_string())?
        .ok_or_else(|| "session_store_unavailable".to_string())?;
    product_session::ProductSessionRegistry::new(&credential_store).append_pending_operation_state(
        &token,
        &projection.owner,
        installation.principal(),
        &projection.code,
        projection.created_at_ms,
    )
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl Drop for LifecycleMaintenanceRuntime {
    fn drop(&mut self) {
        if let Some(stop) = self.stop.take() {
            let _ = stop.send(());
        }
        if let Some(join) = self.join.take() {
            let _ = join.join();
        }
    }
}

#[cfg(all(
    test,
    any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    )
))]
fn run_lifecycle_maintenance_once_at(
    cfg: &Config,
    oauth_dir: &Path,
    provider_leases: &Arc<account_lifecycle::ProviderLeaseRegistry>,
    product_runtime_gate: &Arc<Mutex<()>>,
    last_usage: &Arc<Mutex<BTreeMap<ProductProviderId, isyncyou_agent::Usage>>>,
    maintenance_now_ms: u64,
) {
    run_lifecycle_maintenance_once_at_with_recovery(
        cfg,
        oauth_dir,
        provider_leases,
        product_runtime_gate,
        last_usage,
        maintenance_now_ms,
        false,
    );
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn run_lifecycle_maintenance_once_at_with_recovery(
    cfg: &Config,
    oauth_dir: &Path,
    provider_leases: &Arc<account_lifecycle::ProviderLeaseRegistry>,
    product_runtime_gate: &Arc<Mutex<()>>,
    last_usage: &Arc<Mutex<BTreeMap<ProductProviderId, isyncyou_agent::Usage>>>,
    maintenance_now_ms: u64,
    recover_interrupted_exchange: bool,
) {
    let Ok(repository) = audited_account_lifecycle_repository(oauth_dir, cfg) else {
        return;
    };
    let Ok(Some(context)) = repository.load_existing() else {
        return;
    };
    for (provider, active) in context.authority.active_operations {
        let Ok(maintenance_id) = account_lifecycle::mint_operation_id() else {
            continue;
        };
        let Ok(_lease) = provider_leases.acquire_exclusive(
            oauth_dir,
            provider,
            maintenance_id,
            account_lifecycle::ProviderOperationKind::Maintenance,
        ) else {
            continue;
        };
        let Ok(_runtime) = product_runtime_gate.lock() else {
            continue;
        };
        let Ok(_snapshot) = acquire_product_runtime_file_lock(oauth_dir) else {
            continue;
        };
        let Ok(Some(current)) = repository.load_existing() else {
            continue;
        };
        let Some(current_active) = current.authority.active_operations.get(&provider) else {
            continue;
        };
        if current_active.operation_etag != active.operation_etag
            || current_active.prepared.fence_epoch != active.prepared.fence_epoch
        {
            continue;
        }
        let Ok(Some(journal)) = repository.recover_active_journal(provider, maintenance_now_ms)
        else {
            continue;
        };
        match journal.phase {
            account_lifecycle::AccountLifecyclePhase::CandidateValidation
            | account_lifecycle::AccountLifecyclePhase::Completed => {
                let candidate_id = repository
                    .candidate_record_id(provider, &journal.prepared.operation_id)
                    .ok();
                let candidate = candidate_id
                    .as_deref()
                    .and_then(|id| repository.load_candidate(id).ok().flatten());
                let credential_id = match provider {
                    ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
                    ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
                };
                let committed_generation = candidate
                    .as_ref()
                    .and_then(|candidate| candidate.result_generation.as_deref());
                let bundle = load_product_bundle_meta(oauth_dir, credential_id);
                let activation = load_product_activation(oauth_dir, provider);
                let selection = load_agent_provider_selection(oauth_dir);
                let product_commit_matches = committed_generation.is_some_and(|generation| {
                    bundle.as_ref().is_some_and(|meta| {
                        meta.lifecycle == CredentialLifecycle::Active
                            && meta.generation == generation
                            && meta.policy_fingerprint == oauth_policy_fingerprint(provider)
                    }) && activation.as_ref().is_some_and(|activation| {
                        activation.matches(
                            provider,
                            generation,
                            &oauth_policy_fingerprint(provider),
                            isyncyou_agent::HARNESS_CONTRACT_VERSION,
                        )
                    }) && selection
                        .as_ref()
                        .is_some_and(|settings| settings.provider == provider)
                });
                if product_commit_matches {
                    if let (Some(candidate_id), Some(generation)) =
                        (candidate_id.as_deref(), committed_generation)
                    {
                        let _ = repository.promote_candidate(
                            &active.journal_record_id,
                            candidate_id,
                            generation,
                            maintenance_now_ms,
                        );
                    }
                } else if journal.phase
                    == account_lifecycle::AccountLifecyclePhase::CandidateValidation
                {
                    let partial_commit_is_owned = candidate.as_ref().is_some_and(|candidate| {
                        if candidate.state != account_lifecycle::OAuthCandidateState::GrantBearing {
                            return false;
                        }
                        match candidate.result_generation.as_deref() {
                            Some(generation) => {
                                bundle.as_ref().is_none_or(|meta| {
                                    meta.lifecycle == CredentialLifecycle::Active
                                        && meta.generation == generation
                                        && meta.policy_fingerprint
                                            == oauth_policy_fingerprint(provider)
                                }) && activation.as_ref().is_none_or(|activation| {
                                    activation.matches(
                                        provider,
                                        generation,
                                        &oauth_policy_fingerprint(provider),
                                        isyncyou_agent::HARNESS_CONTRACT_VERSION,
                                    )
                                })
                            }
                            None => {
                                bundle.is_none()
                                    && activation.is_none()
                                    && !selection
                                        .as_ref()
                                        .is_some_and(|settings| settings.provider == provider)
                            }
                        }
                    });
                    if partial_commit_is_owned
                        && delete_provider_product_state_durable(oauth_dir, provider).is_ok()
                    {
                        if let Ok(mut usage) = last_usage.lock() {
                            usage.remove(&provider);
                        }
                        let _ = repository.require_candidate_cleanup(
                            &active.journal_record_id,
                            "candidate_activation_interrupted",
                            maintenance_now_ms,
                        );
                    }
                }
            }
            account_lifecycle::AccountLifecyclePhase::RevokedPendingCleanup
            | account_lifecycle::AccountLifecyclePhase::Disconnected => {
                if delete_provider_product_state_durable(oauth_dir, provider).is_ok()
                    && repository
                        .complete_disconnect(&active.journal_record_id, maintenance_now_ms)
                        .is_ok()
                {
                    if let Ok(mut usage) = last_usage.lock() {
                        usage.remove(&provider);
                    }
                }
            }
            account_lifecycle::AccountLifecyclePhase::RevokeInFlight
                if journal.in_flight_until_ms != 0
                    && journal.in_flight_until_ms <= maintenance_now_ms =>
            {
                let _ = repository.publish_revoke_outcome(
                    &active.journal_record_id,
                    false,
                    "revoke_interrupted",
                    maintenance_now_ms,
                );
            }
            account_lifecycle::AccountLifecyclePhase::ExchangeInFlight
                if recover_interrupted_exchange
                    || journal.in_flight_until_ms != 0
                        && journal.in_flight_until_ms <= maintenance_now_ms =>
            {
                let has_intent = repository
                    .load_exchange_intent(provider, &journal.prepared.operation_id)
                    .ok()
                    .flatten()
                    .is_some();
                if has_intent {
                    let _ = repository.transition_journal(
                        &active.journal_record_id,
                        account_lifecycle::AccountLifecyclePhase::ExchangeInFlight,
                        account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown,
                        Some("exchange_outcome_unknown"),
                        maintenance_now_ms,
                    );
                }
            }
            account_lifecycle::AccountLifecyclePhase::RevokeOutcomeUnknown
            | account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown => {}
            _ => {}
        }
    }
    for provider in ProductProviderId::ALL {
        let Ok(maintenance_id) = account_lifecycle::mint_operation_id() else {
            continue;
        };
        let Ok(_lease) = provider_leases.acquire_exclusive(
            oauth_dir,
            provider,
            maintenance_id,
            account_lifecycle::ProviderOperationKind::Maintenance,
        ) else {
            continue;
        };
        let Ok(_runtime) = product_runtime_gate.lock() else {
            continue;
        };
        let Ok(_snapshot) = acquire_product_runtime_file_lock(oauth_dir) else {
            continue;
        };
        let credential_id = match provider {
            ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
            ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
        };
        let protected_generation =
            load_product_bundle_meta(oauth_dir, credential_id).map(|meta| meta.generation);
        if repository
            .cleanup_terminal_operation_artifacts(provider)
            .is_err()
        {
            continue;
        }
        let _ = repository.compact_terminal_receipts(
            provider,
            protected_generation.as_deref(),
            maintenance_now_ms,
        );
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
enum OAuthAttempt {
    Claude {
        state: String,
        expires_at: std::time::Instant,
    },
    Codex {
        cancelled: Arc<AtomicBool>,
        expires_at: std::time::Instant,
    },
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct OAuthLifecycleAttemptBinding {
    provider: ProductProviderId,
    operation_id: String,
    authorize_url: String,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const OAUTH_ATTEMPT_TTL: std::time::Duration = std::time::Duration::from_secs(8 * 60);

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn reap_oauth_attempts(
    attempts: &mut HashMap<String, OAuthAttempt>,
    oauth_dir: &Path,
) -> Vec<String> {
    let now = std::time::Instant::now();
    let expired: Vec<(String, ProductProviderId)> = attempts
        .iter()
        .filter_map(|(attempt_id, attempt)| {
            let (expires_at, provider) = match attempt {
                OAuthAttempt::Claude { expires_at, .. } => (expires_at, ProductProviderId::Claude),
                OAuthAttempt::Codex { expires_at, .. } => (expires_at, ProductProviderId::Codex),
            };
            (*expires_at <= now).then(|| (attempt_id.clone(), provider))
        })
        .collect();
    attempts.retain(|_, attempt| match attempt {
        OAuthAttempt::Claude { expires_at, .. } | OAuthAttempt::Codex { expires_at, .. } => {
            *expires_at > now
        }
    });
    for (attempt_id, provider) in &expired {
        record_onboarding_attempt_transition(
            oauth_dir,
            *provider,
            attempt_id,
            ProductOnboardingState::ErrorRedacted,
            Some("expired".into()),
        );
    }
    expired
        .into_iter()
        .map(|(attempt_id, _)| attempt_id)
        .collect()
}

/// #639 T7: the typed reason a turn was refused before any turn state was created. It maps to a
/// closed wire code the router turns into a specific HTTP status (never a blanket 500).
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum AgentStartTurnError {
    /// The selected product provider is not host-verified ready (no valid activated credential),
    /// and no experimental fallback applies. Closed wire code `product_not_ready` -> HTTP 409.
    ProductNotReady,
    /// Another turn, refresh, or lifecycle mutation currently owns the provider lease.
    ProviderBusy,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl AgentStartTurnError {
    fn wire(self) -> &'static str {
        match self {
            Self::ProductNotReady => "product_not_ready",
            Self::ProviderBusy => "provider_busy",
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
#[allow(dead_code)]
struct AccountLifecycleResult {
    state: &'static str,
    code: &'static str,
    retryable: bool,
    operation_id: Option<String>,
    operation_etag: Option<String>,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn lifecycle_api_response(
    provider: ProductProviderId,
    mode: account_lifecycle::AccountLifecycleMode,
    result: AccountLifecycleResult,
) -> isyncyou_webui::AgentAccountLifecycleResponse {
    isyncyou_webui::AgentAccountLifecycleResponse {
        provider: provider.wire().into(),
        mode: match mode {
            account_lifecycle::AccountLifecycleMode::Connect => "connect",
            account_lifecycle::AccountLifecycleMode::Disconnect => "disconnect",
            account_lifecycle::AccountLifecycleMode::Reconnect => "reconnect",
            account_lifecycle::AccountLifecycleMode::Switch => "switch",
        }
        .into(),
        operation_id: result.operation_id,
        operation_etag: result.operation_etag,
        state: result.state.into(),
        revoke_leg: u32::from(mode != account_lifecycle::AccountLifecycleMode::Connect),
        revoked_grant: (mode != account_lifecycle::AccountLifecycleMode::Connect)
            .then(|| "active_credential".into()),
        revoke_request_target: (mode != account_lifecycle::AccountLifecycleMode::Connect)
            .then(|| "refresh_token".into()),
        revoke_scope_guarantee: (mode != account_lifecycle::AccountLifecycleMode::Connect)
            .then(|| "observed_token_session".into()),
        retryable: result.retryable,
        code: result.code.into(),
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[allow(dead_code)]
fn revoke_failure_wire(code: isyncyou_agent::oauth::RevokeFailureCode) -> &'static str {
    use isyncyou_agent::oauth::RevokeFailureCode::*;
    match code {
        InvalidCredential => "revoke_invalid_credential",
        ConnectTimedOut => "revoke_connect_timed_out",
        NameResolutionFailed => "revoke_name_resolution_failed",
        TlsFailed => "revoke_tls_failed",
        ConnectFailed => "revoke_connect_failed",
        RateLimited => "revoke_rate_limited",
        ProviderUnavailable => "revoke_provider_unavailable",
        Rejected => "revoke_rejected",
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn lifecycle_mode(value: &str) -> Option<account_lifecycle::AccountLifecycleMode> {
    match value {
        "disconnect" => Some(account_lifecycle::AccountLifecycleMode::Disconnect),
        "reconnect" => Some(account_lifecycle::AccountLifecycleMode::Reconnect),
        "switch" => Some(account_lifecycle::AccountLifecycleMode::Switch),
        _ => None,
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn require_revoke_scope_acknowledgement(
    scope: isyncyou_agent::oauth::RevokeScopeGuarantee,
    acknowledged: bool,
) -> Result<(), String> {
    if scope == isyncyou_agent::oauth::RevokeScopeGuarantee::FullGrant && !acknowledged {
        return Err("acknowledgement_required".into());
    }
    Ok(())
}

/// The in-app agent handler (S-AG.6/#621). Product turns require a host-attested
/// Claude/Codex OAuth provider; deterministic providers are injected only by tests.
/// Owns the stream hub + pending-action registry, so the model never holds a capability token.
pub struct DaemonAgent {
    /// Source of each account's `archive_root` for the retrieval executor
    /// (`archive_root_for`); the restore path lands in #624.
    cfg: Config,
    hub: Arc<isyncyou_agent::AgentStreamHub>,
    turns: Arc<TurnRegistry>,
    pending: Arc<isyncyou_agent::PendingRegistry>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    control_store: Option<Arc<agent_control_store::AgentControlStore>>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    control_store_state: &'static str,
    confirmed_executor: Arc<dyn AgentConfirmedActionExecutor>,
    audit_sink: Arc<dyn AgentAuditSink>,
    streams: Mutex<std::collections::HashMap<String, AgentStreamSlot>>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental",
        test
    ))]
    turn_admissions: Arc<TurnAdmissionRegistry>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    turn_recovery_error: Mutex<Option<String>>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental",
        test
    ))]
    hot_request_statuses: Arc<HotRequestStatusCache>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental",
        test
    ))]
    hot_agent_status: Arc<HotAgentStatusCache>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental",
        test
    ))]
    hot_session_history: Arc<HotSessionHistoryCache>,
    #[cfg_attr(
        not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )),
        allow(dead_code)
    )]
    last_usage: Arc<Mutex<BTreeMap<ProductProviderId, isyncyou_agent::Usage>>>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    provider_leases: Arc<account_lifecycle::ProviderLeaseRegistry>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    lifecycle_initialized: bool,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    lifecycle_maintenance: Option<LifecycleMaintenanceRuntime>,
    // Read only by the gated product credential-refresh path; keep them without that feature so the
    // no-oauth-feature build (mobile --no-default-features) compiles.
    #[cfg_attr(
        not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )),
        allow(dead_code)
    )]
    credential_now_ms: Arc<dyn Fn() -> u64 + Send + Sync>,
    #[cfg_attr(
        not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )),
        allow(dead_code)
    )]
    credential_refresh_gate: Mutex<()>,
    /// #639: the in-process product-runtime snapshot gate. One hold spans a consistent selection,
    /// credential, activation, and harness snapshot (and the selection write), but never provider
    /// network I/O. Refresh retains only the provider-exclusive lifecycle lease across I/O, then
    /// reacquires this gate before `credential_refresh_gate` and the cross-process snapshot lock.
    #[cfg_attr(
        not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )),
        allow(dead_code)
    )]
    product_runtime_gate: Arc<Mutex<()>>,
    seq: AtomicU64,
    /// Directory holding the app OAuth credential store and an optional local
    /// `agent-oauth.json` policy assertion. Product builds reject any tuple that differs
    /// from the compiled official provider configuration.
    #[cfg_attr(
        not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )),
        allow(dead_code)
    )]
    oauth_dir: PathBuf,
    /// Tracks in-flight device OAuth logins between start and the browser callback.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    oauth: Arc<isyncyou_agent::AgentOAuth>,
    /// Opaque UI attempt ids map to private OAuth state or cancellation flags. They are
    /// process-local, short-lived, and never serialized into status/audit output.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    oauth_attempts: Arc<Mutex<HashMap<String, OAuthAttempt>>>,
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    oauth_lifecycle_bindings: Arc<Mutex<HashMap<String, OAuthLifecycleAttemptBinding>>>,
    #[cfg(test)]
    test_provider_script: Option<TestProviderScript>,
}

impl DaemonAgent {
    pub fn new(cfg: Config, oauth_dir: PathBuf) -> Self {
        Self::new_with_policy(
            cfg,
            oauth_dir,
            AgentOperationPolicy::DesktopEnabled,
            Arc::new(Mutex::new(())),
        )
    }

    pub fn new_with_policy(
        cfg: Config,
        oauth_dir: PathBuf,
        operation_policy: AgentOperationPolicy,
        gate: Arc<Mutex<()>>,
    ) -> Self {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        remove_legacy_codex_callback_diagnostics(&oauth_dir);
        let audit_sink = Arc::new(StoreAgentAuditSink { cfg: cfg.clone() });
        let confirmed_executor =
            agent_ops::confirmed_executor_for_policy(operation_policy, cfg.clone(), gate);
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let lifecycle_initialized = initialize_account_lifecycle(&oauth_dir);
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let (control_store, mut control_store_state) = if lifecycle_initialized {
            match open_agent_control_store(&oauth_dir) {
                Ok(store) => (Some(store), "ready"),
                Err(error) => (None, public_control_store_init_code(&error)),
            }
        } else {
            (None, "lifecycle_unavailable")
        };
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let pending_confirmation_recovery_ready = control_store.as_ref().is_some_and(|store| {
            store
                .recover_interrupted_pending_confirmations(unix_now_ms())
                .is_ok()
        });
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        if control_store.is_some() && !pending_confirmation_recovery_ready {
            control_store_state = "recovery_required";
        }
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let lifecycle_initialized =
            lifecycle_initialized && control_store.is_some() && pending_confirmation_recovery_ready;
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        if let Some(store) = &control_store {
            let _ = store.reap_expired(unix_now_ms(), 256);
        }
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let pending = control_store
            .as_ref()
            .map(|store| {
                Arc::new(isyncyou_agent::PendingRegistry::with_persistence(
                    store.clone(),
                ))
            })
            .unwrap_or_else(|| Arc::new(isyncyou_agent::PendingRegistry::new()));
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        let pending = Arc::new(isyncyou_agent::PendingRegistry::new());
        #[allow(unused_mut)]
        let mut agent = Self {
            cfg,
            hub: Arc::new(isyncyou_agent::AgentStreamHub::new()),
            turns: Arc::new(TurnRegistry::default()),
            pending,
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            control_store,
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            control_store_state,
            confirmed_executor,
            audit_sink,
            streams: Mutex::new(std::collections::HashMap::new()),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental",
                test
            ))]
            turn_admissions: Arc::new(TurnAdmissionRegistry::default()),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            turn_recovery_error: Mutex::new(None),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental",
                test
            ))]
            hot_request_statuses: Arc::new(HotRequestStatusCache::default()),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental",
                test
            ))]
            hot_agent_status: Arc::new(HotAgentStatusCache::default()),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental",
                test
            ))]
            hot_session_history: Arc::new(HotSessionHistoryCache::default()),
            last_usage: Arc::new(Mutex::new(BTreeMap::new())),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            provider_leases: Arc::new(account_lifecycle::ProviderLeaseRegistry::default()),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            lifecycle_initialized,
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            lifecycle_maintenance: None,
            credential_now_ms: Arc::new(now_ms),
            credential_refresh_gate: Mutex::new(()),
            product_runtime_gate: Arc::new(Mutex::new(())),
            seq: AtomicU64::new(0),
            oauth_dir,
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            oauth: Arc::new(isyncyou_agent::AgentOAuth::new()),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            oauth_attempts: Arc::new(Mutex::new(HashMap::new())),
            #[cfg(any(
                feature = "agent-oauth-providers",
                feature = "agent-subscription-experimental"
            ))]
            oauth_lifecycle_bindings: Arc::new(Mutex::new(HashMap::new())),
            #[cfg(test)]
            test_provider_script: None,
        };
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        if agent.lifecycle_initialized
            && agent
                .bind_existing_product_credential_generations()
                .is_err()
        {
            agent.lifecycle_initialized = false;
            agent.control_store_state = "recovery_required";
        }
        // #639 T8: recover any product onboarding interrupted by a crash before the durable
        // authority (bundle + activation + terminal journal entry) was fully written.
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            reap_onboarding_journals_at(&agent.oauth_dir, now_ms());
            recover_interrupted_onboarding_attempts(&agent.oauth_dir);
            agent.recover_product_onboarding();
            let maintenance_context = agent.lifecycle_maintenance_context();
            run_account_maintenance_once(
                &maintenance_context,
                AccountMaintenancePass::StartupRecovery,
            );
            agent.lifecycle_maintenance =
                Some(LifecycleMaintenanceRuntime::spawn(maintenance_context));
        }
        agent
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn shared_control_store(&self) -> Option<Arc<agent_control_store::AgentControlStore>> {
        self.control_store.clone()
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn bind_existing_product_credential_generations(&self) -> Result<(), String> {
        for provider in ProductProviderId::ALL {
            let operation_id = account_lifecycle::mint_operation_id()
                .map_err(|_| "lifecycle_unavailable".to_string())?;
            let _provider = self
                .provider_leases
                .acquire_exclusive(
                    &self.oauth_dir,
                    provider,
                    operation_id,
                    account_lifecycle::ProviderOperationKind::Maintenance,
                )
                .map_err(|_| "provider_busy".to_string())?;
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| "lifecycle_unavailable".to_string())?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
            let repository = account_lifecycle_repository(&self.oauth_dir)?;
            let context = repository
                .load_existing()
                .map_err(|error| error.wire().to_string())?
                .ok_or_else(|| "lifecycle_unavailable".to_string())?;
            // An active lifecycle operation owns this provider's generation transition. Its
            // recovery path either retires the old etag or publishes the candidate etag before
            // releasing authority; startup migration must not race or pre-empt that operation.
            if context.authority.active_operations.contains_key(&provider) {
                continue;
            }
            let credential_id = match provider {
                ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
                ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
            };
            let Some(meta) = load_product_bundle_meta(&self.oauth_dir, credential_id) else {
                continue;
            };
            if !self.provider_activation_valid_for_meta(provider, &meta) {
                continue;
            }
            repository
                .bind_current_credential_generation(provider, &meta.generation)
                .map_err(|error| error.wire().to_string())?;
        }
        Ok(())
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn lifecycle_maintenance_context(&self) -> LifecycleMaintenanceContext {
        LifecycleMaintenanceContext {
            cfg: self.cfg.clone(),
            oauth_dir: self.oauth_dir.clone(),
            control_store: self.control_store.clone(),
            provider_leases: Arc::clone(&self.provider_leases),
            product_runtime_gate: Arc::clone(&self.product_runtime_gate),
            last_usage: Arc::clone(&self.last_usage),
            oauth: Arc::clone(&self.oauth),
            oauth_attempts: Arc::clone(&self.oauth_attempts),
            oauth_lifecycle_bindings: Arc::clone(&self.oauth_lifecycle_bindings),
            session_maintenance_last_ms: Arc::new(AtomicU64::new(0)),
        }
    }

    #[cfg(test)]
    fn with_test_confirm_components(
        cfg: Config,
        oauth_dir: PathBuf,
        executor: Arc<dyn AgentConfirmedActionExecutor>,
        audit_sink: Arc<dyn AgentAuditSink>,
    ) -> Self {
        let mut agent = Self::new(cfg, oauth_dir);
        agent.pending = Arc::new(isyncyou_agent::PendingRegistry::new());
        agent.confirmed_executor = executor;
        agent.audit_sink = audit_sink;
        agent
    }

    #[cfg(test)]
    fn with_test_provider_script_and_confirm_components(
        cfg: Config,
        oauth_dir: PathBuf,
        script: Vec<Vec<isyncyou_agent::AssistantBlock>>,
        executor: Arc<dyn AgentConfirmedActionExecutor>,
        audit_sink: Arc<dyn AgentAuditSink>,
    ) -> Self {
        let mut agent = Self::with_test_confirm_components(cfg, oauth_dir, executor, audit_sink);
        agent.test_provider_script = Some(Arc::new(Mutex::new(Some(script))));
        agent
    }

    /// Resolve an account's archive root (holds `.isyncyou-store.db` + the on-disk body
    /// files) for the retrieval executor. Matches by account id, else the first account,
    /// else an empty path (an empty store simply yields no hits — never a panic).
    fn archive_root_for(&self, account: &str) -> std::path::PathBuf {
        self.cfg
            .accounts
            .iter()
            .find(|a| a.id == account)
            .or_else(|| self.cfg.accounts.first())
            .map(|a| a.archive_root.clone())
            .unwrap_or_default()
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn product_session_account(&self) -> Result<&str, String> {
        match self.cfg.accounts.as_slice() {
            [account] => Ok(account.id.as_str()),
            [] => Err("session_account_unavailable".into()),
            _ => Err("session_account_selection_required".into()),
        }
    }

    fn sweep_unopened_streams_locked(
        streams: &mut std::collections::HashMap<String, AgentStreamSlot>,
        now_ms: u64,
    ) -> usize {
        let before = streams.len();
        streams.retain(|_, slot| {
            now_ms
                <= slot
                    .created_at_ms
                    .saturating_add(AGENT_STREAM_UNOPENED_TTL_MS)
        });
        before - streams.len()
    }

    #[cfg(test)]
    fn sweep_unopened_streams_for_tests(&self, now_ms: u64) -> usize {
        let mut streams = self.streams.lock().unwrap();
        Self::sweep_unopened_streams_locked(&mut streams, now_ms)
    }

    #[cfg(test)]
    fn unopened_stream_count_for_tests(&self) -> usize {
        self.streams.lock().unwrap().len()
    }

    /// Test-only provider-SELECTION probe (#639 T7): resolve the selected provider directly from
    /// stored credentials, without the product-runtime readiness gate. Production turns go through
    /// [`resolve_turn_provider`] / [`product_runtime_gate`]; this stays for selection unit tests.
    #[cfg(all(
        test,
        any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )
    ))]
    fn build_turn_provider(&self, system: &str) -> Box<dyn isyncyou_agent::LlmProvider + Send> {
        #[cfg(test)]
        if let Some(script) = &self.test_provider_script {
            if let Some(script) = script.lock().unwrap().take() {
                return Box::new(isyncyou_agent::FakeProvider::new(script));
            }
        }
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            // #639: the switcher selection drives which provider is built; there is NO
            // cross-provider fallback (an activated non-selected provider is never silently
            // substituted, fixing the old "falls back to the other" behavior).
            let built = match self.agent_settings() {
                Some(settings) if settings.provider == ProductProviderId::Codex => self
                    .try_codex_provider(
                        system,
                        &settings.model,
                        settings.reasoning_effort.unwrap_or_default(),
                    ),
                Some(settings) if settings.provider == ProductProviderId::Claude => {
                    self.try_subscription_provider(system, &settings.model)
                }
                _ => Ok(None),
            };
            match built {
                Ok(Some(provider)) => return provider,
                Err(_) => return credential_resolution_error_provider(),
                Ok(None) => {}
            }
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        let _ = system;
        Box::new(isyncyou_agent::FakeProvider::new(vec![vec![
            isyncyou_agent::AssistantBlock::Text(
                "The AI assistant isn't connected yet — open the Assistant tab and connect your \
                 Claude account, then try again."
                    .to_string(),
            ),
        ]]))
    }

    /// #639 T7: resolve the provider a turn will use, applying the product-runtime gate. A test
    /// script (CI) and the no-product-feature build bypass the gate with a deterministic provider;
    /// the product build returns the closed error code on not-ready so `start_turn` can reject the
    /// turn before creating any turn state.
    fn resolve_turn_provider(&self, system: &str) -> Result<PreparedTurnProvider, String> {
        #[cfg(test)]
        if let Some(script) = &self.test_provider_script {
            if let Some(script) = script.lock().unwrap().take() {
                return Ok(PreparedTurnProvider {
                    provider: Box::new(isyncyou_agent::FakeProvider::new(script)),
                    #[cfg(any(
                        feature = "agent-oauth-providers",
                        feature = "agent-subscription-experimental"
                    ))]
                    provider_id: None,
                    #[cfg(any(
                        feature = "agent-oauth-providers",
                        feature = "agent-subscription-experimental"
                    ))]
                    operation_lease: None,
                    #[cfg(any(
                        feature = "agent-oauth-providers",
                        feature = "agent-subscription-experimental"
                    ))]
                    session_binding: None,
                });
            }
        }
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            self.product_runtime_gate(system)
                .map_err(|e| e.wire().to_string())
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = system;
            Err("product_not_ready".into())
        }
    }

    /// #639 T7: per-provider PRODUCT readiness, DECOUPLED from selection. `true` only when a valid
    /// **Active** V2 bundle is present (not needs-refresh / invalid / absent / experimental) AND a
    /// durable `ProductActivationV1` matches its credential generation + the official policy
    /// fingerprint + the harness contract version AND the shipped static harness still attests.
    /// An experimental local-CLI credential can never satisfy this (it has no bundle/activation).
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn provider_ready(&self, provider: ProductProviderId) -> bool {
        if self.lifecycle_provider_blocked(provider)
            || !self.lifecycle_credential_generation_bound(provider)
        {
            return false;
        }
        match provider {
            ProductProviderId::Claude => match self.claude_product_bundle_state() {
                ProductCredentialState::PresentValid((_, meta)) => {
                    self.provider_activation_valid_for_meta(provider, &meta)
                }
                _ => false,
            },
            ProductProviderId::Codex => match self.codex_product_bundle_state() {
                ProductCredentialState::PresentValid((_, meta)) => {
                    self.provider_activation_valid_for_meta(provider, &meta)
                }
                _ => false,
            },
        }
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn lifecycle_provider_blocked(&self, provider: ProductProviderId) -> bool {
        if !self.lifecycle_initialized {
            return true;
        }
        account_lifecycle_repository(&self.oauth_dir)
            .and_then(|repository| {
                repository
                    .provider_blocked(provider)
                    .map_err(|_| "lifecycle_unavailable".to_string())
            })
            .unwrap_or(true)
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn lifecycle_credential_generation_bound(&self, provider: ProductProviderId) -> bool {
        account_lifecycle_repository(&self.oauth_dir)
            .and_then(|repository| {
                repository
                    .load_existing()
                    .map_err(|_| "lifecycle_unavailable".to_string())
            })
            .ok()
            .flatten()
            .and_then(|context| {
                context
                    .authority
                    .current_credential_etags
                    .get(&provider)
                    .cloned()
            })
            .is_some_and(|etag| !etag.is_empty())
    }

    /// #639 (F3): the DURABLE product activation is valid — a valid Active V2 bundle whose OWN policy
    /// fingerprint matches the current official policy, a matching `ProductActivationV1`, and a
    /// passing static harness attestation. This deliberately does NOT check token expiry: a turn may
    /// proceed for an activated provider whose token merely needs refresh (the build path refreshes
    /// it under the runtime gate), whereas status readiness (`provider_ready`) additionally requires
    /// a currently-valid token.
    #[cfg(all(
        test,
        feature = "agent-oauth-providers",
        not(feature = "agent-subscription-experimental")
    ))]
    fn provider_activation_valid(&self, provider: ProductProviderId) -> bool {
        let credential_id = match provider {
            ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
            ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
        };
        let Some(meta) = load_product_bundle_meta(&self.oauth_dir, credential_id) else {
            return false;
        };
        self.provider_activation_valid_for_meta(provider, &meta)
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn provider_activation_valid_for_meta(
        &self,
        provider: ProductProviderId,
        meta: &ProductBundleMeta,
    ) -> bool {
        if self.lifecycle_provider_blocked(provider) {
            return false;
        }
        let official_policy = oauth_policy_fingerprint(provider);
        if meta.provider != provider
            || meta.lifecycle != CredentialLifecycle::Active
            || meta.policy_fingerprint != official_policy
        {
            return false;
        }
        let activation = match load_product_activation(&self.oauth_dir, provider) {
            Some(activation) => activation,
            None => return false,
        };
        if !activation.matches(
            provider,
            &meta.generation,
            &official_policy,
            isyncyou_agent::HARNESS_CONTRACT_VERSION,
        ) {
            return false;
        }
        isyncyou_agent::attest_static_product_harness(
            harness_provider_for(provider),
            AGENT_SYSTEM_PROMPT,
        )
        .is_ok()
    }

    /// The product credential state for `provider`, projected to unit so callers can match the class
    /// (PresentValid / PresentNeedsRefresh / PresentInvalid / Absent) without the credential value.
    #[cfg(all(
        test,
        feature = "agent-oauth-providers",
        not(feature = "agent-subscription-experimental")
    ))]
    fn provider_credential_state_class(
        &self,
        provider: ProductProviderId,
    ) -> ProductCredentialState<()> {
        fn classify<T>(state: ProductCredentialState<T>) -> ProductCredentialState<()> {
            match state {
                ProductCredentialState::PresentValid(_) => ProductCredentialState::PresentValid(()),
                ProductCredentialState::PresentNeedsRefresh(_) => {
                    ProductCredentialState::PresentNeedsRefresh(())
                }
                ProductCredentialState::PresentInvalid => ProductCredentialState::PresentInvalid,
                ProductCredentialState::Absent => ProductCredentialState::Absent,
            }
        }
        match provider {
            ProductProviderId::Claude => classify(self.claude_product_credential_state()),
            ProductProviderId::Codex => classify(self.codex_product_credential_state()),
        }
    }

    /// #639 T9: whether an official OAuth attempt for `provider` is currently in flight.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn has_active_attempt(&self, provider: ProductProviderId) -> bool {
        self.oauth_attempts
            .lock()
            .map(|attempts| {
                attempts.values().any(|attempt| {
                    matches!(
                        (provider, attempt),
                        (ProductProviderId::Claude, OAuthAttempt::Claude { .. })
                            | (ProductProviderId::Codex, OAuthAttempt::Codex { .. })
                    )
                })
            })
            .unwrap_or(false)
    }

    /// #639 T9: the per-provider onboarding projection for the wizard — `{state, steps[]}`. It is
    /// derived from the DURABLE authority first (a ready provider reports all 8 steps complete
    /// regardless of the journal, so the projection survives journal TTL), then an in-flight attempt,
    /// then credential presence. It never leaks any token/account/OAuth value.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn provider_onboarding(&self, provider: ProductProviderId) -> serde_json::Value {
        let (state, completed, error_code) = if self.provider_ready(provider) {
            // Ready: all steps complete, derived from the durable activation (survives journal TTL).
            ("ready", ONBOARDING_SUCCESS_CHAIN.len(), None)
        } else {
            // A new official OAuth attempt must remain visible even when it is replacing an invalid
            // credential. Otherwise reconnect would stay stuck at `reconnect_required` until the
            // exchange had already completed. The attempt journal is bounded and evidence-only;
            // readiness still comes exclusively from the durable activation above.
            match latest_attempt_journal(&self.oauth_dir, provider) {
                Ok(Some(journal)) => {
                    if let Some(terminal) = journal.terminal_error() {
                        (
                            "error_redacted",
                            0,
                            Some(public_onboarding_error_code(terminal.error_code.as_deref())),
                        )
                    } else if let Some(last) = journal.transitions.last() {
                        (last.state.wire(), 0, None)
                    } else {
                        ("not_started", 0, None)
                    }
                }
                Err(()) => ("error_redacted", 0, Some("journal_invalid")),
                Ok(None) if self.has_active_attempt(provider) => {
                    ("official_sign_in_started", 0, None)
                }
                Ok(None) => match self
                    .product_credential_status(provider.wire())
                    .unwrap_or("reconnect_required")
                {
                    "reconnect_required" | "refresh_required" => ("reconnect_required", 0, None),
                    _ => match self.journal_completed_success_steps(provider) {
                        Ok(completed) if completed > 0 => (
                            ONBOARDING_SUCCESS_CHAIN[completed - 1].wire(),
                            completed,
                            None,
                        ),
                        Err(()) => ("error_redacted", 0, Some("journal_invalid")),
                        Ok(_) => ("not_started", 0, None),
                    },
                },
            }
        };
        let steps: Vec<serde_json::Value> = ONBOARDING_SUCCESS_CHAIN
            .iter()
            .enumerate()
            .map(|(i, step)| serde_json::json!({ "key": step.wire(), "complete": i < completed }))
            .collect();
        let mut result = serde_json::json!({ "state": state, "steps": steps });
        if let Some(error_code) = error_code {
            result["error_code"] = serde_json::Value::String(error_code.to_string());
        }
        result
    }

    /// #639 (F5): count the ordered success-chain transitions the generation-keyed journal has
    /// actually recorded (TTL-bounded) — the journal-driven basis for the in-progress step count.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn journal_completed_success_steps(&self, provider: ProductProviderId) -> Result<usize, ()> {
        let _gate = onboarding_journal_gate().lock().map_err(|_| ())?;
        let _file_gate = acquire_onboarding_journal_file_lock(&self.oauth_dir)?;
        let credential_id = match provider {
            ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
            ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
        };
        let Some(meta) = load_product_bundle_meta(&self.oauth_dir, credential_id) else {
            return Ok(0);
        };
        let store_id =
            OnboardingAttemptJournalV1::journal_store_id_for_generation(&meta.generation);
        let Some(journal) = load_onboarding_journal_at(&self.oauth_dir, &store_id) else {
            return Ok(0);
        };
        journal.ordered_success_prefix()
    }

    /// #639 T9: the full onboarding projection block for `status_json`. `selected_provider` is null
    /// for a corrupt/unknown settings record (fail-closed), never a default/alternative provider.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn onboarding_projection(&self, selected: Option<ProductProviderId>) -> serde_json::Value {
        let claude = self.provider_onboarding(ProductProviderId::Claude);
        let codex = self.provider_onboarding(ProductProviderId::Codex);
        let selected_state = match selected {
            Some(ProductProviderId::Claude) => claude["state"].clone(),
            Some(ProductProviderId::Codex) => codex["state"].clone(),
            None => serde_json::Value::String("not_started".into()),
        };
        serde_json::json!({
            "selected_provider": selected.map(|p| p.wire()),
            "selected_state": selected_state,
            "providers": {
                "claude": claude,
                "codex": codex,
            },
        })
    }

    /// #639 T7 / #627: build a provider from the EXPERIMENTAL local-CLI credential only. Compiled
    /// solely under the experimental opt-in, it never reads the product store and only resolves on
    /// an `Absent` product state (a present-but-invalid bundle fails closed). It never sets product
    /// readiness/activation — it exists so the experimental turn stays available, walled off.
    #[cfg(feature = "agent-subscription-experimental")]
    fn try_experimental_only_provider(
        &self,
        provider: ProductProviderId,
        model: &str,
        system: &str,
    ) -> Option<Box<dyn isyncyou_agent::LlmProvider + Send>> {
        match provider {
            ProductProviderId::Claude => {
                let credential = self.experimental_claude_credential().ok()??;
                let provider = isyncyou_agent::SubscriptionProvider::new(
                    credential.access_token,
                    model,
                    system,
                    self.subscription_config(),
                )
                .ok()?;
                Some(Box::new(provider))
            }
            ProductProviderId::Codex => {
                let credential = self.experimental_codex_credential().ok()??;
                let cfg = isyncyou_agent::CodexConfig {
                    account_id: credential.account_id,
                    model: model.to_string(),
                    ..Default::default()
                };
                let provider =
                    isyncyou_agent::CodexProvider::new(credential.access_token, system, cfg)
                        .ok()?;
                Some(Box::new(provider))
            }
        }
    }

    /// #639 T7/#645: build a turn provider from one lifecycle-fenced product snapshot. Short
    /// runtime/refresh/file locks validate and copy the minimum refresh input, are released for
    /// provider I/O, and are reacquired in the fixed order for publication. The exclusive provider
    /// lease is then handed off to a shared turn lease; under that lease the current encrypted
    /// bundle and activation are re-read and provider construction is refresh-free. This runs
    /// before turn-id/stream/archive allocation. The product path uses only host-verified product
    /// authority; #627 remains a separate compiled-in path that never confers product readiness.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn product_runtime_gate(
        &self,
        system: &str,
    ) -> Result<PreparedTurnProvider, AgentStartTurnError> {
        enum CredentialSnapshot {
            Claude {
                credential: StoredCredential,
                refresh_fence: Option<ProductRefreshFence>,
            },
            Codex {
                credential: CodexStoredCredential,
                refresh_fence: Option<ProductRefreshFence>,
            },
        }

        // Preliminary read selects only the provider enum; no credential material survives it.
        let selected = {
            let _gate = self
                .product_runtime_gate
                .lock()
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            let _file_gate = acquire_product_runtime_file_lock(&self.oauth_dir)
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            self.agent_settings()
                .map(|settings| settings.provider)
                .ok_or(AgentStartTurnError::ProductNotReady)?
        };
        let operation_id = account_lifecycle::mint_operation_id()
            .map_err(|_| AgentStartTurnError::ProductNotReady)?;
        let exclusive = self
            .provider_leases
            .acquire_exclusive(
                &self.oauth_dir,
                selected,
                operation_id.clone(),
                account_lifecycle::ProviderOperationKind::Refresh,
            )
            .map_err(|_| AgentStartTurnError::ProviderBusy)?;

        let (settings, meta, turn_fence, credential) = {
            let _gate = self
                .product_runtime_gate
                .lock()
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            let _refresh = self
                .credential_refresh_gate
                .lock()
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            let _file_gate = acquire_product_runtime_file_lock(&self.oauth_dir)
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            let settings = self
                .agent_settings()
                .filter(|settings| settings.provider == selected)
                .ok_or(AgentStartTurnError::ProductNotReady)?;
            if self.lifecycle_provider_blocked(selected) {
                return Err(AgentStartTurnError::ProductNotReady);
            }
            match selected {
                ProductProviderId::Claude => {
                    let state = self.claude_product_bundle_state();
                    let (credential, meta, refresh_required) = match state {
                        ProductCredentialState::PresentValid((credential, meta)) => {
                            (credential, meta, false)
                        }
                        ProductCredentialState::PresentNeedsRefresh((credential, meta)) => {
                            if !self.provider_activation_valid_for_meta(selected, &meta) {
                                return Err(AgentStartTurnError::ProductNotReady);
                            }
                            (credential, meta, true)
                        }
                        ProductCredentialState::Absent => {
                            #[cfg(feature = "agent-subscription-experimental")]
                            #[expect(
                                clippy::manual_option_zip,
                                reason = "experimental provider construction must remain lazy until the absent-product fence is captured"
                            )]
                            if let Some((provider, experimental_fence)) = self
                                .capture_absent_product_refresh_fence(selected)
                                .ok()
                                .and_then(|fence| {
                                    self.try_experimental_only_provider(
                                        selected,
                                        &settings.model,
                                        system,
                                    )
                                    .map(|provider| (provider, fence))
                                })
                            {
                                drop(_file_gate);
                                drop(_refresh);
                                drop(_gate);
                                drop(exclusive);
                                let lease = self
                                    .provider_leases
                                    .acquire_shared(
                                        &self.oauth_dir,
                                        selected,
                                        operation_id,
                                        account_lifecycle::ProviderOperationKind::Turn,
                                    )
                                    .map_err(|_| AgentStartTurnError::ProviderBusy)?;
                                let still_absent = {
                                    let _gate = self
                                        .product_runtime_gate
                                        .lock()
                                        .map_err(|_| AgentStartTurnError::ProductNotReady)?;
                                    let _file_gate =
                                        acquire_product_runtime_file_lock(&self.oauth_dir)
                                            .map_err(|_| AgentStartTurnError::ProductNotReady)?;
                                    self.product_refresh_fence_matches(
                                        selected,
                                        &experimental_fence,
                                    ) && matches!(
                                        self.claude_product_bundle_state(),
                                        ProductCredentialState::Absent
                                    )
                                };
                                if !still_absent {
                                    return Err(AgentStartTurnError::ProductNotReady);
                                }
                                return Ok(PreparedTurnProvider {
                                    provider,
                                    provider_id: Some(selected),
                                    operation_lease: Some(lease),
                                    session_binding: None,
                                });
                            }
                            return Err(AgentStartTurnError::ProductNotReady);
                        }
                        ProductCredentialState::PresentInvalid => {
                            return Err(AgentStartTurnError::ProductNotReady);
                        }
                    };
                    if !self.provider_activation_valid_for_meta(selected, &meta) {
                        return Err(AgentStartTurnError::ProductNotReady);
                    }
                    let turn_fence = self
                        .capture_bound_product_refresh_fence(selected)
                        .map_err(|_| AgentStartTurnError::ProductNotReady)?;
                    (
                        settings,
                        meta,
                        turn_fence.clone(),
                        CredentialSnapshot::Claude {
                            credential,
                            refresh_fence: refresh_required.then_some(turn_fence),
                        },
                    )
                }
                ProductProviderId::Codex => {
                    let state = self.codex_product_bundle_state();
                    let (credential, meta, refresh_required) = match state {
                        ProductCredentialState::PresentValid((credential, meta)) => {
                            (credential, meta, false)
                        }
                        ProductCredentialState::PresentNeedsRefresh((credential, meta)) => {
                            if !self.provider_activation_valid_for_meta(selected, &meta) {
                                return Err(AgentStartTurnError::ProductNotReady);
                            }
                            (credential, meta, true)
                        }
                        ProductCredentialState::Absent => {
                            #[cfg(feature = "agent-subscription-experimental")]
                            #[expect(
                                clippy::manual_option_zip,
                                reason = "experimental provider construction must remain lazy until the absent-product fence is captured"
                            )]
                            if let Some((provider, experimental_fence)) = self
                                .capture_absent_product_refresh_fence(selected)
                                .ok()
                                .and_then(|fence| {
                                    self.try_experimental_only_provider(
                                        selected,
                                        &settings.model,
                                        system,
                                    )
                                    .map(|provider| (provider, fence))
                                })
                            {
                                drop(_file_gate);
                                drop(_refresh);
                                drop(_gate);
                                drop(exclusive);
                                let lease = self
                                    .provider_leases
                                    .acquire_shared(
                                        &self.oauth_dir,
                                        selected,
                                        operation_id,
                                        account_lifecycle::ProviderOperationKind::Turn,
                                    )
                                    .map_err(|_| AgentStartTurnError::ProviderBusy)?;
                                let still_absent = {
                                    let _gate = self
                                        .product_runtime_gate
                                        .lock()
                                        .map_err(|_| AgentStartTurnError::ProductNotReady)?;
                                    let _file_gate =
                                        acquire_product_runtime_file_lock(&self.oauth_dir)
                                            .map_err(|_| AgentStartTurnError::ProductNotReady)?;
                                    self.product_refresh_fence_matches(
                                        selected,
                                        &experimental_fence,
                                    ) && matches!(
                                        self.codex_product_bundle_state(),
                                        ProductCredentialState::Absent
                                    )
                                };
                                if !still_absent {
                                    return Err(AgentStartTurnError::ProductNotReady);
                                }
                                return Ok(PreparedTurnProvider {
                                    provider,
                                    provider_id: Some(selected),
                                    operation_lease: Some(lease),
                                    session_binding: None,
                                });
                            }
                            return Err(AgentStartTurnError::ProductNotReady);
                        }
                        ProductCredentialState::PresentInvalid => {
                            return Err(AgentStartTurnError::ProductNotReady);
                        }
                    };
                    if !self.provider_activation_valid_for_meta(selected, &meta) {
                        return Err(AgentStartTurnError::ProductNotReady);
                    }
                    let turn_fence = self
                        .capture_bound_product_refresh_fence(selected)
                        .map_err(|_| AgentStartTurnError::ProductNotReady)?;
                    (
                        settings,
                        meta,
                        turn_fence.clone(),
                        CredentialSnapshot::Codex {
                            credential,
                            refresh_fence: refresh_required.then_some(turn_fence),
                        },
                    )
                }
            }
        };
        // Provider I/O runs with only the provider-exclusive lifecycle lease held. The refresh
        // publisher reacquires runtime -> refresh -> file locks and validates this exact fence.
        let credential = match credential {
            CredentialSnapshot::Claude {
                credential,
                refresh_fence: Some(refresh_fence),
            } => CredentialSnapshot::Claude {
                credential: self
                    .refresh_claude_product_credential_with_fence(
                        credential,
                        meta.clone(),
                        refresh_fence,
                    )
                    .map_err(|_| AgentStartTurnError::ProductNotReady)?,
                refresh_fence: None,
            },
            CredentialSnapshot::Codex {
                credential,
                refresh_fence: Some(refresh_fence),
            } => CredentialSnapshot::Codex {
                credential: self
                    .refresh_codex_product_credential_with_fence(
                        credential,
                        meta.clone(),
                        refresh_fence,
                    )
                    .map_err(|_| AgentStartTurnError::ProductNotReady)?,
                refresh_fence: None,
            },
            credential => credential,
        };
        let generation = meta.generation.clone();
        drop(exclusive);

        let shared = self
            .provider_leases
            .acquire_shared(
                &self.oauth_dir,
                selected,
                operation_id,
                account_lifecycle::ProviderOperationKind::Turn,
            )
            .map_err(|_| AgentStartTurnError::ProviderBusy)?;
        let provider = {
            let _gate = self
                .product_runtime_gate
                .lock()
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            let _file_gate = acquire_product_runtime_file_lock(&self.oauth_dir)
                .map_err(|_| AgentStartTurnError::ProductNotReady)?;
            if !self.product_refresh_fence_matches(selected, &turn_fence) {
                return Err(AgentStartTurnError::ProductNotReady);
            }
            // Another process may win the exclusive lease between our release and this
            // shared acquisition and refresh the same credential generation. Its etag and
            // lifecycle fence remain unchanged, so reload the encrypted bundle while the
            // shared lease now prevents another refresh. This construction path never
            // performs network I/O or upgrades the shared lease.
            let credential = match (selected, credential) {
                (ProductProviderId::Claude, CredentialSnapshot::Claude { .. }) => {
                    match self.claude_product_bundle_state() {
                        ProductCredentialState::PresentValid((credential, current_meta))
                            if current_meta == meta =>
                        {
                            CredentialSnapshot::Claude {
                                credential,
                                refresh_fence: None,
                            }
                        }
                        ProductCredentialState::PresentValid(_)
                        | ProductCredentialState::PresentNeedsRefresh(_)
                        | ProductCredentialState::PresentInvalid
                        | ProductCredentialState::Absent => {
                            return Err(AgentStartTurnError::ProductNotReady);
                        }
                    }
                }
                (ProductProviderId::Codex, CredentialSnapshot::Codex { .. }) => {
                    match self.codex_product_bundle_state() {
                        ProductCredentialState::PresentValid((credential, current_meta))
                            if current_meta == meta =>
                        {
                            CredentialSnapshot::Codex {
                                credential,
                                refresh_fence: None,
                            }
                        }
                        ProductCredentialState::PresentValid(_)
                        | ProductCredentialState::PresentNeedsRefresh(_)
                        | ProductCredentialState::PresentInvalid
                        | ProductCredentialState::Absent => {
                            return Err(AgentStartTurnError::ProductNotReady);
                        }
                    }
                }
                _ => return Err(AgentStartTurnError::ProductNotReady),
            };
            if !self.provider_activation_valid_for_meta(selected, &meta) {
                return Err(AgentStartTurnError::ProductNotReady);
            }
            match credential {
                CredentialSnapshot::Claude { credential, .. } => {
                    isyncyou_agent::SubscriptionProvider::new(
                        credential.access_token,
                        &settings.model,
                        system,
                        self.subscription_config(),
                    )
                    .map(|provider| {
                        Box::new(provider) as Box<dyn isyncyou_agent::LlmProvider + Send>
                    })
                    .map_err(|_| AgentStartTurnError::ProductNotReady)?
                }
                CredentialSnapshot::Codex { credential, .. } => {
                    let config = isyncyou_agent::CodexConfig {
                        account_id: credential.account_id,
                        model: settings.model.clone(),
                        reasoning_effort: settings.reasoning_effort.unwrap_or_default(),
                        ..Default::default()
                    };
                    isyncyou_agent::CodexProvider::new(credential.access_token, system, config)
                        .map(|provider| {
                            Box::new(provider) as Box<dyn isyncyou_agent::LlmProvider + Send>
                        })
                        .map_err(|_| AgentStartTurnError::ProductNotReady)?
                }
            }
        };
        let session_binding = self.provider_attempt_binding(
            selected,
            &settings.model,
            settings.reasoning_effort,
            &generation,
        )?;
        Ok(PreparedTurnProvider {
            provider,
            provider_id: Some(selected),
            operation_lease: Some(shared),
            session_binding: Some(session_binding),
        })
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn provider_attempt_binding(
        &self,
        provider: ProductProviderId,
        model: &str,
        reasoning_effort: Option<isyncyou_agent::CodexReasoningEffort>,
        generation: &str,
    ) -> Result<isyncyou_agent::ProviderAttemptBindingV1, AgentStartTurnError> {
        use base64::Engine as _;
        let repository = account_lifecycle_repository(&self.oauth_dir)
            .map_err(|_| AgentStartTurnError::ProductNotReady)?;
        let installation = repository
            .load_existing()
            .map_err(|_| AgentStartTurnError::ProductNotReady)?
            .ok_or(AgentStartTurnError::ProductNotReady)?;
        let mut digest_input = b"isyncyou-origin-installation-v1\0".to_vec();
        digest_input.extend_from_slice(installation.principal().as_bytes());
        let origin_installation_digest = base64::engine::general_purpose::URL_SAFE_NO_PAD
            .encode(ring::digest::digest(&ring::digest::SHA256, &digest_input).as_ref());
        Ok(isyncyou_agent::ProviderAttemptBindingV1 {
            provider,
            model: model.to_owned(),
            reasoning_effort: reasoning_effort.map(|value| value.as_str().to_owned()),
            credential_generation: generation.to_owned(),
            oauth_policy_fingerprint: oauth_policy_fingerprint(provider),
            harness_contract_version: isyncyou_agent::HARNESS_CONTRACT_VERSION,
            origin_installation_digest,
        })
    }

    /// #639 T8: commit a successful official Claude OAuth atomically under the product-runtime gate:
    /// write the encrypted V2 credential (fresh generation) + activation, record the ordered success
    /// chain to the generation journal, then persist the selection. Holding the gate here means a
    /// concurrent status/turn read can never observe a half-written credential/activation revision.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    #[allow(dead_code)]
    fn commit_claude_oauth_success(
        &self,
        token: &isyncyou_agent::oauth::RefreshedToken,
    ) -> Result<(), String> {
        let _gate = self
            .product_runtime_gate
            .lock()
            .map_err(|_| "product_busy".to_string())?;
        let _file_gate = acquire_product_runtime_file_lock(&self.oauth_dir)?;
        self.store_token(token)?;
        let generation = load_product_bundle_meta(&self.oauth_dir, SUBSCRIPTION_CREDENTIAL_ID)
            .map(|m| m.generation)
            .unwrap_or_default();
        record_onboarding_generation_transitions(
            &self.oauth_dir,
            ProductProviderId::Claude,
            &generation,
            &ONBOARDING_SUCCESS_CHAIN,
        );
        self.set_agent_settings("claude", DEFAULT_MODEL)?;
        Ok(())
    }

    /// #639 T8: startup crash-window recovery over the DURABLE authority (bundle + activation),
    /// never re-running OAuth. For each product provider with a valid Active V2 bundle:
    /// window 2 (bundle written, activation missing) -> re-attest + write the matching activation
    /// for the bundle's generation; window 2/3 -> ensure the generation journal carries the full
    /// success chain (the missing terminal transition is added). Run once at construction.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn recover_product_onboarding(&self) {
        let _gate = match self.product_runtime_gate.lock() {
            Ok(gate) => gate,
            Err(_) => return,
        };
        let _file_gate = match acquire_product_runtime_file_lock(&self.oauth_dir) {
            Ok(gate) => gate,
            Err(_) => return,
        };
        for provider in [ProductProviderId::Claude, ProductProviderId::Codex] {
            let credential_id = match provider {
                ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
                ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
            };
            let meta = match load_product_bundle_meta(&self.oauth_dir, credential_id) {
                Some(meta) if meta.lifecycle == CredentialLifecycle::Active => meta,
                _ => continue,
            };
            let policy = oauth_policy_fingerprint(provider);
            let activation_matches = load_product_activation(&self.oauth_dir, provider)
                .map(|activation| {
                    activation.matches(
                        provider,
                        &meta.generation,
                        &policy,
                        isyncyou_agent::HARNESS_CONTRACT_VERSION,
                    )
                })
                .unwrap_or(false);
            if !activation_matches
                && activate_product(&self.oauth_dir, provider, &meta.generation).is_err()
            {
                // A harness that no longer attests refuses activation; leave it not ready.
                continue;
            }
            record_onboarding_generation_transitions(
                &self.oauth_dir,
                provider,
                &meta.generation,
                &ONBOARDING_SUCCESS_CHAIN,
            );
        }
    }
}

/// The app OAuth credential we persist: access token, refresh token, and the access
/// token's absolute expiry (ms since the Unix epoch), so the daemon can refresh without
/// reading local provider CLI files.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Clone, PartialEq, Eq)]
struct StoredCredential {
    access_token: String,
    refresh_token: String,
    /// Absolute expiry in ms since the Unix epoch; 0 = unknown.
    expires_at_ms: u64,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl StoredCredential {
    /// Serialize to the JSON blob persisted in the credential store.
    fn to_json(&self) -> Vec<u8> {
        serde_json::to_vec(&serde_json::json!({
            "access_token": self.access_token,
            "refresh_token": self.refresh_token,
            "expires_at_ms": self.expires_at_ms,
        }))
        .unwrap_or_default()
    }

    /// Parse a stored JSON blob; `None` if it is not our blob shape (e.g. a bare token).
    fn from_json(raw: &[u8]) -> Option<Self> {
        let v: serde_json::Value = serde_json::from_slice(raw).ok()?;
        let access_token = v.get("access_token")?.as_str()?.to_string();
        Some(Self {
            access_token,
            refresh_token: v.get("refresh_token")?.as_str()?.to_string(),
            expires_at_ms: v.get("expires_at_ms")?.as_u64()?,
        })
    }
}

/// Ms since the Unix epoch (0 on a clock error). Always available (the non-gated `DaemonAgent`
/// constructor seeds `credential_now_ms` with it), so the no-oauth-feature build compiles too.
fn now_ms() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0)
}

/// #639: the current schema version of a persisted product credential blob. A blob without it
/// (a legacy token-only blob from before #639) is treated as un-migratable and forces reconnect.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const PRODUCT_CREDENTIAL_SCHEMA_VERSION: u32 = 3;

/// #639: whether a persisted product credential is usable, or has been marked (fail-closed) as
/// requiring a fresh official OAuth. A failed refresh persists `ReconnectRequired` so the next
/// status read reports reconnect rather than re-attempting a refresh in a loop.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
enum CredentialLifecycle {
    Active,
    Disconnecting { operation_id: String },
    ReconnectRequired { closed_code: String },
}

/// #639: the non-token metadata bound to a persisted product credential bundle (V2). It carries
/// the identity of the credential (`generation`), the official-OAuth policy it was minted under
/// (`policy_fingerprint`), and its `lifecycle`. `generation` is minted once at login and preserved
/// across refresh; a credential identity change rotates it via a fresh login only.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct ProductBundleMeta {
    schema_version: u32,
    provider: ProductProviderId,
    generation: String,
    policy_fingerprint: String,
    lifecycle: CredentialLifecycle,
    identity: account_identity::ProductCredentialIdentityV3,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[allow(dead_code)]
enum ProductCredentialMaterial {
    Claude(StoredCredential),
    Codex(CodexStoredCredential),
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
#[allow(dead_code)]
enum CandidateIdentityDecision {
    VerifiedSubject(String),
    Unavailable,
    Invalid,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[allow(dead_code)]
struct OAuthCandidateMaterial {
    provider: ProductProviderId,
    access_token: String,
    refresh_token: String,
    expires_at_ms: u64,
    provider_account_id: Option<String>,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[allow(dead_code)]
impl OAuthCandidateMaterial {
    fn revoke_credential(&self) -> isyncyou_agent::oauth::RevokeCredential {
        isyncyou_agent::oauth::RevokeCredential {
            access_token: (!self.access_token.is_empty())
                .then(|| isyncyou_agent::Secret::new(self.access_token.as_bytes().to_vec())),
            refresh_token: (!self.refresh_token.is_empty())
                .then(|| isyncyou_agent::Secret::new(self.refresh_token.as_bytes().to_vec())),
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[allow(dead_code)]
impl ProductCredentialMaterial {
    fn revoke_credential(&self) -> isyncyou_agent::oauth::RevokeCredential {
        match self {
            Self::Claude(value) => isyncyou_agent::oauth::RevokeCredential {
                access_token: (!value.access_token.is_empty())
                    .then(|| isyncyou_agent::Secret::new(value.access_token.as_bytes().to_vec())),
                refresh_token: (!value.refresh_token.is_empty())
                    .then(|| isyncyou_agent::Secret::new(value.refresh_token.as_bytes().to_vec())),
            },
            Self::Codex(value) => isyncyou_agent::oauth::RevokeCredential {
                access_token: (!value.access_token.is_empty())
                    .then(|| isyncyou_agent::Secret::new(value.access_token.as_bytes().to_vec())),
                refresh_token: (!value.refresh_token.is_empty())
                    .then(|| isyncyou_agent::Secret::new(value.refresh_token.as_bytes().to_vec())),
            },
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl ProductBundleMeta {
    /// Fresh metadata for a brand-new login: a new random generation, the current official policy
    /// fingerprint for `provider`, and an `Active` lifecycle.
    fn fresh(provider: ProductProviderId) -> Result<Self, String> {
        Ok(Self {
            schema_version: PRODUCT_CREDENTIAL_SCHEMA_VERSION,
            provider,
            generation: uuid_v4()?,
            policy_fingerprint: oauth_policy_fingerprint(provider),
            lifecycle: CredentialLifecycle::Active,
            identity: account_identity::ProductCredentialIdentityV3 {
                subject_digest: None,
                session_id_digest: None,
            },
        })
    }

    /// Merge these metadata keys into a token-only JSON object (`token_json`) to form the V2 blob.
    /// Returns the token blob unchanged (best-effort) only if it is not a JSON object.
    fn to_blob(&self, token_json: Vec<u8>) -> Vec<u8> {
        let mut v: serde_json::Value = match serde_json::from_slice(&token_json) {
            Ok(serde_json::Value::Object(map)) => serde_json::Value::Object(map),
            _ => return token_json,
        };
        if let Some(obj) = v.as_object_mut() {
            obj.insert(
                "schema_version".into(),
                serde_json::json!(self.schema_version),
            );
            obj.insert(
                "provider_id".into(),
                serde_json::json!(self.provider.wire()),
            );
            obj.insert(
                "credential_generation".into(),
                serde_json::json!(self.generation),
            );
            obj.insert(
                "oauth_policy_fingerprint".into(),
                serde_json::json!(self.policy_fingerprint),
            );
            let (lifecycle, code, operation_id) = match &self.lifecycle {
                CredentialLifecycle::Active => ("active", String::new(), None),
                CredentialLifecycle::Disconnecting { operation_id } => {
                    ("disconnecting", String::new(), Some(operation_id.clone()))
                }
                CredentialLifecycle::ReconnectRequired { closed_code } => {
                    ("reconnect_required", closed_code.clone(), None)
                }
            };
            obj.insert("lifecycle".into(), serde_json::json!(lifecycle));
            obj.insert("reconnect_code".into(), serde_json::json!(code));
            if self.schema_version == PRODUCT_CREDENTIAL_SCHEMA_VERSION {
                obj.insert(
                    "lifecycle_operation_id".into(),
                    operation_id.map_or(serde_json::Value::Null, serde_json::Value::String),
                );
                self.identity.merge_into(obj);
            }
        }
        serde_json::to_vec(&v).unwrap_or(token_json)
    }

    /// Parse the V2 metadata from a stored blob. `None` for a legacy/incomplete blob (missing the
    /// schema version or the generation) — the caller treats that as un-migratable → reconnect.
    fn from_blob(raw: &[u8], expected_provider: ProductProviderId) -> Option<Self> {
        let v: serde_json::Value = serde_json::from_slice(raw).ok()?;
        let schema_version = u32::try_from(v.get("schema_version")?.as_u64()?).ok()?;
        if !matches!(schema_version, 2 | PRODUCT_CREDENTIAL_SCHEMA_VERSION) {
            return None;
        }
        let provider = ProductProviderId::parse(v.get("provider_id")?.as_str()?)?;
        if provider != expected_provider {
            return None;
        }
        let mut expected_keys: BTreeSet<&str> = match provider {
            ProductProviderId::Claude => [
                "access_token",
                "credential_generation",
                "expires_at_ms",
                "lifecycle",
                "oauth_policy_fingerprint",
                "provider_id",
                "reconnect_code",
                "refresh_token",
                "schema_version",
            ]
            .into_iter()
            .collect(),
            ProductProviderId::Codex => [
                "access_token",
                "account_id",
                "credential_generation",
                "expires_at_ms",
                "lifecycle",
                "oauth_policy_fingerprint",
                "provider_id",
                "reconnect_code",
                "refresh_token",
                "schema_version",
            ]
            .into_iter()
            .collect(),
        };
        if schema_version == PRODUCT_CREDENTIAL_SCHEMA_VERSION {
            expected_keys.extend([
                "lifecycle_operation_id",
                "session_id_digest",
                "subject_digest",
            ]);
        }
        if v.as_object()?
            .keys()
            .map(String::as_str)
            .collect::<BTreeSet<_>>()
            != expected_keys
        {
            return None;
        }
        let generation = v.get("credential_generation")?.as_str()?.to_string();
        if !is_uuid_v4(&generation) {
            return None;
        }
        let policy_fingerprint = v.get("oauth_policy_fingerprint")?.as_str()?.to_string();
        if !is_lower_hex(&policy_fingerprint, 64) {
            return None;
        }
        let reconnect_code = v.get("reconnect_code")?.as_str()?;
        let lifecycle_operation_id = v.get("lifecycle_operation_id");
        let lifecycle = match v.get("lifecycle")?.as_str()? {
            "active"
                if reconnect_code.is_empty()
                    && lifecycle_operation_id.is_none_or(serde_json::Value::is_null) =>
            {
                CredentialLifecycle::Active
            }
            "disconnecting" if schema_version == PRODUCT_CREDENTIAL_SCHEMA_VERSION => {
                let operation_id = lifecycle_operation_id?.as_str()?.to_string();
                account_lifecycle::validate_operation_id(&operation_id).ok()?;
                if !reconnect_code.is_empty() {
                    return None;
                }
                CredentialLifecycle::Disconnecting { operation_id }
            }
            "reconnect_required" => {
                if reconnect_code.is_empty()
                    || lifecycle_operation_id.is_some_and(|value| !value.is_null())
                {
                    return None;
                }
                CredentialLifecycle::ReconnectRequired {
                    closed_code: reconnect_code.to_string(),
                }
            }
            _ => return None,
        };
        let identity = if schema_version == PRODUCT_CREDENTIAL_SCHEMA_VERSION {
            let identity = account_identity::ProductCredentialIdentityV3 {
                subject_digest: v
                    .get("subject_digest")
                    .and_then(|value| value.as_str().map(str::to_string)),
                session_id_digest: v
                    .get("session_id_digest")
                    .and_then(|value| value.as_str().map(str::to_string)),
            };
            identity.validate().ok()?;
            identity
        } else {
            account_identity::ProductCredentialIdentityV3 {
                subject_digest: None,
                session_id_digest: None,
            }
        };
        Some(Self {
            schema_version,
            provider,
            generation,
            policy_fingerprint,
            lifecycle,
            identity,
        })
    }

    #[allow(dead_code)]
    fn switch_capability(&self) -> account_identity::SwitchCapability {
        if self.schema_version != PRODUCT_CREDENTIAL_SCHEMA_VERSION {
            return account_identity::SwitchCapability::Unavailable;
        }
        account_identity::switch_capability(self.provider, self.identity.subject_digest.as_deref())
    }

    #[allow(dead_code)]
    fn preserve_refresh_identity(
        &self,
        refreshed_subject: Option<&str>,
    ) -> Result<account_identity::ProductCredentialIdentityV3, String> {
        if let (Some(current), Some(refreshed)) =
            (self.identity.subject_digest.as_deref(), refreshed_subject)
        {
            if current != refreshed {
                return Err("credential_subject_mismatch".into());
            }
        }
        Ok(self.identity.clone())
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn is_uuid_v4(value: &str) -> bool {
    let bytes = value.as_bytes();
    bytes.len() == 36
        && bytes[8] == b'-'
        && bytes[13] == b'-'
        && bytes[18] == b'-'
        && bytes[23] == b'-'
        && bytes[14] == b'4'
        && matches!(bytes[19], b'8' | b'9' | b'a' | b'b')
        && bytes.iter().enumerate().all(|(index, &byte)| {
            matches!(index, 8 | 13 | 18 | 23) || matches!(byte, b'0'..=b'9' | b'a'..=b'f')
        })
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn is_lower_hex(value: &str, len: usize) -> bool {
    value.len() == len
        && value
            .bytes()
            .all(|byte| matches!(byte, b'0'..=b'9' | b'a'..=b'f'))
}

/// #639: a random RFC-4122 v4 UUID string (from the crypto RNG) — the credential generation id.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn uuid_v4() -> Result<String, String> {
    use ring::rand::{SecureRandom, SystemRandom};
    let mut b = [0u8; 16];
    SystemRandom::new()
        .fill(&mut b)
        .map_err(|_| "credential_generation_unavailable".to_string())?;
    b[6] = (b[6] & 0x0f) | 0x40; // version 4
    b[8] = (b[8] & 0x3f) | 0x80; // variant
    Ok(format!(
        "{:02x}{:02x}{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}-{:02x}{:02x}{:02x}{:02x}{:02x}{:02x}",
        b[0], b[1], b[2], b[3], b[4], b[5], b[6], b[7], b[8], b[9], b[10], b[11], b[12], b[13], b[14], b[15],
    ))
}

/// #639: a stable fingerprint of the compiled official OAuth policy tuple for `provider`
/// (authorize/token endpoints, client id, redirect, scopes, and required public-client fields).
/// Binding it into the activation record means a credential minted under a different (e.g.
/// overridden) policy can never read as ready.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn oauth_policy_fingerprint(provider: ProductProviderId) -> String {
    let tuple = match provider {
        ProductProviderId::Claude => {
            let c = isyncyou_agent::oauth::OAuthConfig::default();
            format!(
                "claude|{}|{}|{}|{}|{}",
                c.authorize_url,
                c.token_url,
                c.client_id,
                c.manual_redirect_url,
                c.scopes.join(",")
            )
        }
        ProductProviderId::Codex => {
            let c = isyncyou_agent::oauth::CodexOAuthConfig::default();
            format!(
                "codex|{}|{}|{}|{}|{}|{}|{}|{}",
                c.authorize_url,
                c.token_url,
                c.client_id,
                c.redirect_uri,
                c.scope,
                isyncyou_agent::oauth::CODEX_OAUTH_SIMPLIFIED_FLOW,
                isyncyou_agent::oauth::CODEX_OAUTH_ORIGINATOR,
                "codex-oidc-subject-rs256-v1",
            )
        }
    };
    let d = ring::digest::digest(&ring::digest::SHA256, tuple.as_bytes());
    d.as_ref().iter().map(|b| format!("{b:02x}")).collect()
}

/// #639: the iSyncYou harness contract version the runtime attestation enforces (T6). The
/// activation record binds it so a credential activated under an older harness contract cannot
/// read as ready after the contract changes without a re-attestation (T4/T8).
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
// #639: the activation/journal/lock storage below is wired into the runtime by T7 (gate),
// T8 (journal transitions) and T9 (status); it reads as dead in the lib target until then.
#[allow(dead_code)]
const HARNESS_CONTRACT_VERSION: u32 = 1;

/// #639: journal bounds — a hard cap the bounded reader enforces before allocation.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const MAX_JOURNAL_PLAINTEXT_BYTES: usize = 65_536;
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const MAX_JOURNAL_ENVELOPE_BYTES: usize = 98_304;
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const MAX_JOURNAL_TRANSITIONS: usize = 32;
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const MAX_JOURNAL_INDEX_ENTRIES: usize = 64;

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn onboarding_journal_gate() -> &'static Mutex<()> {
    static GATE: OnceLock<Mutex<()>> = OnceLock::new();
    GATE.get_or_init(|| Mutex::new(()))
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn acquire_onboarding_journal_file_lock(oauth_dir: &Path) -> Result<isyncyou_agent::FileLock, ()> {
    match isyncyou_agent::FileLock::try_acquire_exclusive(
        &oauth_dir.join(".onboarding-journal.lock"),
    ) {
        Ok(Some(lock)) => Ok(lock),
        Ok(None) | Err(_) => Err(()),
    }
}

/// #639 (F5): onboarding journal TTL — transitions older than 8 minutes are reaped on load, and an
/// all-expired journal reads as absent (the journal is expiry/recovery/evidence only, never the
/// readiness authority, so its expiry never affects a ready provider).
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const ONBOARDING_JOURNAL_TTL_MS: u64 = 8 * 60 * 1000;

/// #639: the ordered product onboarding states (monotonic within one setup attempt). Ordering is
/// proven by recorded transitions in the journal, not by an ordinal — `ErrorRedacted` is a terminal
/// transition, never a "highest" state.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ProductOnboardingState {
    NotStarted,
    OfficialSignInStarted,
    OfficialOauthCompleted,
    CredentialEncrypted,
    RetainedEnvelopeVerified,
    DefaultHarnessRemoved,
    M365ProfileActivated,
    IsyncyouToolConnected,
    SubscriptionIdentitySet,
    Ready,
    ErrorRedacted,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl ProductOnboardingState {
    fn wire(self) -> &'static str {
        match self {
            Self::NotStarted => "not_started",
            Self::OfficialSignInStarted => "official_sign_in_started",
            Self::OfficialOauthCompleted => "official_oauth_completed",
            Self::CredentialEncrypted => "credential_encrypted",
            Self::RetainedEnvelopeVerified => "retained_envelope_verified",
            Self::DefaultHarnessRemoved => "default_harness_removed",
            Self::M365ProfileActivated => "m365_profile_activated",
            Self::IsyncyouToolConnected => "isyncyou_tool_connected",
            Self::SubscriptionIdentitySet => "subscription_identity_set",
            Self::Ready => "ready",
            Self::ErrorRedacted => "error_redacted",
        }
    }
}

/// #639: the durable, authenticated product-activation record — the ONLY persisted readiness
/// authority. It binds the credential `generation`, the official-OAuth `policy_fingerprint`, and
/// the `harness_contract_version`; readiness additionally requires a valid Active V2 bundle and a
/// fresh runtime attestation (T6/T7). Stored in the encrypted CredentialStore (authenticated via
/// its AAD-bound class), id `activation:<provider>`.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct ProductActivationV1 {
    provider_id: String,
    credential_generation: String,
    oauth_policy_fingerprint: String,
    harness_contract_version: u32,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl ProductActivationV1 {
    fn activation_store_id(provider: ProductProviderId) -> String {
        format!("activation:{}", provider.wire())
    }

    fn to_json(&self) -> Vec<u8> {
        serde_json::to_vec(&serde_json::json!({
            "schema_version": 1,
            "provider_id": self.provider_id,
            "credential_generation": self.credential_generation,
            "oauth_policy_fingerprint": self.oauth_policy_fingerprint,
            "harness_contract_version": self.harness_contract_version,
        }))
        .unwrap_or_default()
    }

    fn from_json(raw: &[u8], expected_provider: ProductProviderId) -> Option<Self> {
        let v: serde_json::Value = serde_json::from_slice(raw).ok()?;
        if v.get("schema_version").and_then(|x| x.as_u64()) != Some(1)
            || v.as_object().map(|object| object.len()) != Some(5)
        {
            return None;
        }
        let provider_id = v.get("provider_id")?.as_str()?.to_string();
        let credential_generation = v.get("credential_generation")?.as_str()?.to_string();
        let oauth_policy_fingerprint = v.get("oauth_policy_fingerprint")?.as_str()?.to_string();
        let harness_contract_version =
            u32::try_from(v.get("harness_contract_version")?.as_u64()?).ok()?;
        if provider_id != expected_provider.wire()
            || !is_uuid_v4(&credential_generation)
            || !is_lower_hex(&oauth_policy_fingerprint, 64)
        {
            return None;
        }
        Some(Self {
            provider_id,
            credential_generation,
            oauth_policy_fingerprint,
            harness_contract_version,
        })
    }

    /// Whether this activation authorizes readiness for `provider` at the given credential
    /// `generation`, official `policy_fingerprint`, and harness `contract_version`. All four must
    /// match — a generation match alone is not enough.
    fn matches(
        &self,
        provider: ProductProviderId,
        generation: &str,
        policy_fingerprint: &str,
        contract_version: u32,
    ) -> bool {
        self.provider_id == provider.wire()
            && self.credential_generation == generation
            && self.oauth_policy_fingerprint == policy_fingerprint
            && self.harness_contract_version == contract_version
    }
}

/// Persist a product activation record (#639) under the dedicated activation secret class.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn store_product_activation(
    oauth_dir: &Path,
    provider: ProductProviderId,
    activation: &ProductActivationV1,
) -> Result<(), String> {
    agent_credential_store(oauth_dir)?
        .put(
            isyncyou_agent::SecretClass::ProductActivation,
            &ProductActivationV1::activation_store_id(provider),
            &isyncyou_agent::Secret::new(activation.to_json()),
        )
        .map_err(credential_store_error)
}

/// Load the product activation record (#639); `None` if absent/legacy/undecryptable.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn load_product_activation(
    oauth_dir: &Path,
    provider: ProductProviderId,
) -> Option<ProductActivationV1> {
    if !agent_credential_store_exists(oauth_dir) {
        return None;
    }
    let store = agent_credential_store(oauth_dir).ok()?;
    let secret = store
        .get_bounded(
            isyncyou_agent::SecretClass::ProductActivation,
            &ProductActivationV1::activation_store_id(provider),
            MAX_JOURNAL_ENVELOPE_BYTES,
            MAX_JOURNAL_PLAINTEXT_BYTES,
        )
        .ok()??;
    ProductActivationV1::from_json(secret.expose(), provider)
}

/// A single recorded onboarding transition (#639). It never carries OAuth state/verifier/code/url —
/// only the reached state, the credential generation it belongs to, and an optional closed error code.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct OnboardingTransition {
    state: ProductOnboardingState,
    generation: String,
    error_code: Option<String>,
    /// #639 (F5): ms since the Unix epoch when this transition was recorded — drives the 8-min
    /// journal TTL (the reaper drops transitions older than that on load).
    recorded_at_ms: u64,
}

/// The bounded, authenticated per-attempt onboarding transition journal (#639). It is for expiry,
/// crash recovery, and evidence only — never the readiness authority. Capped at
/// `MAX_JOURNAL_TRANSITIONS` transitions; the encrypted blob is bounded-read at load.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct OnboardingAttemptJournalV1 {
    transitions: Vec<OnboardingTransition>,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum OnboardingJournalKind {
    Attempt,
    Generation,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct OnboardingJournalIndexEntry {
    store_id: String,
    kind: OnboardingJournalKind,
    expires_at_ms: u64,
    updated_at_ms: u64,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct OnboardingJournalIndexV1 {
    entries: Vec<OnboardingJournalIndexEntry>,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl OnboardingJournalIndexV1 {
    fn store_id(provider: ProductProviderId) -> String {
        format!("journal-index:{}", provider.wire())
    }

    fn upsert(&mut self, entry: OnboardingJournalIndexEntry) -> Vec<String> {
        self.entries
            .retain(|existing| existing.store_id != entry.store_id);
        self.entries.push(entry);
        self.entries.sort_by_key(|entry| entry.updated_at_ms);
        if self.entries.len() > MAX_JOURNAL_INDEX_ENTRIES {
            return self
                .entries
                .drain(0..self.entries.len() - MAX_JOURNAL_INDEX_ENTRIES)
                .map(|entry| entry.store_id)
                .collect();
        }
        Vec::new()
    }

    fn to_json(&self) -> Vec<u8> {
        let entries: Vec<serde_json::Value> = self
            .entries
            .iter()
            .map(|entry| {
                serde_json::json!({
                    "store_id": entry.store_id,
                    "kind": match entry.kind {
                        OnboardingJournalKind::Attempt => "attempt",
                        OnboardingJournalKind::Generation => "generation",
                    },
                    "expires_at_ms": entry.expires_at_ms,
                    "updated_at_ms": entry.updated_at_ms,
                })
            })
            .collect();
        serde_json::to_vec(&serde_json::json!({ "schema_version": 1, "entries": entries }))
            .unwrap_or_default()
    }

    fn from_json(raw: &[u8]) -> Option<Self> {
        let value: serde_json::Value = serde_json::from_slice(raw).ok()?;
        if value.as_object().map(|object| object.len()) != Some(2)
            || value.get("schema_version").and_then(|v| v.as_u64()) != Some(1)
        {
            return None;
        }
        let source = value.get("entries")?.as_array()?;
        if source.len() > MAX_JOURNAL_INDEX_ENTRIES {
            return None;
        }
        let mut entries = Vec::with_capacity(source.len());
        for value in source {
            if value.as_object().map(|object| object.len()) != Some(4) {
                return None;
            }
            let store_id = value.get("store_id")?.as_str()?.to_string();
            if !store_id.starts_with("journal:")
                || store_id.len() != "journal:".len() + 64
                || !is_lower_hex(&store_id["journal:".len()..], 64)
                || entries
                    .iter()
                    .any(|entry: &OnboardingJournalIndexEntry| entry.store_id == store_id)
            {
                return None;
            }
            let kind = match value.get("kind")?.as_str()? {
                "attempt" => OnboardingJournalKind::Attempt,
                "generation" => OnboardingJournalKind::Generation,
                _ => return None,
            };
            let expires_at_ms = value.get("expires_at_ms")?.as_u64()?;
            let updated_at_ms = value.get("updated_at_ms")?.as_u64()?;
            if updated_at_ms == 0
                || expires_at_ms != updated_at_ms.saturating_add(ONBOARDING_JOURNAL_TTL_MS)
            {
                return None;
            }
            entries.push(OnboardingJournalIndexEntry {
                store_id,
                kind,
                expires_at_ms,
                updated_at_ms,
            });
        }
        Some(Self { entries })
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl OnboardingAttemptJournalV1 {
    /// The store id for `attempt_id`: a domain-separated hash, never the raw attempt id. Used for
    /// the pre-credential (in-flight) phase, keyed by the opaque UI attempt.
    fn journal_store_id(attempt_id: &str) -> String {
        Self::hashed_store_id("isyncyou-onboarding-attempt-v1", attempt_id)
    }

    /// The store id for a credential `generation`: a distinct domain-separated hash. Used for the
    /// durable (post-credential) phase, so startup crash recovery can find the journal by the
    /// bundle's generation after the in-memory attempt id is gone (§6 windows 2/3, §9 projection).
    fn journal_store_id_for_generation(generation: &str) -> String {
        Self::hashed_store_id("isyncyou-onboarding-generation-v1", generation)
    }

    fn hashed_store_id(domain: &str, value: &str) -> String {
        let d = ring::digest::digest(
            &ring::digest::SHA256,
            format!("{domain}:{value}").as_bytes(),
        );
        format!(
            "journal:{}",
            d.as_ref()
                .iter()
                .map(|b| format!("{b:02x}"))
                .collect::<String>()
        )
    }

    #[cfg(all(test, not(feature = "agent-subscription-experimental")))]
    fn has_state(&self, state: ProductOnboardingState) -> bool {
        self.transitions.iter().any(|t| t.state == state)
    }

    fn ordered_success_prefix(&self) -> Result<usize, ()> {
        if self.transitions.len() > ONBOARDING_SUCCESS_CHAIN.len() {
            return Err(());
        }
        for (index, transition) in self.transitions.iter().enumerate() {
            if transition.state != ONBOARDING_SUCCESS_CHAIN[index]
                || transition.generation.is_empty()
                || transition.error_code.is_some()
            {
                return Err(());
            }
        }
        Ok(self.transitions.len())
    }

    fn terminal_error(&self) -> Option<&OnboardingTransition> {
        self.transitions
            .last()
            .filter(|transition| transition.state == ProductOnboardingState::ErrorRedacted)
    }

    /// Append a transition, keeping only the most recent `MAX_JOURNAL_TRANSITIONS` (compaction).
    fn push(&mut self, transition: OnboardingTransition) {
        self.transitions.push(transition);
        let len = self.transitions.len();
        if len > MAX_JOURNAL_TRANSITIONS {
            self.transitions.drain(0..len - MAX_JOURNAL_TRANSITIONS);
        }
    }

    fn to_json(&self) -> Vec<u8> {
        let arr: Vec<serde_json::Value> = self
            .transitions
            .iter()
            .map(|t| {
                serde_json::json!({
                    "state": t.state.wire(),
                    "generation": t.generation,
                    "error_code": t.error_code,
                    "recorded_at_ms": t.recorded_at_ms,
                })
            })
            .collect();
        serde_json::to_vec(&serde_json::json!({ "schema_version": 1, "transitions": arr }))
            .unwrap_or_default()
    }

    fn from_json(raw: &[u8]) -> Option<Self> {
        let v: serde_json::Value = serde_json::from_slice(raw).ok()?;
        if v.as_object().map(|object| object.len()) != Some(2)
            || v.get("schema_version").and_then(|x| x.as_u64()) != Some(1)
        {
            return None;
        }
        let source = v.get("transitions").and_then(|x| x.as_array())?;
        if source.len() > MAX_JOURNAL_TRANSITIONS {
            return None;
        }
        let mut transitions = Vec::with_capacity(source.len());
        for (index, t) in source.iter().enumerate() {
            if t.as_object().map(|object| object.len()) != Some(4) {
                return None;
            }
            let state = onboarding_state_from_wire(t.get("state").and_then(|x| x.as_str())?)?;
            let generation = t.get("generation")?.as_str()?.to_string();
            let error_code = match t.get("error_code")? {
                serde_json::Value::Null => None,
                value => Some(value.as_str()?.to_string()),
            };
            let recorded_at_ms = t.get("recorded_at_ms")?.as_u64()?;
            if recorded_at_ms == 0 {
                return None;
            }
            match state {
                ProductOnboardingState::OfficialSignInStarted
                    if generation.is_empty() && error_code.is_none() => {}
                ProductOnboardingState::ErrorRedacted
                    if generation.is_empty()
                        && error_code.as_deref().is_some_and(is_onboarding_error_code)
                        && index + 1 == source.len() => {}
                state
                    if ONBOARDING_SUCCESS_CHAIN.contains(&state)
                        && is_uuid_v4(&generation)
                        && error_code.is_none() => {}
                _ => return None,
            }
            transitions.push(OnboardingTransition {
                state,
                generation,
                error_code,
                recorded_at_ms,
            });
        }
        Some(Self { transitions })
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn onboarding_state_from_wire(wire: &str) -> Option<ProductOnboardingState> {
    use ProductOnboardingState::*;
    Some(match wire {
        "not_started" => NotStarted,
        "official_sign_in_started" => OfficialSignInStarted,
        "official_oauth_completed" => OfficialOauthCompleted,
        "credential_encrypted" => CredentialEncrypted,
        "retained_envelope_verified" => RetainedEnvelopeVerified,
        "default_harness_removed" => DefaultHarnessRemoved,
        "m365_profile_activated" => M365ProfileActivated,
        "isyncyou_tool_connected" => IsyncyouToolConnected,
        "subscription_identity_set" => SubscriptionIdentitySet,
        "ready" => Ready,
        "error_redacted" => ErrorRedacted,
        _ => return None,
    })
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn public_onboarding_error_code(code: Option<&str>) -> &'static str {
    match code {
        Some("cancelled") => "cancelled",
        Some("expired") => "expired",
        Some("interrupted") => "interrupted",
        Some("policy_unavailable") => "policy_unavailable",
        Some("transport_unavailable") => "transport_unavailable",
        Some("exchange_failed") => "exchange_failed",
        Some("commit_failed") => "commit_failed",
        Some("same_account_selected") => "same_account_selected",
        Some("candidate_identity_invalid") => "candidate_identity_invalid",
        Some("candidate_revoke_unknown") => "candidate_revoke_unknown",
        Some("authorization_failed") => "authorization_failed",
        Some("callback_invalid") => "callback_invalid",
        Some("journal_invalid") => "journal_invalid",
        _ => "onboarding_failed",
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn is_onboarding_error_code(code: &str) -> bool {
    matches!(
        code,
        "cancelled"
            | "expired"
            | "interrupted"
            | "policy_unavailable"
            | "transport_unavailable"
            | "exchange_failed"
            | "commit_failed"
            | "same_account_selected"
            | "candidate_identity_invalid"
            | "candidate_revoke_unknown"
            | "authorization_failed"
            | "callback_invalid"
            | "journal_invalid"
    )
}

/// Persist an onboarding journal at a precomputed store id (#639) — bounded, authenticated, atomic.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn store_onboarding_journal_at(
    oauth_dir: &Path,
    store_id: &str,
    journal: &OnboardingAttemptJournalV1,
) -> Result<(), String> {
    agent_credential_store(oauth_dir)?
        .put(
            isyncyou_agent::SecretClass::OnboardingAttemptJournal,
            store_id,
            &isyncyou_agent::Secret::new(journal.to_json()),
        )
        .map_err(credential_store_error)
}

/// Load an onboarding journal at a precomputed store id (#639) with hard size bounds.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn load_onboarding_journal_at(
    oauth_dir: &Path,
    store_id: &str,
) -> Option<OnboardingAttemptJournalV1> {
    if !agent_credential_store_exists(oauth_dir) {
        return None;
    }
    let store = agent_credential_store(oauth_dir).ok()?;
    let secret = store
        .get_bounded(
            isyncyou_agent::SecretClass::OnboardingAttemptJournal,
            store_id,
            MAX_JOURNAL_ENVELOPE_BYTES,
            MAX_JOURNAL_PLAINTEXT_BYTES,
        )
        .ok()??;
    let mut journal = OnboardingAttemptJournalV1::from_json(secret.expose())?;
    // #639 (F5): reap transitions older than the TTL; an all-expired (or legacy, unstamped) journal
    // reads as absent.
    let cutoff = now_ms().saturating_sub(ONBOARDING_JOURNAL_TTL_MS);
    journal.transitions.retain(|t| t.recorded_at_ms >= cutoff);
    if journal.transitions.is_empty() {
        return None;
    }
    Some(journal)
}

/// Persist the onboarding attempt journal (#639), keyed by the opaque UI attempt id.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[cfg(test)]
fn store_onboarding_journal(
    oauth_dir: &Path,
    attempt_id: &str,
    journal: &OnboardingAttemptJournalV1,
) -> Result<(), String> {
    store_onboarding_journal_at(
        oauth_dir,
        &OnboardingAttemptJournalV1::journal_store_id(attempt_id),
        journal,
    )
}

/// Load the onboarding attempt journal (#639), keyed by the opaque UI attempt id.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn load_onboarding_journal(
    oauth_dir: &Path,
    attempt_id: &str,
) -> Option<OnboardingAttemptJournalV1> {
    load_onboarding_journal_at(
        oauth_dir,
        &OnboardingAttemptJournalV1::journal_store_id(attempt_id),
    )
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn load_onboarding_journal_index(
    oauth_dir: &Path,
    provider: ProductProviderId,
) -> Result<OnboardingJournalIndexV1, ()> {
    if !agent_credential_store_exists(oauth_dir) {
        return Ok(OnboardingJournalIndexV1::default());
    }
    let store = agent_credential_store(oauth_dir).map_err(|_| ())?;
    let Some(secret) = store
        .get_bounded(
            isyncyou_agent::SecretClass::OnboardingAttemptJournal,
            &OnboardingJournalIndexV1::store_id(provider),
            MAX_JOURNAL_ENVELOPE_BYTES,
            MAX_JOURNAL_PLAINTEXT_BYTES,
        )
        .map_err(|_| ())?
    else {
        return Ok(OnboardingJournalIndexV1::default());
    };
    OnboardingJournalIndexV1::from_json(secret.expose()).ok_or(())
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn store_onboarding_journal_index(
    oauth_dir: &Path,
    provider: ProductProviderId,
    index: &OnboardingJournalIndexV1,
) -> Result<(), String> {
    let store = agent_credential_store(oauth_dir)?;
    if index.entries.is_empty() {
        return store
            .delete(
                isyncyou_agent::SecretClass::OnboardingAttemptJournal,
                &OnboardingJournalIndexV1::store_id(provider),
            )
            .map_err(credential_store_error);
    }
    store
        .put(
            isyncyou_agent::SecretClass::OnboardingAttemptJournal,
            &OnboardingJournalIndexV1::store_id(provider),
            &isyncyou_agent::Secret::new(index.to_json()),
        )
        .map_err(credential_store_error)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn delete_provider_onboarding_journals_durable(
    oauth_dir: &Path,
    provider: ProductProviderId,
) -> Result<(), String> {
    let index = load_onboarding_journal_index(oauth_dir, provider)
        .map_err(|_| "onboarding journal index is invalid".to_string())?;
    let store = agent_credential_store(oauth_dir)?;
    for entry in index.entries {
        store
            .delete_durable(
                isyncyou_agent::SecretClass::OnboardingAttemptJournal,
                &entry.store_id,
            )
            .map_err(credential_store_error)?;
    }
    store
        .delete_durable(
            isyncyou_agent::SecretClass::OnboardingAttemptJournal,
            &OnboardingJournalIndexV1::store_id(provider),
        )
        .map_err(credential_store_error)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn store_indexed_onboarding_journal(
    oauth_dir: &Path,
    provider: ProductProviderId,
    store_id: &str,
    kind: OnboardingJournalKind,
    journal: &OnboardingAttemptJournalV1,
    recorded_at_ms: u64,
) -> Result<(), String> {
    let mut index = load_onboarding_journal_index(oauth_dir, provider)
        .map_err(|_| "onboarding journal index is invalid".to_string())?;
    let evicted = index.upsert(OnboardingJournalIndexEntry {
        store_id: store_id.to_string(),
        kind,
        expires_at_ms: recorded_at_ms.saturating_add(ONBOARDING_JOURNAL_TTL_MS),
        updated_at_ms: recorded_at_ms,
    });
    let store = agent_credential_store(oauth_dir)?;

    // Journals are evidence-only. Delete entries evicted by the hard index bound before publishing
    // the new index, so an interrupted write cannot leave an ever-growing set of unindexed files.
    for evicted_id in evicted {
        store
            .delete(
                isyncyou_agent::SecretClass::OnboardingAttemptJournal,
                &evicted_id,
            )
            .map_err(credential_store_error)?;
    }
    store_onboarding_journal_index(oauth_dir, provider, &index)?;
    if let Err(error) = store_onboarding_journal_at(oauth_dir, store_id, journal) {
        index.entries.retain(|entry| entry.store_id != store_id);
        let _ = store_onboarding_journal_index(oauth_dir, provider, &index);
        return Err(error);
    }
    Ok(())
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn reap_onboarding_journals_at(oauth_dir: &Path, now: u64) {
    let Ok(_gate) = onboarding_journal_gate().lock() else {
        return;
    };
    let Ok(_file_gate) = acquire_onboarding_journal_file_lock(oauth_dir) else {
        return;
    };
    if !agent_credential_store_exists(oauth_dir) {
        return;
    }
    let Ok(store) = agent_credential_store(oauth_dir) else {
        return;
    };
    for provider in ProductProviderId::ALL {
        let Ok(mut index) = load_onboarding_journal_index(oauth_dir, provider) else {
            continue;
        };
        // The index is written before its journal so a failed journal write can be rolled back. A
        // process crash in that narrow window leaves a dangling index entry; remove it during
        // startup or bounded maintenance instead of projecting `journal_invalid` forever.
        let expired_or_dangling: Vec<String> = index
            .entries
            .iter()
            .filter(|entry| {
                entry.expires_at_ms <= now
                    || load_onboarding_journal_at(oauth_dir, &entry.store_id).is_none()
            })
            .map(|entry| entry.store_id.clone())
            .collect();
        index
            .entries
            .retain(|entry| !expired_or_dangling.contains(&entry.store_id));
        for store_id in expired_or_dangling {
            let _ = store.delete(
                isyncyou_agent::SecretClass::OnboardingAttemptJournal,
                &store_id,
            );
        }
        let _ = store_onboarding_journal_index(oauth_dir, provider, &index);
    }
}

/// A process restart loses the PKCE verifier and OAuth state held in memory. Any still-live,
/// nonterminal attempt journal therefore cannot be resumed and is closed with a redacted terminal
/// transition. The hashed store id is sufficient; raw attempt ids are neither recovered nor stored.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn recover_interrupted_onboarding_attempts(oauth_dir: &Path) {
    let Ok(_gate) = onboarding_journal_gate().lock() else {
        return;
    };
    let Ok(_file_gate) = acquire_onboarding_journal_file_lock(oauth_dir) else {
        return;
    };
    for provider in ProductProviderId::ALL {
        let Ok(index) = load_onboarding_journal_index(oauth_dir, provider) else {
            continue;
        };
        let attempt_store_ids: Vec<String> = index
            .entries
            .iter()
            .filter(|entry| entry.kind == OnboardingJournalKind::Attempt)
            .map(|entry| entry.store_id.clone())
            .collect();
        for store_id in attempt_store_ids {
            let Some(mut journal) = load_onboarding_journal_at(oauth_dir, &store_id) else {
                continue;
            };
            if journal.terminal_error().is_some() {
                continue;
            }
            let recorded_at_ms = now_ms();
            journal.push(OnboardingTransition {
                state: ProductOnboardingState::ErrorRedacted,
                generation: String::new(),
                error_code: Some("interrupted".into()),
                recorded_at_ms,
            });
            let _ = store_indexed_onboarding_journal(
                oauth_dir,
                provider,
                &store_id,
                OnboardingJournalKind::Attempt,
                &journal,
                recorded_at_ms,
            );
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn latest_attempt_journal(
    oauth_dir: &Path,
    provider: ProductProviderId,
) -> Result<Option<OnboardingAttemptJournalV1>, ()> {
    let _gate = onboarding_journal_gate().lock().map_err(|_| ())?;
    let _file_gate = acquire_onboarding_journal_file_lock(oauth_dir)?;
    let index = load_onboarding_journal_index(oauth_dir, provider)?;
    let latest = index
        .entries
        .iter()
        .filter(|entry| entry.kind == OnboardingJournalKind::Attempt)
        .max_by_key(|entry| entry.updated_at_ms);
    match latest {
        Some(entry) => load_onboarding_journal_at(oauth_dir, &entry.store_id)
            .map(Some)
            .ok_or(()),
        None => Ok(None),
    }
}

/// The ordered onboarding chain recorded once a successful official OAuth is committed and the
/// product is activated (#639): official OAuth completed -> credential encrypted -> retained
/// envelope verified -> default harness removed -> M365 profile activated -> iSyncYou tool
/// connected -> subscription identity set -> ready.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const ONBOARDING_SUCCESS_CHAIN: [ProductOnboardingState; 8] = [
    ProductOnboardingState::OfficialOauthCompleted,
    ProductOnboardingState::CredentialEncrypted,
    ProductOnboardingState::RetainedEnvelopeVerified,
    ProductOnboardingState::DefaultHarnessRemoved,
    ProductOnboardingState::M365ProfileActivated,
    ProductOnboardingState::IsyncyouToolConnected,
    ProductOnboardingState::SubscriptionIdentitySet,
    ProductOnboardingState::Ready,
];

/// Append an in-flight transition to the attempt-keyed journal (#639). Best-effort: the journal is
/// evidence/recovery only, never the readiness authority, so a write failure never blocks the flow.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn record_onboarding_attempt_transition(
    oauth_dir: &Path,
    provider: ProductProviderId,
    attempt_id: &str,
    state: ProductOnboardingState,
    error_code: Option<String>,
) {
    let Ok(_gate) = onboarding_journal_gate().lock() else {
        return;
    };
    let Ok(_file_gate) = acquire_onboarding_journal_file_lock(oauth_dir) else {
        return;
    };
    let store_id = OnboardingAttemptJournalV1::journal_store_id(attempt_id);
    let mut journal =
        load_onboarding_journal(oauth_dir, attempt_id).unwrap_or(OnboardingAttemptJournalV1 {
            transitions: vec![],
        });
    journal.push(OnboardingTransition {
        state,
        generation: String::new(),
        error_code,
        recorded_at_ms: now_ms(),
    });
    let _ = store_indexed_onboarding_journal(
        oauth_dir,
        provider,
        &store_id,
        OnboardingJournalKind::Attempt,
        &journal,
        now_ms(),
    );
}

/// Append one or more ordered transitions to the generation-keyed journal (#639), skipping any that
/// are already present so recovery is idempotent. Best-effort (evidence only).
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn record_onboarding_generation_transitions(
    oauth_dir: &Path,
    provider: ProductProviderId,
    generation: &str,
    states: &[ProductOnboardingState],
) {
    let Ok(_gate) = onboarding_journal_gate().lock() else {
        return;
    };
    let Ok(_file_gate) = acquire_onboarding_journal_file_lock(oauth_dir) else {
        return;
    };
    let store_id = OnboardingAttemptJournalV1::journal_store_id_for_generation(generation);
    let mut journal =
        load_onboarding_journal_at(oauth_dir, &store_id).unwrap_or(OnboardingAttemptJournalV1 {
            transitions: vec![],
        });
    let mut changed = false;
    for &state in states {
        let Some(chain_index) = ONBOARDING_SUCCESS_CHAIN
            .iter()
            .position(|item| *item == state)
        else {
            break;
        };
        if chain_index < journal.transitions.len() {
            if journal.transitions[chain_index].state != state {
                break;
            }
            continue;
        }
        if chain_index == journal.transitions.len() {
            journal.push(OnboardingTransition {
                state,
                generation: generation.to_string(),
                error_code: None,
                recorded_at_ms: now_ms(),
            });
            changed = true;
        } else {
            break;
        }
    }
    if changed {
        let _ = store_indexed_onboarding_journal(
            oauth_dir,
            provider,
            &store_id,
            OnboardingJournalKind::Generation,
            &journal,
            now_ms(),
        );
    }
}

/// Acquire the cross-process side of the product-runtime transaction gate. The in-process mutex is
/// always taken first; this short-lived lock then spans one complete settings/credential/activation
/// snapshot or write transaction. A competing daemon fails closed instead of reading a mixed
/// revision. Browser sign-in and provider network calls never hold this lock.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn acquire_product_runtime_file_lock(oauth_dir: &Path) -> Result<isyncyou_agent::FileLock, String> {
    match isyncyou_agent::FileLock::try_acquire_exclusive(&oauth_dir.join(".product-runtime.lock"))
    {
        Ok(Some(lock)) => Ok(lock),
        Ok(None) | Err(_) => Err("product_busy".to_string()),
    }
}

