#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
const LEGACY_CODEX_CALLBACK_DIAGNOSTICS_NAME_SHA256: [u8; 32] = [
    0x0f, 0x19, 0x11, 0xfa, 0xf8, 0x32, 0xc0, 0xd2, 0xe7, 0x9e, 0xa6, 0x9b, 0x96, 0x2b, 0xd0, 0x28,
    0x9e, 0x0c, 0xec, 0x4a, 0x3b, 0x0e, 0x2c, 0x4b, 0xbc, 0xb3, 0x2e, 0x3f, 0x9a, 0xbd, 0xcf, 0x10,
];

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn remove_legacy_codex_callback_diagnostics(oauth_dir: &Path) {
    let Ok(entries) = std::fs::read_dir(oauth_dir) else {
        return;
    };
    for entry in entries.flatten() {
        let Some(name) = entry.file_name().to_str().map(str::to_owned) else {
            continue;
        };
        let digest = ring::digest::digest(&ring::digest::SHA256, name.as_bytes());
        let is_regular_file = entry
            .file_type()
            .map(|file_type| file_type.is_file())
            .unwrap_or(false);
        if is_regular_file
            && digest.as_ref() == LEGACY_CODEX_CALLBACK_DIAGNOSTICS_NAME_SHA256.as_slice()
        {
            let _ = std::fs::remove_file(entry.path());
            break;
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(Clone)]
struct CodexCandidateRuntime {
    cfg: Config,
    oauth_dir: PathBuf,
    provider_leases: Arc<account_lifecycle::ProviderLeaseRegistry>,
    product_runtime_gate: Arc<Mutex<()>>,
    now_ms: Arc<dyn Fn() -> u64 + Send + Sync>,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn prepare_product_oauth_exchange(
    cfg: &Config,
    oauth_dir: &Path,
    provider_leases: &Arc<account_lifecycle::ProviderLeaseRegistry>,
    provider: ProductProviderId,
    operation_id: &str,
    attempt_id: &str,
    now_ms: u64,
) -> Result<(), String> {
    let lease_id =
        account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
    let _lease = provider_leases
        .acquire_exclusive(
            oauth_dir,
            provider,
            lease_id,
            account_lifecycle::ProviderOperationKind::OAuthActivation,
        )
        .map_err(|error| error.wire().to_string())?;
    let repository = audited_account_lifecycle_repository(oauth_dir, cfg)?;
    let active = repository
        .active_operation(provider)
        .map_err(|error| error.wire().to_string())?
        .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
    if active.prepared.operation_id != operation_id {
        return Err("lifecycle_operation_mismatch".into());
    }
    repository
        .prepare_exchange(&active.journal_record_id, attempt_id, now_ms)
        .map_err(|error| error.wire().to_string())?;
    Ok(())
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn mark_product_oauth_exchange_unknown(
    cfg: &Config,
    oauth_dir: &Path,
    provider_leases: &Arc<account_lifecycle::ProviderLeaseRegistry>,
    provider: ProductProviderId,
    operation_id: &str,
    code: &str,
    now_ms: u64,
) -> Result<(), String> {
    let lease_id =
        account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
    let _lease = provider_leases
        .acquire_exclusive(
            oauth_dir,
            provider,
            lease_id,
            account_lifecycle::ProviderOperationKind::OAuthActivation,
        )
        .map_err(|error| error.wire().to_string())?;
    let repository = audited_account_lifecycle_repository(oauth_dir, cfg)?;
    let active = repository
        .active_operation(provider)
        .map_err(|error| error.wire().to_string())?
        .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
    if active.prepared.operation_id != operation_id {
        return Err("lifecycle_operation_mismatch".into());
    }
    let journal = repository
        .load_journal(&active.journal_record_id)
        .map_err(|error| error.wire().to_string())?
        .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
    match journal.phase {
        account_lifecycle::AccountLifecyclePhase::ExchangeInFlight => {
            repository
                .transition_journal(
                    &active.journal_record_id,
                    account_lifecycle::AccountLifecyclePhase::ExchangeInFlight,
                    account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown,
                    Some(code),
                    now_ms,
                )
                .map_err(|error| error.wire().to_string())?;
            Ok(())
        }
        account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown => Ok(()),
        _ => Err("lifecycle_phase_mismatch".into()),
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn fetch_codex_subject(
    http: &isyncyou_agent::http::HttpTransport,
    token: &isyncyou_agent::oauth::CodexTokens,
    config: &isyncyou_agent::oauth::CodexOAuthConfig,
    state: &str,
    started_at_seconds: i64,
    now_seconds: i64,
) -> Result<String, account_identity::IdentityError> {
    const DISCOVERY_URL: &str = "https://auth.openai.com/.well-known/openid-configuration";
    let discovery = http
        .get_public_json(DISCOVERY_URL, 32 * 1024)
        .map_err(|_| account_identity::IdentityError::InvalidDiscovery)?;
    if !(200..300).contains(&discovery.status) {
        return Err(account_identity::IdentityError::InvalidDiscovery);
    }
    let jwks_uri = account_identity::validate_codex_discovery(
        &discovery.body,
        &discovery.content_type,
        discovery.redirected,
    )?;
    let fetch_jwks = || {
        let response = http
            .get_public_json(&jwks_uri, 256 * 1024)
            .map_err(|_| account_identity::IdentityError::InvalidJwks)?;
        if !(200..300).contains(&response.status) {
            return Err(account_identity::IdentityError::InvalidJwks);
        }
        Ok(account_identity::JwksResponse {
            body: response.body,
            content_type: response.content_type,
            redirected: response.redirected,
            source_origin: account_identity::CODEX_OIDC_ISSUER.into(),
        })
    };
    let initial = fetch_jwks()?;
    account_identity::validate_codex_subject(
        &token.id_token,
        &token.access_token,
        &config.client_id,
        &account_identity::OidcAttemptBinding {
            expected_state: state,
            callback_state: state,
            expected_nonce: None,
            started_at_seconds,
            now_seconds,
        },
        initial,
        fetch_jwks,
    )
    .map(|validated| validated.subject_digest)
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn commit_codex_oauth_candidate(
    runtime: &CodexCandidateRuntime,
    operation_id: &str,
    token: isyncyou_agent::oauth::CodexTokens,
    state: &str,
    started_at_seconds: i64,
    http: &isyncyou_agent::http::HttpTransport,
) -> Result<(), String> {
    let lease_id =
        account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
    let _provider_lease = runtime
        .provider_leases
        .acquire_exclusive(
            &runtime.oauth_dir,
            ProductProviderId::Codex,
            lease_id,
            account_lifecycle::ProviderOperationKind::OAuthActivation,
        )
        .map_err(|error| error.wire().to_string())?;
    let repository = audited_account_lifecycle_repository(&runtime.oauth_dir, &runtime.cfg)?;
    let active = repository
        .active_operation(ProductProviderId::Codex)
        .map_err(|error| error.wire().to_string())?
        .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
    if active.prepared.operation_id != operation_id {
        return Err("lifecycle_operation_mismatch".into());
    }
    let journal_id = active.journal_record_id.clone();
    let journal = repository
        .load_journal(&journal_id)
        .map_err(|error| error.wire().to_string())?
        .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
    if journal.phase != account_lifecycle::AccountLifecyclePhase::ExchangeInFlight {
        return Err("lifecycle_phase_mismatch".into());
    }

    let created_at_ms = (runtime.now_ms)();
    let candidate_id = repository
        .candidate_record_id(ProductProviderId::Codex, operation_id)
        .map_err(|error| error.wire().to_string())?;
    let material = OAuthCandidateMaterial {
        provider: ProductProviderId::Codex,
        access_token: token.access_token.clone(),
        refresh_token: token.refresh_token.clone(),
        expires_at_ms: created_at_ms.saturating_add(token.expires_in.saturating_mul(1_000)),
        provider_account_id: Some(token.account_id.clone()),
    };
    let candidate = account_lifecycle::OAuthCandidateV1 {
        version: 1,
        provider: ProductProviderId::Codex,
        operation_id: operation_id.to_string(),
        record_id: candidate_id.clone(),
        access_token: material.access_token.clone(),
        refresh_token: material.refresh_token.clone(),
        expires_at_ms: material.expires_at_ms.max(created_at_ms),
        provider_account_id: material.provider_account_id.clone(),
        subject_digest: None,
        session_id_digest: None,
        result_generation: None,
        state: account_lifecycle::OAuthCandidateState::GrantBearing,
        created_at_ms,
        terminal_at_ms: None,
    };
    repository
        .publish_candidate(&journal_id, &candidate, created_at_ms)
        .map_err(|error| error.wire().to_string())?;
    repository
        .delete_exchange_intent(ProductProviderId::Codex, operation_id)
        .map_err(|error| error.wire().to_string())?;
    repository
        .begin_candidate_validation(&journal_id, (runtime.now_ms)())
        .map_err(|error| error.wire().to_string())?;

    let identity = fetch_codex_subject(
        http,
        &token,
        &isyncyou_agent::oauth::CodexOAuthConfig::default(),
        state,
        started_at_seconds,
        i64::try_from((runtime.now_ms)() / 1_000).unwrap_or(i64::MAX),
    );
    let accepted_subject = identity.ok().filter(|subject| {
        journal.prepared.mode != account_lifecycle::AccountLifecycleMode::Switch
            || journal
                .prepared
                .prior_subject_digest
                .as_deref()
                .is_some_and(|prior| prior != subject)
    });
    let Some(subject_digest) = accepted_subject else {
        let code = if journal.prepared.mode == account_lifecycle::AccountLifecycleMode::Switch
            && journal.prepared.prior_subject_digest.is_some()
        {
            "same_account_selected"
        } else {
            "candidate_identity_invalid"
        };
        repository
            .require_candidate_cleanup(&journal_id, code, (runtime.now_ms)())
            .map_err(|error| error.wire().to_string())?;
        // Candidate revocation is a separate authenticated lifecycle operation. The browser
        // callback owns only exchange, encrypted candidate persistence, and identity validation;
        // Android must end the OAuth guard before acquiring a fresh credential-revoke guard.
        return Err(code.into());
    };

    let mut meta = ProductBundleMeta::fresh(ProductProviderId::Codex)?;
    meta.identity.subject_digest = Some(subject_digest);
    repository
        .bind_candidate_generation(&journal_id, &candidate_id, &meta.generation)
        .map_err(|error| error.wire().to_string())?;
    let _runtime_gate = runtime
        .product_runtime_gate
        .lock()
        .map_err(|_| "provider_busy".to_string())?;
    let _snapshot = acquire_product_runtime_file_lock(&runtime.oauth_dir)?;
    let current = repository
        .active_operation(ProductProviderId::Codex)
        .map_err(|error| error.wire().to_string())?
        .ok_or_else(|| "stale_lifecycle_fence".to_string())?;
    if current.operation_etag != active.operation_etag
        || current.prepared.fence_epoch != active.prepared.fence_epoch
    {
        return Err("stale_lifecycle_fence".into());
    }
    store_codex_bundle(
        &runtime.oauth_dir,
        &CodexStoredCredential {
            access_token: material.access_token,
            refresh_token: material.refresh_token,
            account_id: material.provider_account_id.unwrap_or_default(),
            expires_at_ms: material.expires_at_ms,
        },
        &meta,
    )?;
    persist_product_activation(
        &runtime.oauth_dir,
        ProductProviderId::Codex,
        &meta.generation,
    )?;
    store_agent_provider_selection(
        &runtime.oauth_dir,
        "codex",
        &isyncyou_agent::CodexConfig::default().model,
    )?;
    repository
        .promote_candidate(
            &journal_id,
            &candidate_id,
            &meta.generation,
            (runtime.now_ms)(),
        )
        .map_err(|error| error.wire().to_string())?;
    Ok(())
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
/// One-shot loopback callback server for the Codex OAuth (OpenAI registers the fixed
/// `:1455` redirect). Waits for the browser to hit `/auth/callback?code=&state=&scope=`, verifies
/// the CSRF `state`, exchanges the code, and persists the credential. The background
/// thread uses the same bounded lifetime as its owning OAuth attempt. It never persists
/// callback diagnostics or target data.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
struct CodexCallbackContext {
    oauth_dir: std::path::PathBuf,
    cfg: isyncyou_agent::oauth::CodexOAuthConfig,
    verifier: String,
    want_state: String,
    attempt_id: String,
    cancelled: Arc<AtomicBool>,
    attempts: Arc<Mutex<HashMap<String, OAuthAttempt>>>,
    lifecycle_bindings: Arc<Mutex<HashMap<String, OAuthLifecycleAttemptBinding>>>,
    operation_id: String,
    started_at_seconds: i64,
    candidate_runtime: CodexCandidateRuntime,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn codex_callback_serve(listener: std::net::TcpListener, context: CodexCallbackContext) {
    codex_callback_serve_until(
        listener,
        context,
        std::time::Instant::now() + OAUTH_ATTEMPT_TTL,
    );
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn claim_codex_callback_attempt(
    attempts: &Arc<Mutex<HashMap<String, OAuthAttempt>>>,
    attempt_id: &str,
    cancelled: &Arc<AtomicBool>,
) -> bool {
    let Ok(mut attempts) = attempts.lock() else {
        return false;
    };
    let owned = matches!(
        attempts.get(attempt_id),
        Some(OAuthAttempt::Codex { cancelled: current, .. })
            if Arc::ptr_eq(current, cancelled) && !cancelled.load(Ordering::Acquire)
    );
    if owned {
        attempts.remove(attempt_id);
    }
    owned
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn remove_owned_codex_attempt(
    attempts: &Arc<Mutex<HashMap<String, OAuthAttempt>>>,
    attempt_id: &str,
    cancelled: &Arc<AtomicBool>,
) -> bool {
    let Ok(mut attempts) = attempts.lock() else {
        return false;
    };
    let owned = matches!(
        attempts.get(attempt_id),
        Some(OAuthAttempt::Codex { cancelled: current, .. })
            if Arc::ptr_eq(current, cancelled)
    );
    if owned {
        attempts.remove(attempt_id);
    }
    owned
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn codex_callback_serve_until(
    listener: std::net::TcpListener,
    context: CodexCallbackContext,
    deadline: std::time::Instant,
) {
    use std::io::{Read, Write};
    let CodexCallbackContext {
        oauth_dir,
        cfg,
        verifier,
        want_state,
        attempt_id,
        cancelled,
        attempts,
        lifecycle_bindings,
        operation_id,
        started_at_seconds,
        candidate_runtime,
    } = context;
    let mut claimed = false;
    let mut completed = false;
    let mut terminal_code = None;
    if listener.set_nonblocking(true).is_ok() {
        while std::time::Instant::now() < deadline && !cancelled.load(Ordering::Acquire) {
            let mut stream = match listener.accept() {
                Ok((stream, _)) => stream,
                Err(error) if error.kind() == std::io::ErrorKind::WouldBlock => {
                    std::thread::sleep(std::time::Duration::from_millis(50));
                    continue;
                }
                Err(_) => break,
            };
            let _ = stream.set_read_timeout(Some(std::time::Duration::from_secs(15)));
            let mut buf = [0u8; 4096];
            let n = stream.read(&mut buf).unwrap_or(0);
            let req = String::from_utf8_lossy(&buf[..n]);
            let first_line = req.lines().next().unwrap_or("");
            let mut parts = first_line.split_whitespace();
            let method = parts.next().unwrap_or("");
            let target = parts.next().unwrap_or("");
            let path = target
                .split_once('?')
                .map(|(path, _)| path)
                .unwrap_or(target);
            if method != "GET" || path != "/auth/callback" {
                let _ = stream.write_all(b"HTTP/1.1 204 No Content\r\nContent-Length: 0\r\n\r\n");
                continue;
            }
            let query = target.split_once('?').map(|(_, query)| query).unwrap_or("");
            let code = match parse_codex_callback_query(query, &want_state) {
                ParsedCodexCallback::AuthorizationCode(code) => code,
                ParsedCodexCallback::UnboundCallback => {
                    let response = codex_callback_response(CODEX_ERR_HTML);
                    let _ = stream.write_all(response.as_bytes());
                    continue;
                }
                callback @ (ParsedCodexCallback::AuthorizationError
                | ParsedCodexCallback::InvalidBoundCallback) => {
                    if claim_codex_callback_attempt(&attempts, &attempt_id, &cancelled) {
                        claimed = true;
                        terminal_code = Some(
                            if matches!(callback, ParsedCodexCallback::AuthorizationError) {
                                "authorization_failed"
                            } else {
                                "callback_invalid"
                            },
                        );
                    }
                    let response = codex_callback_response(CODEX_ERR_HTML);
                    let _ = stream.write_all(response.as_bytes());
                    break;
                }
            };

            if !claim_codex_callback_attempt(&attempts, &attempt_id, &cancelled) {
                let response = codex_callback_response(CODEX_ERR_HTML);
                let _ = stream.write_all(response.as_bytes());
                break;
            }
            // The callback and cancel/reap paths race only here. Whoever removes this exact
            // pointer-bound attempt first owns the terminal result; a late callback has no authority
            // to exchange or persist credentials.
            claimed = true;
            let prepared = prepare_product_oauth_exchange(
                &candidate_runtime.cfg,
                &candidate_runtime.oauth_dir,
                &candidate_runtime.provider_leases,
                ProductProviderId::Codex,
                &operation_id,
                &attempt_id,
                (candidate_runtime.now_ms)(),
            );
            let exchange_prepared = prepared.is_ok();
            let exchange = prepared.map_err(|_| ()).and_then(|()| {
                isyncyou_agent::http::HttpTransport::shared()
                    .map_err(|_| ())
                    .and_then(|http| {
                        isyncyou_agent::oauth::codex_exchange(&http, &cfg, &code, &verifier)
                            .map_err(|_| ())
                    })
            });
            let ok = match exchange {
                Ok(token) => {
                    let commit = isyncyou_agent::http::HttpTransport::shared()
                        .map_err(|_| "transport_unavailable".to_string())
                        .and_then(|http| {
                            commit_codex_oauth_candidate(
                                &candidate_runtime,
                                &operation_id,
                                token,
                                &want_state,
                                started_at_seconds,
                                http.as_ref(),
                            )
                        });
                    match commit {
                        Ok(()) => {
                            completed = true;
                            true
                        }
                        Err(error) => {
                            let _ = mark_product_oauth_exchange_unknown(
                                &candidate_runtime.cfg,
                                &candidate_runtime.oauth_dir,
                                &candidate_runtime.provider_leases,
                                ProductProviderId::Codex,
                                &operation_id,
                                "exchange_outcome_unknown",
                                (candidate_runtime.now_ms)(),
                            );
                            terminal_code = Some(match error.as_str() {
                                "same_account_selected" => "same_account_selected",
                                "candidate_identity_invalid" => "candidate_identity_invalid",
                                "candidate_revoke_unknown" => "candidate_revoke_unknown",
                                _ => "commit_failed",
                            });
                            false
                        }
                    }
                }
                Err(()) => {
                    if exchange_prepared {
                        let _ = mark_product_oauth_exchange_unknown(
                            &candidate_runtime.cfg,
                            &candidate_runtime.oauth_dir,
                            &candidate_runtime.provider_leases,
                            ProductProviderId::Codex,
                            &operation_id,
                            "exchange_outcome_unknown",
                            (candidate_runtime.now_ms)(),
                        );
                    }
                    terminal_code = Some("exchange_failed");
                    false
                }
            };
            let body = if ok { CODEX_OK_HTML } else { CODEX_ERR_HTML };
            let response = codex_callback_response(body);
            let _ = stream.write_all(response.as_bytes());
            break;
        }
    }

    // If no callback claimed the attempt, timeout/listener failure may terminate only the exact
    // entry still owned by this thread. Cancel and the TTL reaper remove it first and own their
    // already-recorded terminal state, preventing a second terminal transition.
    if !claimed
        && remove_owned_codex_attempt(&attempts, &attempt_id, &cancelled)
        && !cancelled.load(Ordering::Acquire)
    {
        terminal_code = Some("interrupted");
    }
    if claimed && !completed && terminal_code.is_none() {
        terminal_code = Some("interrupted");
    }
    if let Some(code) = terminal_code {
        record_onboarding_attempt_transition(
            &oauth_dir,
            ProductProviderId::Codex,
            &attempt_id,
            ProductOnboardingState::ErrorRedacted,
            Some(code.to_string()),
        );
    }
    if let Ok(mut bindings) = lifecycle_bindings.lock() {
        bindings.remove(&attempt_id);
    };
}

/// Product Claude/Codex OAuth runtime (#623). `agent-oauth-providers` owns the app OAuth
/// credential path; `agent-subscription-experimental` layers the local CLI fallback/capture
/// surface tracked by #627.
#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl DaemonAgent {
    /// A human-facing success page shown in the **system browser** after the callback.
    const OAUTH_SUCCESS_HTML: &'static str = "<!doctype html><html><head><meta charset=utf-8>\
<meta name=viewport content=\"width=device-width,initial-scale=1\">\
<title>iSyncYou connected</title><style>body{font-family:system-ui;background:#0b0d12;color:#e8eaf0;\
display:flex;min-height:100vh;align-items:center;justify-content:center;margin:0}\
.c{text-align:center;max-width:22rem;padding:2rem}h1{font-size:1.4rem;margin:.5rem 0}\
p{color:#9aa3b2;line-height:1.5}</style></head><body><div class=c>\
<h1>Connected</h1><p>This device is now authorized. You can close this tab and return to iSyncYou.</p>\
</div></body></html>";

    /// Load the compiled official Claude OAuth recipe. A local `agent-oauth.json` may
    /// assert the same tuple for development diagnostics, but it cannot override any
    /// endpoint, client, scope, or redirect used by the product flow.
    fn load_oauth_config(&self) -> Result<isyncyou_agent::OAuthConfig, String> {
        let path = self.oauth_dir.join("agent-oauth.json");
        if path.exists() {
            let source = std::fs::read_to_string(&path)
                .map_err(|_| "OAuth recipe is unavailable".to_string())?;
            let candidate: isyncyou_agent::OAuthConfig =
                serde_json::from_str(&source).map_err(|_| "OAuth recipe is invalid".to_string())?;
            let official = isyncyou_agent::OAuthConfig::default();
            if candidate.authorize_url != official.authorize_url
                || candidate.token_url != official.token_url
                || candidate.client_id != official.client_id
                || candidate.scopes != official.scopes
                || candidate.manual_redirect_url != official.manual_redirect_url
            {
                return Err("OAuth recipe does not match the official product policy".to_string());
            }
            Ok(official)
        } else {
            Ok(isyncyou_agent::OAuthConfig::default())
        }
    }

    /// Persist a subscription credential (access + refresh + expiry) at rest under a
    /// device-local key, so the daemon can refresh the access token itself.
    #[allow(dead_code)]
    fn store_credential(&self, cred: &StoredCredential) -> Result<(), String> {
        // A bare `store_credential` is a fresh login: mint a new generation (#639), then activate
        // the product path for that generation (attest -> durable ProductActivationV1).
        let meta = ProductBundleMeta::fresh(ProductProviderId::Claude)?;
        self.store_claude_bundle(cred, &meta)?;
        activate_product(&self.oauth_dir, ProductProviderId::Claude, &meta.generation)
    }

    /// Persist a Claude credential with explicit V2 metadata (#639) — used by refresh to preserve
    /// the credential `generation` and to persist a `ReconnectRequired` lifecycle fail-closed.
    fn store_claude_bundle(
        &self,
        cred: &StoredCredential,
        meta: &ProductBundleMeta,
    ) -> Result<(), String> {
        store_agent_credential_blob(
            &self.oauth_dir,
            SUBSCRIPTION_CREDENTIAL_ID,
            meta.to_blob(cred.to_json()),
        )
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    #[allow(dead_code)]
    fn lifecycle_credential(
        &self,
        provider: ProductProviderId,
    ) -> Result<Option<(ProductCredentialMaterial, ProductBundleMeta)>, String> {
        let credential_id = match provider {
            ProductProviderId::Claude => SUBSCRIPTION_CREDENTIAL_ID,
            ProductProviderId::Codex => CODEX_CREDENTIAL_ID,
        };
        let Some(secret) = load_agent_credential_blob(&self.oauth_dir, credential_id)? else {
            return Ok(None);
        };
        let meta = ProductBundleMeta::from_blob(secret.expose(), provider)
            .ok_or_else(|| "credential_invalid".to_string())?;
        let material = match provider {
            ProductProviderId::Claude => ProductCredentialMaterial::Claude(
                StoredCredential::from_json(secret.expose())
                    .ok_or_else(|| "credential_invalid".to_string())?,
            ),
            ProductProviderId::Codex => ProductCredentialMaterial::Codex(
                CodexStoredCredential::from_json(secret.expose())
                    .ok_or_else(|| "credential_invalid".to_string())?,
            ),
        };
        Ok(Some((material, meta)))
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    #[allow(dead_code)]
    fn persist_lifecycle_bundle(
        &self,
        provider: ProductProviderId,
        material: &ProductCredentialMaterial,
        meta: &ProductBundleMeta,
    ) -> Result<(), String> {
        match (provider, material) {
            (ProductProviderId::Claude, ProductCredentialMaterial::Claude(value)) => {
                self.store_claude_bundle(value, meta)
            }
            (ProductProviderId::Codex, ProductCredentialMaterial::Codex(value)) => {
                store_codex_bundle(&self.oauth_dir, value, meta)
            }
            _ => Err("credential_invalid".into()),
        }
    }

    /// Persist the FULL token set from the OAuth code exchange (access + refresh + expiry) so
    /// `fresh_access_token` can self-refresh before the ~8h subscription token expires
    /// (LIVE-verified 2026-07-01 — without the refresh token the client "connection-lost"s
    /// every ~8h with no way to renew).
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    #[allow(dead_code)]
    fn store_token(&self, token: &isyncyou_agent::oauth::RefreshedToken) -> Result<(), String> {
        let expires_at_ms = if token.expires_in > 0 {
            now_ms() + token.expires_in * 1000
        } else {
            0
        };
        self.store_credential(&StoredCredential {
            access_token: token.access_token.clone(),
            refresh_token: token.refresh_token.clone(),
            expires_at_ms,
        })
    }

    /// The one authenticated provider/model snapshot consumed by status and the runtime gate.
    /// Missing, malformed, unknown, or legacy plaintext settings are unconfigured; there is no
    /// environment/default fallback that could silently select another product identity.
    fn agent_settings(&self) -> Option<AgentSettingsSnapshot> {
        load_agent_provider_selection(&self.oauth_dir)
    }

    /// Persist the switcher selection after validating it against the offered models.
    fn set_agent_settings(&self, provider: &str, model: &str) -> Result<(), String> {
        store_agent_provider_selection(&self.oauth_dir, provider, model)
    }

    fn set_agent_settings_with_effort(
        &self,
        provider: &str,
        model: &str,
        reasoning_effort: Option<&str>,
    ) -> Result<(), String> {
        store_agent_provider_selection_with_effort(
            &self.oauth_dir,
            provider,
            model,
            reasoning_effort,
        )
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    #[allow(dead_code)]
    fn disconnect_product_provider_with_transport(
        &self,
        provider: ProductProviderId,
        request_id: &str,
        transport: &dyn isyncyou_agent::oauth::ProductRevokeTransport,
    ) -> Result<AccountLifecycleResult, String> {
        self.run_old_grant_lifecycle_phase(
            provider,
            account_lifecycle::AccountLifecycleMode::Disconnect,
            request_id,
            transport,
        )
    }

    #[allow(dead_code)]
    fn run_old_grant_lifecycle_phase(
        &self,
        provider: ProductProviderId,
        mode: account_lifecycle::AccountLifecycleMode,
        request_id: &str,
        transport: &dyn isyncyou_agent::oauth::ProductRevokeTransport,
    ) -> Result<AccountLifecycleResult, String> {
        if !matches!(
            mode,
            account_lifecycle::AccountLifecycleMode::Disconnect
                | account_lifecycle::AccountLifecycleMode::Reconnect
                | account_lifecycle::AccountLifecycleMode::Switch
        ) {
            return Err("lifecycle_mode_invalid".into());
        }
        let lease_id =
            account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
        let _provider_lease = self
            .provider_leases
            .acquire_exclusive(
                &self.oauth_dir,
                provider,
                lease_id,
                account_lifecycle::ProviderOperationKind::Lifecycle,
            )
            .map_err(|error| error.wire().to_string())?;

        let repository = audited_account_lifecycle_repository(&self.oauth_dir, &self.cfg)?;
        let (material, mut meta, operation) = {
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| "provider_busy".to_string())?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
            let Some((material, meta)) = self.lifecycle_credential(provider)? else {
                return Ok(AccountLifecycleResult {
                    state: "disconnected",
                    code: "already_disconnected",
                    retryable: false,
                    operation_id: None,
                    operation_etag: None,
                });
            };
            let refresh_present = match &material {
                ProductCredentialMaterial::Claude(value) => !value.refresh_token.is_empty(),
                ProductCredentialMaterial::Codex(value) => !value.refresh_token.is_empty(),
            };
            let target = if refresh_present {
                isyncyou_agent::oauth::RevokeRequestTarget::RefreshToken
            } else {
                isyncyou_agent::oauth::RevokeRequestTarget::AccessToken
            };
            let operation = repository
                .begin_operation(
                    provider,
                    account_lifecycle::AccountLifecycleRoute::Logout,
                    mode,
                    request_id,
                    Some(&meta.generation),
                    meta.identity.subject_digest.as_deref(),
                    Some(target),
                    Some(isyncyou_agent::oauth::RevokeScopeGuarantee::ObservedTokenSession),
                    (self.credential_now_ms)(),
                )
                .map_err(|error| error.wire().to_string())?;
            (material, meta, operation)
        };

        let Some(mut journal) = repository
            .load_journal(&operation.journal_record_id)
            .map_err(|error| error.wire().to_string())?
        else {
            return Ok(AccountLifecycleResult {
                state: "disconnected",
                code: "already_disconnected",
                retryable: false,
                operation_id: Some(operation.operation_id),
                operation_etag: Some(operation.operation_etag),
            });
        };

        if journal.phase == account_lifecycle::AccountLifecyclePhase::RevokedPendingCleanup {
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| "provider_busy".to_string())?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
            delete_provider_product_state_durable(&self.oauth_dir, provider)?;
            if let Ok(mut usage) = self.last_usage.lock() {
                usage.remove(&provider);
            }
            if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                repository
                    .complete_disconnect(&operation.journal_record_id, (self.credential_now_ms)())
                    .map_err(|error| error.wire().to_string())?;
            } else {
                repository
                    .await_oauth_login(&operation.journal_record_id, (self.credential_now_ms)())
                    .map_err(|error| error.wire().to_string())?;
            }
            return Ok(AccountLifecycleResult {
                state: if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                    "disconnected"
                } else {
                    "awaiting_oauth_login"
                },
                code: if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                    "disconnected"
                } else {
                    "oauth_required"
                },
                retryable: false,
                operation_id: Some(operation.operation_id),
                operation_etag: Some(operation.operation_etag),
            });
        }

        if !matches!(meta.lifecycle, CredentialLifecycle::Disconnecting { .. }) {
            meta.lifecycle = CredentialLifecycle::Disconnecting {
                operation_id: operation.operation_id.clone(),
            };
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| "provider_busy".to_string())?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
            self.persist_lifecycle_bundle(provider, &material, &meta)?;
        }

        journal = repository
            .start_active_revoke(&operation.journal_record_id, (self.credential_now_ms)())
            .map_err(|error| error.wire().to_string())?;
        let revoke_credential = material.revoke_credential();
        let outcome = account_lifecycle_revoke_outcome_for_device_test().unwrap_or_else(|| {
            isyncyou_agent::oauth::revoke_product_credential(
                transport,
                provider,
                &revoke_credential,
            )
        });

        let _runtime = self
            .product_runtime_gate
            .lock()
            .map_err(|_| "provider_busy".to_string())?;
        let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
        let current = repository
            .load_journal(&operation.journal_record_id)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "stale_lifecycle_fence".to_string())?;
        if current.operation_etag != journal.operation_etag
            || current.prepared.fence_epoch != journal.prepared.fence_epoch
        {
            return Err("stale_lifecycle_fence".into());
        }
        match outcome {
            isyncyou_agent::oauth::RevokeOutcome::Confirmed { .. } => {
                repository
                    .publish_revoke_outcome(
                        &operation.journal_record_id,
                        true,
                        "revoke_confirmed",
                        (self.credential_now_ms)(),
                    )
                    .map_err(|error| error.wire().to_string())?;
                account_lifecycle_revoke_checkpoint_for_device_test();
                delete_provider_product_state_durable(&self.oauth_dir, provider)?;
                if let Ok(mut usage) = self.last_usage.lock() {
                    usage.remove(&provider);
                }
                if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                    repository
                        .complete_disconnect(
                            &operation.journal_record_id,
                            (self.credential_now_ms)(),
                        )
                        .map_err(|error| error.wire().to_string())?;
                } else {
                    repository
                        .await_oauth_login(&operation.journal_record_id, (self.credential_now_ms)())
                        .map_err(|error| error.wire().to_string())?;
                }
                Ok(AccountLifecycleResult {
                    state: if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                        "disconnected"
                    } else {
                        "awaiting_oauth_login"
                    },
                    code: if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                        "disconnected"
                    } else {
                        "oauth_required"
                    },
                    retryable: false,
                    operation_id: Some(operation.operation_id),
                    operation_etag: Some(operation.operation_etag),
                })
            }
            isyncyou_agent::oauth::RevokeOutcome::Retryable { code }
            | isyncyou_agent::oauth::RevokeOutcome::Terminal { code } => {
                let code = revoke_failure_wire(code);
                repository
                    .publish_revoke_outcome(
                        &operation.journal_record_id,
                        false,
                        code,
                        (self.credential_now_ms)(),
                    )
                    .map_err(|error| error.wire().to_string())?;
                Ok(AccountLifecycleResult {
                    state: "revoke_unknown",
                    code,
                    retryable: true,
                    operation_id: Some(operation.operation_id),
                    operation_etag: Some(operation.operation_etag),
                })
            }
        }
    }

    #[allow(clippy::too_many_arguments)]
    #[allow(dead_code)]
    fn process_oauth_candidate_with_transport(
        &self,
        provider: ProductProviderId,
        operation_id: &str,
        material: OAuthCandidateMaterial,
        identity: CandidateIdentityDecision,
        _transport: &dyn isyncyou_agent::oauth::ProductRevokeTransport,
    ) -> Result<AccountLifecycleResult, String> {
        if material.provider != provider {
            return Err("candidate_provider_mismatch".into());
        }
        let lease_id =
            account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
        let _provider_lease = self
            .provider_leases
            .acquire_exclusive(
                &self.oauth_dir,
                provider,
                lease_id,
                account_lifecycle::ProviderOperationKind::OAuthActivation,
            )
            .map_err(|error| error.wire().to_string())?;
        let repository = audited_account_lifecycle_repository(&self.oauth_dir, &self.cfg)?;
        let active = repository
            .active_operation(provider)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
        if active.prepared.operation_id != operation_id {
            return Err("lifecycle_operation_mismatch".into());
        }
        let journal_id = active.journal_record_id;
        #[cfg(test)]
        if repository
            .load_journal(&journal_id)
            .map_err(|error| error.wire().to_string())?
            .is_some_and(|journal| {
                journal.phase == account_lifecycle::AccountLifecyclePhase::AwaitingOAuthLogin
            })
        {
            repository
                .prepare_exchange(&journal_id, &"a".repeat(32), (self.credential_now_ms)())
                .map_err(|error| error.wire().to_string())?;
        }
        let journal = repository
            .load_journal(&journal_id)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
        if journal.phase != account_lifecycle::AccountLifecyclePhase::ExchangeInFlight {
            return Err("lifecycle_phase_mismatch".into());
        }

        let candidate_id = repository
            .candidate_record_id(provider, operation_id)
            .map_err(|error| error.wire().to_string())?;
        let created_at_ms = (self.credential_now_ms)();
        let candidate = account_lifecycle::OAuthCandidateV1 {
            version: 1,
            provider,
            operation_id: operation_id.to_string(),
            record_id: candidate_id.clone(),
            access_token: material.access_token.clone(),
            refresh_token: material.refresh_token.clone(),
            expires_at_ms: material.expires_at_ms.max(created_at_ms),
            provider_account_id: material.provider_account_id.clone(),
            subject_digest: None,
            session_id_digest: None,
            result_generation: None,
            state: account_lifecycle::OAuthCandidateState::GrantBearing,
            created_at_ms,
            terminal_at_ms: None,
        };
        repository
            .publish_candidate(&journal_id, &candidate, created_at_ms)
            .map_err(|error| error.wire().to_string())?;
        repository
            .delete_exchange_intent(provider, operation_id)
            .map_err(|error| error.wire().to_string())?;
        repository
            .begin_candidate_validation(&journal_id, (self.credential_now_ms)())
            .map_err(|error| error.wire().to_string())?;

        let identity = if force_candidate_validation_failure_for_device_test() {
            CandidateIdentityDecision::Invalid
        } else {
            identity
        };
        let prior_subject = active.prepared.prior_subject_digest.as_deref();
        let accepted_subject = match (journal.prepared.mode, provider, identity) {
            (
                account_lifecycle::AccountLifecycleMode::Switch,
                _,
                CandidateIdentityDecision::Unavailable | CandidateIdentityDecision::Invalid,
            ) => None,
            (
                account_lifecycle::AccountLifecycleMode::Switch,
                ProductProviderId::Codex,
                CandidateIdentityDecision::VerifiedSubject(subject),
            ) if prior_subject.is_some_and(|prior| prior != subject) => Some(subject),
            (
                account_lifecycle::AccountLifecycleMode::Switch,
                ProductProviderId::Codex,
                CandidateIdentityDecision::VerifiedSubject(_),
            ) => None,
            (
                account_lifecycle::AccountLifecycleMode::Connect
                | account_lifecycle::AccountLifecycleMode::Reconnect,
                ProductProviderId::Codex,
                CandidateIdentityDecision::VerifiedSubject(subject),
            ) => Some(subject),
            (
                account_lifecycle::AccountLifecycleMode::Connect
                | account_lifecycle::AccountLifecycleMode::Reconnect,
                ProductProviderId::Claude,
                CandidateIdentityDecision::Unavailable,
            ) => Some(String::new()),
            _ => None,
        };

        let Some(subject) = accepted_subject else {
            let code = if journal.prepared.mode == account_lifecycle::AccountLifecycleMode::Switch
                && matches!(provider, ProductProviderId::Claude)
            {
                "switch_identity_unavailable"
            } else if journal.prepared.mode == account_lifecycle::AccountLifecycleMode::Switch
                && prior_subject.is_some()
            {
                "same_account_selected"
            } else {
                "candidate_identity_invalid"
            };
            repository
                .require_candidate_cleanup(&journal_id, code, (self.credential_now_ms)())
                .map_err(|error| error.wire().to_string())?;
            let result = AccountLifecycleResult {
                state: "candidate_cleanup",
                code,
                retryable: true,
                operation_id: Some(operation_id.to_string()),
                operation_etag: Some(active.operation_etag),
            };
            return Ok(result);
        };

        let mut meta = ProductBundleMeta::fresh(provider)?;
        meta.identity.subject_digest = (!subject.is_empty()).then_some(subject.clone());
        repository
            .bind_candidate_generation(&journal_id, &candidate_id, &meta.generation)
            .map_err(|error| error.wire().to_string())?;
        let _runtime = self
            .product_runtime_gate
            .lock()
            .map_err(|_| "provider_busy".to_string())?;
        let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
        let current = repository
            .active_operation(provider)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "stale_lifecycle_fence".to_string())?;
        if current.operation_etag != active.operation_etag
            || current.prepared.fence_epoch != active.prepared.fence_epoch
        {
            return Err("stale_lifecycle_fence".into());
        }
        match provider {
            ProductProviderId::Claude => self.store_claude_bundle(
                &StoredCredential {
                    access_token: material.access_token,
                    refresh_token: material.refresh_token,
                    expires_at_ms: material.expires_at_ms,
                },
                &meta,
            )?,
            ProductProviderId::Codex => store_codex_bundle(
                &self.oauth_dir,
                &CodexStoredCredential {
                    access_token: material.access_token,
                    refresh_token: material.refresh_token,
                    account_id: material.provider_account_id.unwrap_or_default(),
                    expires_at_ms: material.expires_at_ms,
                },
                &meta,
            )?,
        }
        persist_product_activation(&self.oauth_dir, provider, &meta.generation)?;
        let default_model = match provider {
            ProductProviderId::Claude => DEFAULT_MODEL,
            ProductProviderId::Codex => CODEX_MODELS[0].id,
        };
        self.set_agent_settings(provider.wire(), default_model)?;
        repository
            .promote_candidate(
                &journal_id,
                &candidate_id,
                &meta.generation,
                (self.credential_now_ms)(),
            )
            .map_err(|error| error.wire().to_string())?;
        let result = AccountLifecycleResult {
            state: "connected",
            code: "connected",
            retryable: false,
            operation_id: Some(operation_id.to_string()),
            operation_etag: Some(active.operation_etag),
        };
        Ok(result)
    }

    #[allow(dead_code)]
    fn begin_connect_lifecycle(
        &self,
        provider: ProductProviderId,
        request_id: &str,
    ) -> Result<AccountLifecycleResult, String> {
        let lease_id =
            account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
        let _provider_lease = self
            .provider_leases
            .acquire_exclusive(
                &self.oauth_dir,
                provider,
                lease_id,
                account_lifecycle::ProviderOperationKind::Lifecycle,
            )
            .map_err(|error| error.wire().to_string())?;
        let _runtime = self
            .product_runtime_gate
            .lock()
            .map_err(|_| "provider_busy".to_string())?;
        let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
        if self.lifecycle_credential(provider)?.is_some() {
            return Err("lifecycle_required".into());
        }
        let repository = audited_account_lifecycle_repository(&self.oauth_dir, &self.cfg)?;
        let operation = repository
            .begin_operation(
                provider,
                account_lifecycle::AccountLifecycleRoute::OAuthStart,
                account_lifecycle::AccountLifecycleMode::Connect,
                request_id,
                None,
                None,
                None,
                None,
                (self.credential_now_ms)(),
            )
            .map_err(|error| error.wire().to_string())?;
        repository
            .await_oauth_login(&operation.journal_record_id, (self.credential_now_ms)())
            .map_err(|error| error.wire().to_string())?;
        Ok(AccountLifecycleResult {
            state: "awaiting_oauth_login",
            code: "oauth_required",
            retryable: false,
            operation_id: Some(operation.operation_id),
            operation_etag: Some(operation.operation_etag),
        })
    }

    #[allow(dead_code)]
    fn begin_reconnect_or_switch_with_transport(
        &self,
        provider: ProductProviderId,
        mode: account_lifecycle::AccountLifecycleMode,
        request_id: &str,
        transport: &dyn isyncyou_agent::oauth::ProductRevokeTransport,
    ) -> Result<AccountLifecycleResult, String> {
        if mode == account_lifecycle::AccountLifecycleMode::Switch {
            let (_, meta) = self
                .lifecycle_credential(provider)?
                .ok_or_else(|| "already_disconnected".to_string())?;
            if meta.switch_capability() != account_identity::SwitchCapability::VerifiedSubject {
                return Err("switch_identity_unavailable".into());
            }
        }
        self.run_old_grant_lifecycle_phase(provider, mode, request_id, transport)
    }

    fn resume_lifecycle_operation_with_transport(
        &self,
        provider: ProductProviderId,
        operation_id: &str,
        operation_etag: &str,
        action: &str,
        transport: &dyn isyncyou_agent::oauth::ProductRevokeTransport,
    ) -> Result<AccountLifecycleResult, String> {
        let lease_id =
            account_lifecycle::mint_operation_id().map_err(|error| error.wire().to_string())?;
        let _provider_lease = self
            .provider_leases
            .acquire_exclusive(
                &self.oauth_dir,
                provider,
                lease_id,
                account_lifecycle::ProviderOperationKind::Lifecycle,
            )
            .map_err(|error| error.wire().to_string())?;
        let repository = audited_account_lifecycle_repository(&self.oauth_dir, &self.cfg)?;
        let active = repository
            .active_operation(provider)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
        if active.prepared.operation_id != operation_id || active.operation_etag != operation_etag {
            return Err("lifecycle_operation_mismatch".into());
        }
        let journal_id = active.journal_record_id;
        let journal = repository
            .load_journal(&journal_id)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
        let mode = journal.prepared.mode;

        let candidate_retry = match journal.phase {
            account_lifecycle::AccountLifecyclePhase::OAuthCandidateCleanup
                if action == "retry_revoke" =>
            {
                Some((
                    repository
                        .candidate_record_id(provider, operation_id)
                        .map_err(|error| error.wire().to_string())?,
                    match journal.closed_code.as_deref() {
                        Some("same_account_selected") => "same_account_selected",
                        Some("switch_identity_unavailable") => "switch_identity_unavailable",
                        Some("candidate_activation_interrupted") => {
                            "candidate_activation_interrupted"
                        }
                        _ => "candidate_identity_invalid",
                    },
                    true,
                ))
            }
            account_lifecycle::AccountLifecyclePhase::RevokeOutcomeUnknown
                if action == "retry_revoke" =>
            {
                journal
                    .revoked_grant
                    .as_ref()
                    .and_then(|grant| match grant {
                        account_lifecycle::RevokedGrantRef::OAuthCandidate { record_id } => {
                            Some((record_id.clone(), "candidate_identity_invalid", false))
                        }
                        account_lifecycle::RevokedGrantRef::ActiveCredential { .. } => None,
                    })
            }
            _ => None,
        };
        if let Some((candidate_id, terminal_code, first_attempt)) = candidate_retry {
            let candidate = repository
                .load_candidate(&candidate_id)
                .map_err(|error| error.wire().to_string())?
                .ok_or_else(|| "candidate_missing".to_string())?;
            let target = if candidate.refresh_token.is_empty() {
                isyncyou_agent::oauth::RevokeRequestTarget::AccessToken
            } else {
                isyncyou_agent::oauth::RevokeRequestTarget::RefreshToken
            };
            if first_attempt {
                repository
                    .start_candidate_revoke(
                        &journal_id,
                        &candidate_id,
                        target,
                        isyncyou_agent::oauth::RevokeScopeGuarantee::ObservedTokenSession,
                        (self.credential_now_ms)(),
                    )
                    .map_err(|error| error.wire().to_string())?;
            } else {
                repository
                    .start_active_revoke(&journal_id, (self.credential_now_ms)())
                    .map_err(|error| error.wire().to_string())?;
            }
            let material = OAuthCandidateMaterial {
                provider,
                access_token: candidate.access_token,
                refresh_token: candidate.refresh_token,
                expires_at_ms: candidate.expires_at_ms,
                provider_account_id: candidate.provider_account_id,
            };
            let outcome = account_lifecycle_revoke_outcome_for_device_test().unwrap_or_else(|| {
                isyncyou_agent::oauth::revoke_product_credential(
                    transport,
                    provider,
                    &material.revoke_credential(),
                )
            });
            return match outcome {
                isyncyou_agent::oauth::RevokeOutcome::Confirmed { .. } => {
                    repository
                        .mark_candidate_revoke_outcome(
                            &journal_id,
                            &candidate_id,
                            true,
                            "revoke_confirmed",
                            (self.credential_now_ms)(),
                        )
                        .map_err(|error| error.wire().to_string())?;
                    account_lifecycle_revoke_checkpoint_for_device_test();
                    repository
                        .finish_candidate_cleanup(
                            &journal_id,
                            &candidate_id,
                            terminal_code,
                            (self.credential_now_ms)(),
                        )
                        .map_err(|error| error.wire().to_string())?;
                    Ok(AccountLifecycleResult {
                        state: "disconnected",
                        code: terminal_code,
                        retryable: false,
                        operation_id: Some(operation_id.into()),
                        operation_etag: Some(operation_etag.into()),
                    })
                }
                isyncyou_agent::oauth::RevokeOutcome::Retryable { code }
                | isyncyou_agent::oauth::RevokeOutcome::Terminal { code } => {
                    let code = revoke_failure_wire(code);
                    repository
                        .mark_candidate_revoke_outcome(
                            &journal_id,
                            &candidate_id,
                            false,
                            code,
                            (self.credential_now_ms)(),
                        )
                        .map_err(|error| error.wire().to_string())?;
                    Ok(AccountLifecycleResult {
                        state: "candidate_revoke_unknown",
                        code,
                        retryable: true,
                        operation_id: Some(operation_id.into()),
                        operation_etag: Some(operation_etag.into()),
                    })
                }
            };
        }
        match (journal.phase, action) {
            (account_lifecycle::AccountLifecyclePhase::RevokedPendingCleanup, "resume_cleanup") => {
                let _runtime = self
                    .product_runtime_gate
                    .lock()
                    .map_err(|_| "provider_busy".to_string())?;
                let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
                delete_provider_product_state_durable(&self.oauth_dir, provider)?;
                if let Ok(mut usage) = self.last_usage.lock() {
                    usage.remove(&provider);
                }
                if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                    repository
                        .complete_disconnect(&journal_id, (self.credential_now_ms)())
                        .map_err(|error| error.wire().to_string())?;
                    Ok(AccountLifecycleResult {
                        state: "disconnected",
                        code: "disconnected",
                        retryable: false,
                        operation_id: Some(operation_id.into()),
                        operation_etag: Some(operation_etag.into()),
                    })
                } else {
                    repository
                        .await_oauth_login(&journal_id, (self.credential_now_ms)())
                        .map_err(|error| error.wire().to_string())?;
                    Ok(AccountLifecycleResult {
                        state: "awaiting_oauth_login",
                        code: "oauth_required",
                        retryable: false,
                        operation_id: Some(operation_id.into()),
                        operation_etag: Some(operation_etag.into()),
                    })
                }
            }
            (account_lifecycle::AccountLifecyclePhase::RevokeOutcomeUnknown, "retry_revoke") => {
                let (material, _) = self
                    .lifecycle_credential(provider)?
                    .ok_or_else(|| "credential_missing".to_string())?;
                let started = repository
                    .start_active_revoke(&journal_id, (self.credential_now_ms)())
                    .map_err(|error| error.wire().to_string())?;
                let outcome = isyncyou_agent::oauth::revoke_product_credential(
                    transport,
                    provider,
                    &material.revoke_credential(),
                );
                let current = repository
                    .load_journal(&journal_id)
                    .map_err(|error| error.wire().to_string())?
                    .ok_or_else(|| "stale_lifecycle_fence".to_string())?;
                if current.operation_etag != started.operation_etag
                    || current.prepared.fence_epoch != started.prepared.fence_epoch
                {
                    return Err("stale_lifecycle_fence".into());
                }
                match outcome {
                    isyncyou_agent::oauth::RevokeOutcome::Confirmed { .. } => {
                        repository
                            .publish_revoke_outcome(
                                &journal_id,
                                true,
                                "revoke_confirmed",
                                (self.credential_now_ms)(),
                            )
                            .map_err(|error| error.wire().to_string())?;
                        let _runtime = self
                            .product_runtime_gate
                            .lock()
                            .map_err(|_| "provider_busy".to_string())?;
                        let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)?;
                        delete_provider_product_state_durable(&self.oauth_dir, provider)?;
                        if let Ok(mut usage) = self.last_usage.lock() {
                            usage.remove(&provider);
                        }
                        if mode == account_lifecycle::AccountLifecycleMode::Disconnect {
                            repository
                                .complete_disconnect(&journal_id, (self.credential_now_ms)())
                                .map_err(|error| error.wire().to_string())?;
                            Ok(AccountLifecycleResult {
                                state: "disconnected",
                                code: "disconnected",
                                retryable: false,
                                operation_id: Some(operation_id.into()),
                                operation_etag: Some(operation_etag.into()),
                            })
                        } else {
                            repository
                                .await_oauth_login(&journal_id, (self.credential_now_ms)())
                                .map_err(|error| error.wire().to_string())?;
                            Ok(AccountLifecycleResult {
                                state: "awaiting_oauth_login",
                                code: "oauth_required",
                                retryable: false,
                                operation_id: Some(operation_id.into()),
                                operation_etag: Some(operation_etag.into()),
                            })
                        }
                    }
                    isyncyou_agent::oauth::RevokeOutcome::Retryable { code }
                    | isyncyou_agent::oauth::RevokeOutcome::Terminal { code } => {
                        let code = revoke_failure_wire(code);
                        repository
                            .publish_revoke_outcome(
                                &journal_id,
                                false,
                                code,
                                (self.credential_now_ms)(),
                            )
                            .map_err(|error| error.wire().to_string())?;
                        Ok(AccountLifecycleResult {
                            state: "revoke_unknown",
                            code,
                            retryable: true,
                            operation_id: Some(operation_id.into()),
                            operation_etag: Some(operation_etag.into()),
                        })
                    }
                }
            }
            (account_lifecycle::AccountLifecyclePhase::AwaitingOAuthLogin, "continue_oauth") => {
                Ok(AccountLifecycleResult {
                    state: "awaiting_oauth_login",
                    code: "oauth_required",
                    retryable: false,
                    operation_id: Some(operation_id.into()),
                    operation_etag: Some(operation_etag.into()),
                })
            }
            (
                account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown,
                "retry_exchange",
            ) => Ok(AccountLifecycleResult {
                state: "exchange_outcome_unknown",
                code: "exchange_outcome_unknown",
                retryable: true,
                operation_id: Some(operation_id.into()),
                operation_etag: Some(operation_etag.into()),
            }),
            _ => Err("lifecycle_phase_mismatch".into()),
        }
    }

    fn claude_product_bundle_state(
        &self,
    ) -> ProductCredentialState<(StoredCredential, ProductBundleMeta)> {
        match load_agent_credential_blob(&self.oauth_dir, SUBSCRIPTION_CREDENTIAL_ID) {
            Ok(None) => ProductCredentialState::Absent,
            Ok(Some(secret)) => {
                match ProductBundleMeta::from_blob(secret.expose(), ProductProviderId::Claude) {
                    Some(meta)
                        if meta.lifecycle == CredentialLifecycle::Active
                            && meta.policy_fingerprint
                                == oauth_policy_fingerprint(ProductProviderId::Claude) =>
                    {
                        match StoredCredential::from_json(secret.expose()).map(|credential| {
                            classify_claude_product_credential_at(
                                credential,
                                (self.credential_now_ms)(),
                            )
                        }) {
                            Some(ProductCredentialState::PresentValid(credential)) => {
                                ProductCredentialState::PresentValid((credential, meta))
                            }
                            Some(ProductCredentialState::PresentNeedsRefresh(credential)) => {
                                ProductCredentialState::PresentNeedsRefresh((credential, meta))
                            }
                            _ => ProductCredentialState::PresentInvalid,
                        }
                    }
                    _ => ProductCredentialState::PresentInvalid,
                }
            }
            Err(_) => ProductCredentialState::PresentInvalid,
        }
    }

    fn claude_product_credential_state(&self) -> ProductCredentialState<StoredCredential> {
        match self.claude_product_bundle_state() {
            ProductCredentialState::Absent => ProductCredentialState::Absent,
            ProductCredentialState::PresentValid((credential, _)) => {
                ProductCredentialState::PresentValid(credential)
            }
            ProductCredentialState::PresentNeedsRefresh((credential, _)) => {
                ProductCredentialState::PresentNeedsRefresh(credential)
            }
            ProductCredentialState::PresentInvalid => ProductCredentialState::PresentInvalid,
        }
    }

    fn capture_product_refresh_fence(
        &self,
        provider: ProductProviderId,
    ) -> Result<ProductRefreshFence, ProviderCredentialResolutionError> {
        let repository = account_lifecycle_repository(&self.oauth_dir)
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        let context = repository
            .load_existing()
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?
            .ok_or(ProviderCredentialResolutionError::ProductReconnectRequired)?;
        if context.authority.active_operations.contains_key(&provider) {
            return Err(ProviderCredentialResolutionError::ProductReconnectRequired);
        }
        Ok(ProductRefreshFence {
            selection: self.agent_settings(),
            lifecycle_epoch: context.authority.lifecycle_epoch,
            fence_epoch: context.authority.fence_epoch,
            lifecycle_key_version: context.authority.lifecycle_key_version,
            credential_etag: context
                .authority
                .current_credential_etags
                .get(&provider)
                .cloned(),
        })
    }

    fn capture_bound_product_refresh_fence(
        &self,
        provider: ProductProviderId,
    ) -> Result<ProductRefreshFence, ProviderCredentialResolutionError> {
        let fence = self.capture_product_refresh_fence(provider)?;
        fence
            .credential_etag
            .as_ref()
            .filter(|etag| !etag.is_empty())
            .ok_or(ProviderCredentialResolutionError::ProductReconnectRequired)?;
        Ok(fence)
    }

    #[cfg(feature = "agent-subscription-experimental")]
    fn capture_absent_product_refresh_fence(
        &self,
        provider: ProductProviderId,
    ) -> Result<ProductRefreshFence, ProviderCredentialResolutionError> {
        let fence = self.capture_product_refresh_fence(provider)?;
        if fence.credential_etag.is_some() {
            return Err(ProviderCredentialResolutionError::ProductReconnectRequired);
        }
        Ok(fence)
    }

    fn product_refresh_fence_matches(
        &self,
        provider: ProductProviderId,
        expected: &ProductRefreshFence,
    ) -> bool {
        let Ok(repository) = account_lifecycle_repository(&self.oauth_dir) else {
            return false;
        };
        let Ok(Some(context)) = repository.load_existing() else {
            return false;
        };
        // Epochs are installation-wide while provider leases are intentionally provider-scoped.
        // A monotonic advance caused solely by the other provider is safe when this provider's
        // generation etag, key version, selection, and active-operation slot are unchanged.
        !context.authority.active_operations.contains_key(&provider)
            && self.agent_settings() == expected.selection
            && context.authority.lifecycle_epoch >= expected.lifecycle_epoch
            && context.authority.fence_epoch >= expected.fence_epoch
            && context.authority.lifecycle_key_version == expected.lifecycle_key_version
            && context.authority.current_credential_etags.get(&provider)
                == expected.credential_etag.as_ref()
    }

    fn claude_bundle_matches(
        &self,
        expected_credential: &StoredCredential,
        expected_meta: &ProductBundleMeta,
    ) -> bool {
        let Ok(Some(secret)) =
            load_agent_credential_blob(&self.oauth_dir, SUBSCRIPTION_CREDENTIAL_ID)
        else {
            return false;
        };
        StoredCredential::from_json(secret.expose()).as_ref() == Some(expected_credential)
            && ProductBundleMeta::from_blob(secret.expose(), ProductProviderId::Claude).as_ref()
                == Some(expected_meta)
    }

    fn publish_claude_refresh_outcome(
        &self,
        original_credential: &StoredCredential,
        original_meta: &ProductBundleMeta,
        fence: &ProductRefreshFence,
        outcome: Result<StoredCredential, ProviderCredentialResolutionError>,
        failure_code: &'static str,
    ) -> Result<StoredCredential, ProviderCredentialResolutionError> {
        let _runtime = self
            .product_runtime_gate
            .lock()
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        let _refresh = self
            .credential_refresh_gate
            .lock()
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        if !self.product_refresh_fence_matches(ProductProviderId::Claude, fence)
            || !self.claude_bundle_matches(original_credential, original_meta)
        {
            return Err(ProviderCredentialResolutionError::ProductReconnectRequired);
        }
        match outcome {
            Ok(refreshed_credential) => {
                self.store_claude_bundle(&refreshed_credential, original_meta)
                    .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
                Ok(refreshed_credential)
            }
            Err(error) => {
                let mut reconnect_meta = original_meta.clone();
                reconnect_meta.lifecycle = CredentialLifecycle::ReconnectRequired {
                    closed_code: failure_code.into(),
                };
                self.store_claude_bundle(original_credential, &reconnect_meta)
                    .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
                Err(error)
            }
        }
    }

    fn refresh_claude_product_credential_with_fence(
        &self,
        credential: StoredCredential,
        meta: ProductBundleMeta,
        fence: ProductRefreshFence,
    ) -> Result<StoredCredential, ProviderCredentialResolutionError> {
        let official_policy = oauth_policy_fingerprint(ProductProviderId::Claude);
        let (outcome, failure_code) = if meta.provider != ProductProviderId::Claude
            || meta.lifecycle != CredentialLifecycle::Active
            || meta.policy_fingerprint != official_policy
        {
            (
                Err(ProviderCredentialResolutionError::ProductReconnectRequired),
                "oauth_policy_changed",
            )
        } else if credential.refresh_token.trim().is_empty() {
            (
                Err(ProviderCredentialResolutionError::ProductReconnectRequired),
                "refresh_failed",
            )
        } else if let Ok(config) = self.load_oauth_config() {
            let outcome = isyncyou_agent::http::HttpTransport::shared()
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)
                .and_then(|http| {
                    isyncyou_agent::oauth::refresh(&http, &config, &credential.refresh_token)
                        .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)
                })
                .and_then(|refreshed| {
                    complete_claude_refresh(
                        credential.clone(),
                        refreshed,
                        (self.credential_now_ms)(),
                    )
                });
            (outcome, "refresh_failed")
        } else {
            (
                Err(ProviderCredentialResolutionError::ProductReconnectRequired),
                "oauth_policy_changed",
            )
        };
        self.publish_claude_refresh_outcome(&credential, &meta, &fence, outcome, failure_code)
    }

    #[cfg(test)]
    fn refresh_claude_product_credential_unlocked(
        &self,
        credential: StoredCredential,
        meta: ProductBundleMeta,
    ) -> Result<StoredCredential, ProviderCredentialResolutionError> {
        let fence = {
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
            let _refresh = self
                .credential_refresh_gate
                .lock()
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
            self.capture_bound_product_refresh_fence(ProductProviderId::Claude)?
        };
        self.refresh_claude_product_credential_with_fence(credential, meta, fence)
    }

    #[cfg(any(test, feature = "agent-subscription-experimental"))]
    fn experimental_claude_credential(
        &self,
    ) -> Result<Option<StoredCredential>, ProviderCredentialResolutionError> {
        #[cfg(feature = "agent-subscription-experimental")]
        {
            match local_cli_fallback::load_claude_from_process() {
                Ok(credential) => Ok(Some(StoredCredential {
                    access_token: credential.access_token,
                    refresh_token: String::new(),
                    expires_at_ms: 0,
                })),
                Err(error) if error.is_absent() => Ok(None),
                Err(error) if error.is_unsupported_platform() => {
                    Err(ProviderCredentialResolutionError::ExperimentalUnsupportedPlatform)
                }
                Err(_) => Err(ProviderCredentialResolutionError::ExperimentalCredentialRejected),
            }
        }
        #[cfg(not(feature = "agent-subscription-experimental"))]
        {
            Ok(None)
        }
    }

    #[cfg(test)]
    fn resolve_claude_credential(
        &self,
    ) -> Result<ResolvedProviderCredential, ProviderCredentialResolutionError> {
        match self.claude_product_bundle_state() {
            ProductCredentialState::PresentValid((credential, _meta)) => {
                Ok(ResolvedProviderCredential::Claude {
                    origin: ProviderCredentialOrigin::ProductCredentialStore,
                    credential,
                })
            }
            ProductCredentialState::PresentNeedsRefresh((credential, meta)) => {
                let credential =
                    self.refresh_claude_product_credential_unlocked(credential, meta)?;
                Ok(ResolvedProviderCredential::Claude {
                    origin: ProviderCredentialOrigin::ProductCredentialStore,
                    credential,
                })
            }
            ProductCredentialState::PresentInvalid => {
                Err(ProviderCredentialResolutionError::ProductReconnectRequired)
            }
            ProductCredentialState::Absent => Ok(match self.experimental_claude_credential()? {
                Some(credential) => ResolvedProviderCredential::Claude {
                    origin: ProviderCredentialOrigin::ExperimentalLocalCli,
                    credential,
                },
                None => ResolvedProviderCredential::Unconfigured(ProviderKind::Claude),
            }),
        }
    }

    /// The minimized Claude request config. Local client account/device metadata is not
    /// imported: #627 supplies credentials only and leaves all default-client harness
    /// state outside iSyncYou.
    fn subscription_config(&self) -> isyncyou_agent::SubscriptionConfig {
        isyncyou_agent::SubscriptionConfig::default()
    }

    /// Build the Claude provider from one origin-bound credential bundle.
    #[cfg(test)]
    fn try_subscription_provider(
        &self,
        system: &str,
        model: &str,
    ) -> Result<
        Option<Box<dyn isyncyou_agent::LlmProvider + Send>>,
        ProviderCredentialResolutionError,
    > {
        let credential = match self.resolve_claude_credential()? {
            ResolvedProviderCredential::Claude { origin, credential } => {
                let _credential_origin = origin;
                credential
            }
            ResolvedProviderCredential::Unconfigured(ProviderKind::Claude) => return Ok(None),
            _ => return Err(ProviderCredentialResolutionError::ProviderUnavailable),
        };
        let p = isyncyou_agent::SubscriptionProvider::new(
            credential.access_token,
            model,
            system,
            self.subscription_config(),
        )
        .map_err(|_| ProviderCredentialResolutionError::ProviderUnavailable)?;
        Ok(Some(Box::new(p)))
    }

    fn codex_product_bundle_state(
        &self,
    ) -> ProductCredentialState<(CodexStoredCredential, ProductBundleMeta)> {
        match load_agent_credential_blob(&self.oauth_dir, CODEX_CREDENTIAL_ID) {
            Ok(None) => ProductCredentialState::Absent,
            Ok(Some(secret)) => {
                match ProductBundleMeta::from_blob(secret.expose(), ProductProviderId::Codex) {
                    Some(meta)
                        if meta.lifecycle == CredentialLifecycle::Active
                            && meta.policy_fingerprint
                                == oauth_policy_fingerprint(ProductProviderId::Codex) =>
                    {
                        match CodexStoredCredential::from_json(secret.expose()).map(|credential| {
                            classify_codex_product_credential_at(
                                credential,
                                (self.credential_now_ms)(),
                            )
                        }) {
                            Some(ProductCredentialState::PresentValid(credential)) => {
                                ProductCredentialState::PresentValid((credential, meta))
                            }
                            Some(ProductCredentialState::PresentNeedsRefresh(credential)) => {
                                ProductCredentialState::PresentNeedsRefresh((credential, meta))
                            }
                            _ => ProductCredentialState::PresentInvalid,
                        }
                    }
                    _ => ProductCredentialState::PresentInvalid,
                }
            }
            Err(_) => ProductCredentialState::PresentInvalid,
        }
    }

    fn codex_product_credential_state(&self) -> ProductCredentialState<CodexStoredCredential> {
        match self.codex_product_bundle_state() {
            ProductCredentialState::Absent => ProductCredentialState::Absent,
            ProductCredentialState::PresentValid((credential, _)) => {
                ProductCredentialState::PresentValid(credential)
            }
            ProductCredentialState::PresentNeedsRefresh((credential, _)) => {
                ProductCredentialState::PresentNeedsRefresh(credential)
            }
            ProductCredentialState::PresentInvalid => ProductCredentialState::PresentInvalid,
        }
    }

    fn codex_bundle_matches(
        &self,
        expected_credential: &CodexStoredCredential,
        expected_meta: &ProductBundleMeta,
    ) -> bool {
        let Ok(Some(secret)) = load_agent_credential_blob(&self.oauth_dir, CODEX_CREDENTIAL_ID)
        else {
            return false;
        };
        CodexStoredCredential::from_json(secret.expose()).as_ref() == Some(expected_credential)
            && ProductBundleMeta::from_blob(secret.expose(), ProductProviderId::Codex).as_ref()
                == Some(expected_meta)
    }

    fn publish_codex_refresh_outcome(
        &self,
        original_credential: &CodexStoredCredential,
        original_meta: &ProductBundleMeta,
        fence: &ProductRefreshFence,
        outcome: Result<CodexStoredCredential, ProviderCredentialResolutionError>,
        failure_code: &'static str,
    ) -> Result<CodexStoredCredential, ProviderCredentialResolutionError> {
        let _runtime = self
            .product_runtime_gate
            .lock()
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        let _refresh = self
            .credential_refresh_gate
            .lock()
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)
            .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
        if !self.product_refresh_fence_matches(ProductProviderId::Codex, fence)
            || !self.codex_bundle_matches(original_credential, original_meta)
        {
            return Err(ProviderCredentialResolutionError::ProductReconnectRequired);
        }
        match outcome {
            Ok(refreshed_credential) => {
                store_codex_bundle(&self.oauth_dir, &refreshed_credential, original_meta)
                    .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
                Ok(refreshed_credential)
            }
            Err(error) => {
                let mut reconnect_meta = original_meta.clone();
                reconnect_meta.lifecycle = CredentialLifecycle::ReconnectRequired {
                    closed_code: failure_code.into(),
                };
                store_codex_bundle(&self.oauth_dir, original_credential, &reconnect_meta)
                    .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
                Err(error)
            }
        }
    }

    fn refresh_codex_product_credential_with_fence(
        &self,
        credential: CodexStoredCredential,
        meta: ProductBundleMeta,
        fence: ProductRefreshFence,
    ) -> Result<CodexStoredCredential, ProviderCredentialResolutionError> {
        let official_policy = oauth_policy_fingerprint(ProductProviderId::Codex);
        let (outcome, failure_code) = if meta.provider != ProductProviderId::Codex
            || meta.lifecycle != CredentialLifecycle::Active
            || meta.policy_fingerprint != official_policy
        {
            (
                Err(ProviderCredentialResolutionError::ProductReconnectRequired),
                "oauth_policy_changed",
            )
        } else if credential.refresh_token.trim().is_empty() {
            (
                Err(ProviderCredentialResolutionError::ProductReconnectRequired),
                "refresh_failed",
            )
        } else {
            let config = isyncyou_agent::oauth::CodexOAuthConfig::default();
            let outcome = isyncyou_agent::http::HttpTransport::shared()
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)
                .and_then(|http| {
                    isyncyou_agent::oauth::codex_refresh(&http, &config, &credential.refresh_token)
                        .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)
                })
                .and_then(|refreshed| {
                    complete_codex_refresh(
                        credential.clone(),
                        refreshed,
                        (self.credential_now_ms)(),
                    )
                });
            (outcome, "refresh_failed")
        };
        self.publish_codex_refresh_outcome(&credential, &meta, &fence, outcome, failure_code)
    }

    #[cfg(test)]
    fn refresh_codex_product_credential_unlocked(
        &self,
        credential: CodexStoredCredential,
        meta: ProductBundleMeta,
    ) -> Result<CodexStoredCredential, ProviderCredentialResolutionError> {
        let fence = {
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
            let _refresh = self
                .credential_refresh_gate
                .lock()
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)
                .map_err(|_| ProviderCredentialResolutionError::ProductReconnectRequired)?;
            self.capture_bound_product_refresh_fence(ProductProviderId::Codex)?
        };
        self.refresh_codex_product_credential_with_fence(credential, meta, fence)
    }

    #[cfg(any(test, feature = "agent-subscription-experimental"))]
    fn experimental_codex_credential(
        &self,
    ) -> Result<Option<CodexStoredCredential>, ProviderCredentialResolutionError> {
        #[cfg(feature = "agent-subscription-experimental")]
        {
            match local_cli_fallback::load_codex_from_process() {
                Ok(credential) => Ok(Some(CodexStoredCredential {
                    access_token: credential.access_token,
                    refresh_token: String::new(),
                    account_id: credential.account_id,
                    expires_at_ms: 0,
                })),
                Err(error) if error.is_absent() => Ok(None),
                Err(error) if error.is_unsupported_platform() => {
                    Err(ProviderCredentialResolutionError::ExperimentalUnsupportedPlatform)
                }
                Err(_) => Err(ProviderCredentialResolutionError::ExperimentalCredentialRejected),
            }
        }
        #[cfg(not(feature = "agent-subscription-experimental"))]
        {
            Ok(None)
        }
    }

    #[cfg(test)]
    fn resolve_codex_credential(
        &self,
    ) -> Result<ResolvedProviderCredential, ProviderCredentialResolutionError> {
        match self.codex_product_bundle_state() {
            ProductCredentialState::PresentValid((credential, _meta)) => {
                Ok(ResolvedProviderCredential::Codex {
                    origin: ProviderCredentialOrigin::ProductCredentialStore,
                    credential,
                })
            }
            ProductCredentialState::PresentNeedsRefresh((credential, meta)) => {
                let credential =
                    self.refresh_codex_product_credential_unlocked(credential, meta)?;
                Ok(ResolvedProviderCredential::Codex {
                    origin: ProviderCredentialOrigin::ProductCredentialStore,
                    credential,
                })
            }
            ProductCredentialState::PresentInvalid => {
                Err(ProviderCredentialResolutionError::ProductReconnectRequired)
            }
            ProductCredentialState::Absent => Ok(match self.experimental_codex_credential()? {
                Some(credential) => ResolvedProviderCredential::Codex {
                    origin: ProviderCredentialOrigin::ExperimentalLocalCli,
                    credential,
                },
                None => ResolvedProviderCredential::Unconfigured(ProviderKind::Codex),
            }),
        }
    }

    /// Side-effect-free product status. Local CLI fallback is intentionally absent here: it is
    /// not product readiness, and this method must never perform a network refresh.
    fn product_credential_status(&self, provider: &str) -> Result<&'static str, String> {
        match ProductProviderId::parse(provider) {
            Some(ProductProviderId::Claude) => Ok(product_credential_state_wire(
                &self.claude_product_credential_state(),
            )),
            Some(ProductProviderId::Codex) => {
                #[cfg(feature = "agent-network-device-test-hooks")]
                if codex_refresh_for_device_test_is_armed()
                    && !matches!(
                        self.codex_product_credential_state(),
                        ProductCredentialState::Absent | ProductCredentialState::PresentInvalid
                    )
                {
                    return Ok("refresh_required");
                }
                Ok(product_credential_state_wire(
                    &self.codex_product_credential_state(),
                ))
            }
            None => Err("unknown provider".into()),
        }
    }

    /// The only explicit product refresh entry point. A refresh never reads the experimental
    /// local CLI source, and the encrypted store is updated only by the existing atomic writer
    /// after a complete finite credential response has been validated.
    fn refresh_product_credential(&self, provider: &str) -> Result<&'static str, String> {
        enum RefreshPlan {
            Connected,
            Claude(StoredCredential, ProductBundleMeta, ProductRefreshFence),
            Codex(
                CodexStoredCredential,
                ProductBundleMeta,
                ProductRefreshFence,
            ),
        }

        let selected =
            ProductProviderId::parse(provider).ok_or_else(|| "reconnect_required".to_string())?;
        let operation_id =
            account_lifecycle::mint_operation_id().map_err(|_| "reconnect_required".to_string())?;
        let _lifecycle = self
            .provider_leases
            .acquire_exclusive(
                &self.oauth_dir,
                selected,
                operation_id,
                account_lifecycle::ProviderOperationKind::Refresh,
            )
            .map_err(|_| "provider_busy".to_string())?;
        // The provider lifecycle lease serializes this refresh against turns and account lifecycle
        // operations. Short locks are ordered runtime -> refresh -> file and protect snapshots only.
        let plan = {
            let _runtime = self
                .product_runtime_gate
                .lock()
                .map_err(|_| "reconnect_required".to_string())?;
            let _refresh = self
                .credential_refresh_gate
                .lock()
                .map_err(|_| "reconnect_required".to_string())?;
            let _snapshot = acquire_product_runtime_file_lock(&self.oauth_dir)
                .map_err(|_| "reconnect_required".to_string())?;
            let fence = self
                .capture_bound_product_refresh_fence(selected)
                .map_err(|_| "reconnect_required".to_string())?;
            match selected {
                ProductProviderId::Claude => match self.claude_product_bundle_state() {
                    ProductCredentialState::PresentValid(_) => RefreshPlan::Connected,
                    ProductCredentialState::PresentNeedsRefresh((credential, meta)) => {
                        RefreshPlan::Claude(credential, meta, fence)
                    }
                    ProductCredentialState::Absent | ProductCredentialState::PresentInvalid => {
                        return Err("reconnect_required".into());
                    }
                },
                ProductProviderId::Codex => {
                    #[cfg(feature = "agent-network-device-test-hooks")]
                    let force_refresh = take_codex_refresh_for_device_test();
                    #[cfg(not(feature = "agent-network-device-test-hooks"))]
                    let force_refresh = false;
                    match self.codex_product_bundle_state() {
                        ProductCredentialState::PresentValid((credential, meta))
                            if force_refresh =>
                        {
                            RefreshPlan::Codex(credential, meta, fence)
                        }
                        ProductCredentialState::PresentValid(_) => RefreshPlan::Connected,
                        ProductCredentialState::PresentNeedsRefresh((credential, meta)) => {
                            RefreshPlan::Codex(credential, meta, fence)
                        }
                        ProductCredentialState::Absent | ProductCredentialState::PresentInvalid => {
                            return Err("reconnect_required".into());
                        }
                    }
                }
            }
        };
        match plan {
            RefreshPlan::Connected => Ok("connected"),
            RefreshPlan::Claude(credential, meta, fence) => self
                .refresh_claude_product_credential_with_fence(credential, meta, fence)
                .map(|_| "connected")
                .map_err(|_| "reconnect_required".into()),
            RefreshPlan::Codex(credential, meta, fence) => self
                .refresh_codex_product_credential_with_fence(credential, meta, fence)
                .map(|_| "connected")
                .map_err(|_| "reconnect_required".into()),
        }
    }

    /// Start the Codex/ChatGPT OAuth flow: bind OpenAI's fixed
    /// loopback port, spawn a one-shot callback server (exchanges + stores on success),
    /// and return the authorize URL for the system browser. The app polls
    /// `/api/v1/agent/status` for `codex:true`.
    fn codex_oauth_start(
        &self,
        operation_id: String,
    ) -> Result<isyncyou_webui::AgentOAuthStartResponse, String> {
        let cfg = isyncyou_agent::oauth::CodexOAuthConfig::default();
        let (verifier, challenge) = isyncyou_agent::oauth::pkce().map_err(|e| e.to_string())?;
        let state = isyncyou_agent::oauth::rand_state().map_err(|e| e.to_string())?;
        let url = isyncyou_agent::oauth::codex_build_authorize_url(&cfg, &challenge, &state);
        let attempt_id = mint_cap_token();
        let started_at_seconds = i64::try_from((self.credential_now_ms)() / 1_000)
            .map_err(|_| "oauth_start_failed".to_string())?;
        let cancelled = Arc::new(AtomicBool::new(false));
        // The registered callback port and active-attempt check are owned together so a
        // second UI start cannot create a competing listener.
        let listener = {
            let mut attempts = self
                .oauth_attempts
                .lock()
                .map_err(|_| "oauth_start_failed".to_string())?;
            let expired = reap_oauth_attempts(&mut attempts, &self.oauth_dir);
            if let Ok(mut bindings) = self.oauth_lifecycle_bindings.lock() {
                for attempt_id in expired {
                    bindings.remove(&attempt_id);
                }
            }
            if attempts
                .values()
                .any(|attempt| matches!(attempt, OAuthAttempt::Codex { .. }))
            {
                return Err("ChatGPT sign-in is already in progress".into());
            }
            let listener = std::net::TcpListener::bind(("127.0.0.1", 1455))
                .map_err(|_| "could not open the ChatGPT sign-in port".to_string())?;
            attempts.insert(
                attempt_id.clone(),
                OAuthAttempt::Codex {
                    cancelled: Arc::clone(&cancelled),
                    expires_at: std::time::Instant::now() + OAUTH_ATTEMPT_TTL,
                },
            );
            listener
        };
        // #639 T8: record the official sign-in start into the attempt-keyed journal.
        record_onboarding_attempt_transition(
            &self.oauth_dir,
            ProductProviderId::Codex,
            &attempt_id,
            ProductOnboardingState::OfficialSignInStarted,
            None,
        );
        let oauth_dir = self.oauth_dir.clone();
        let attempts = Arc::clone(&self.oauth_attempts);
        let lifecycle_bindings = Arc::clone(&self.oauth_lifecycle_bindings);
        let callback_attempt_id = attempt_id.clone();
        let callback_operation_id = operation_id.clone();
        let candidate_runtime = CodexCandidateRuntime {
            cfg: self.cfg.clone(),
            oauth_dir: self.oauth_dir.clone(),
            provider_leases: Arc::clone(&self.provider_leases),
            product_runtime_gate: Arc::clone(&self.product_runtime_gate),
            now_ms: Arc::clone(&self.credential_now_ms),
        };
        std::thread::spawn(move || {
            codex_callback_serve(
                listener,
                CodexCallbackContext {
                    oauth_dir,
                    cfg,
                    verifier,
                    want_state: state,
                    attempt_id: callback_attempt_id,
                    cancelled,
                    attempts,
                    lifecycle_bindings,
                    operation_id: callback_operation_id,
                    started_at_seconds,
                    candidate_runtime,
                },
            )
        });
        Ok(isyncyou_webui::AgentOAuthStartResponse {
            authorize_url: url,
            attempt_id,
            lifecycle_operation_id: Some(operation_id),
        })
    }

    /// Build the Codex (ChatGPT) provider if credentials are available.
    #[cfg(test)]
    fn try_codex_provider(
        &self,
        instructions: &str,
        model: &str,
        reasoning_effort: isyncyou_agent::CodexReasoningEffort,
    ) -> Result<
        Option<Box<dyn isyncyou_agent::LlmProvider + Send>>,
        ProviderCredentialResolutionError,
    > {
        let credential = match self.resolve_codex_credential()? {
            ResolvedProviderCredential::Codex { origin, credential } => {
                let _credential_origin = origin;
                credential
            }
            ResolvedProviderCredential::Unconfigured(ProviderKind::Codex) => return Ok(None),
            _ => return Err(ProviderCredentialResolutionError::ProviderUnavailable),
        };
        let cfg = isyncyou_agent::CodexConfig {
            account_id: credential.account_id,
            model: model.to_string(),
            reasoning_effort,
            ..Default::default()
        };
        let provider =
            isyncyou_agent::CodexProvider::new(credential.access_token, instructions, cfg)
                .map_err(|_| ProviderCredentialResolutionError::ProviderUnavailable)?;
        Ok(Some(Box::new(provider)))
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn account_lifecycle_projection(
    agent: &DaemonAgent,
    provider: ProductProviderId,
    credential_state: &str,
    ready: bool,
) -> serde_json::Value {
    let repository = match account_lifecycle_repository(&agent.oauth_dir) {
        Ok(repository) => repository,
        Err(_) => {
            return serde_json::json!({
                "state": "unavailable", "mode": null, "busy": false,
                "retryable": true, "code": "account_lifecycle_unavailable",
                "switch_capability": "unavailable", "revoke_scope_guarantee": "observed_token_session",
                "ack_required": false, "credential_etag": null, "resume_operation_id": null,
                "operation_etag": null,
            });
        }
    };
    let credential = agent.lifecycle_credential(provider).ok().flatten();
    let switch_capability = credential
        .as_ref()
        .map(|(_, meta)| match meta.switch_capability() {
            account_identity::SwitchCapability::VerifiedSubject => "verified_subject",
            account_identity::SwitchCapability::Unavailable => "unavailable",
        })
        .unwrap_or("unavailable");
    let credential_etag = credential.as_ref().and_then(|(_, meta)| {
        repository
            .projected_credential_etag(provider, &meta.generation)
            .ok()
    });
    let active = repository.active_operation(provider).ok().flatten();
    let journal = active.as_ref().and_then(|active| {
        repository
            .load_journal(&active.journal_record_id)
            .ok()
            .flatten()
    });
    let mode = active.as_ref().map(|active| match active.prepared.mode {
        account_lifecycle::AccountLifecycleMode::Connect => "connect",
        account_lifecycle::AccountLifecycleMode::Disconnect => "disconnect",
        account_lifecycle::AccountLifecycleMode::Reconnect => "reconnect",
        account_lifecycle::AccountLifecycleMode::Switch => "switch",
    });
    let (state, code, retryable) = match journal.as_ref().map(|journal| journal.phase) {
        Some(account_lifecycle::AccountLifecyclePhase::RevokeOutcomeUnknown) => {
            ("revoke_unknown", "retry_revoke", true)
        }
        Some(account_lifecycle::AccountLifecyclePhase::RevokedPendingCleanup) => {
            ("cleanup_pending", "resume_cleanup", true)
        }
        Some(account_lifecycle::AccountLifecyclePhase::AwaitingOAuthLogin) => {
            ("awaiting_oauth_login", "oauth_required", false)
        }
        Some(account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown) => {
            ("exchange_outcome_unknown", "retry_exchange", true)
        }
        Some(account_lifecycle::AccountLifecyclePhase::OAuthCandidateCleanup) => {
            ("candidate_cleanup", "retry_revoke", true)
        }
        Some(_) => ("busy", "operation_in_progress", false),
        None if ready => ("connected", "ok", false),
        None if credential.is_some() || credential_state == "reconnect_required" => {
            ("reconnect_required", "reconnect_required", false)
        }
        None => ("disconnected", "disconnected", false),
    };
    serde_json::json!({
        "state": state,
        "mode": mode,
        "busy": active.is_some() || agent.provider_leases.counts(provider).shared > 0,
        "retryable": retryable,
        "code": code,
        "switch_capability": switch_capability,
        "revoke_scope_guarantee": "observed_token_session",
        "ack_required": false,
        "credential_etag": if active.is_none() { credential_etag } else { None },
        "resume_operation_id": active.as_ref().map(|active| active.prepared.operation_id.clone()),
        "operation_etag": active.as_ref().map(|active| active.operation_etag.clone()),
    })
}

impl DaemonAgent {
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn reserve_agent_turn(
        &self,
        turn_id: String,
        provider: Option<ProductProviderId>,
        admission: TurnAdmissionLease,
        durable_admission: DurableTurnAdmissionLease,
    ) -> Result<ReservedAgentTurn, String> {
        let sequence = self.seq.fetch_add(1, Ordering::SeqCst);
        let rx_events = self.hub.open(&turn_id, 256);
        let turn_state = match self.turns.register(&turn_id) {
            Ok(state) => state,
            Err(error) => {
                self.hub.close(&turn_id);
                return Err(error);
            }
        };
        let cancellation = match self.hub.cancellation_token(&turn_id) {
            Some(cancellation) => cancellation,
            None => {
                self.turns.remove(&turn_id);
                self.hub.close(&turn_id);
                return Err("turn_registry_unavailable".into());
            }
        };
        let (tx_str, rx_str) = std::sync::mpsc::channel::<String>();
        let now_ms = unix_now_ms();
        let mut streams = match self.streams.lock() {
            Ok(streams) => streams,
            Err(_) => {
                self.turns.remove(&turn_id);
                self.hub.close(&turn_id);
                return Err("turn_registry_unavailable".into());
            }
        };
        Self::sweep_unopened_streams_locked(&mut streams, now_ms);
        streams.insert(
            turn_id.clone(),
            AgentStreamSlot {
                rx: rx_str,
                created_at_ms: now_ms,
                provider,
            },
        );
        drop(streams);
        std::thread::spawn(move || {
            while let Ok(event) = rx_events.recv() {
                if tx_str.send(agent_event_json(&event)).is_err() {
                    break;
                }
            }
        });
        Ok(ReservedAgentTurn {
            turn_id,
            sequence,
            turn_state,
            cancellation,
            admission: Some(admission),
            durable_admission,
        })
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn launch_prepared_turn(
        &self,
        account: &str,
        prompt: &str,
        prepared: PreparedTurnProvider,
        product_turn: Option<product_session::ProductTurnRuntime>,
        reserved: ReservedAgentTurn,
    ) -> Result<String, String> {
        let mut provider = prepared.provider;
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let provider_id = prepared.provider_id;
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let operation_lease = prepared.operation_lease;
        let ReservedAgentTurn {
            turn_id,
            sequence: n,
            turn_state,
            cancellation,
            mut admission,
            durable_admission,
        } = reserved;
        let hub = self.hub.clone();
        let tid = turn_id.clone();
        let prompt = prompt.to_owned();
        let account_id = account.to_owned();
        let archive_root = self.archive_root_for(&account_id);
        let pending = self.pending.clone();
        let turns = Arc::clone(&self.turns);
        let hot_request_statuses = Arc::clone(&self.hot_request_statuses);
        let hot_session_history = Arc::clone(&self.hot_session_history);
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let last_usage = Arc::clone(&self.last_usage);
        let hot_request_binding = product_turn
            .as_ref()
            .map(product_session::ProductTurnRuntime::request_status_binding);
        let history_session_id = hot_request_binding
            .as_ref()
            .map(|(session_id, _)| session_id.clone());
        if let Some(session_id) = history_session_id.as_deref() {
            hot_session_history.invalidate(session_id);
        }
        let product_turn = Arc::new(Mutex::new(product_turn));
        let thread_product_turn = Arc::clone(&product_turn);
        let turn_thread = std::thread::Builder::new()
            .name(format!("agent-turn-{n}"))
            .spawn(move || {
                let mut durable_admission = durable_admission;
                let mut terminal_persisted = false;
                #[cfg(any(
                    feature = "agent-oauth-providers",
                    feature = "agent-subscription-experimental"
                ))]
                let _operation_lease = operation_lease;
                let exec = make_executor(&account_id, archive_root);
                let mut product_turn = thread_product_turn
                    .lock()
                    .unwrap_or_else(|poisoned| poisoned.into_inner())
                    .take();
                let history = if let Some(runtime) = product_turn.as_mut() {
                    runtime.provider_history(&prompt, exec.as_ref())
                } else {
                    Ok(vec![isyncyou_agent::Message::user(prompt)])
                };
                let outcome = history.and_then(|mut history| {
                    let _ = hub.emit(
                        &tid,
                        isyncyou_agent::StreamEvent::Progress {
                            phase: isyncyou_agent::ProgressPhase::ProviderStarted,
                        },
                    );
                    if let Some(observer) = product_turn.as_mut() {
                        isyncyou_agent::run_turn_cancellable(
                            provider.as_mut(),
                            exec.as_ref(),
                            &mut history,
                            &mut |event| {
                                hub.emit(&tid, event);
                            },
                            observer,
                            Some(&cancellation),
                        )
                    } else {
                        let mut observer = NoopProductTurnObserver;
                        isyncyou_agent::run_turn_cancellable(
                            provider.as_mut(),
                            exec.as_ref(),
                            &mut history,
                            &mut |event| {
                                hub.emit(&tid, event);
                            },
                            &mut observer,
                            Some(&cancellation),
                        )
                    }
                });
                let usage = provider.last_usage();
                let outcome = if matches!(
                    &outcome,
                    Ok(isyncyou_agent::TurnOutcome::PendingConfirmation { .. })
                ) {
                    outcome
                } else {
                    match TurnRegistry::begin_terminal(&turn_state, &cancellation) {
                        Ok(TerminalTransition::Proceed) => outcome,
                        Ok(TerminalTransition::Cancelled) => {
                            Err(isyncyou_agent::AgentError::Cancelled)
                        }
                        Err(_) => Err(isyncyou_agent::AgentError::Provider(
                            "turn_registry_unavailable".into(),
                        )),
                    }
                };
                match outcome {
                    Ok(isyncyou_agent::TurnOutcome::Final { text }) => {
                        let persisted = product_turn.map_or(Ok(()), |runtime| {
                            cache_product_session_context(
                                &hot_session_history,
                                runtime.finish_final(
                                    text,
                                    usage.clone().map(|usage| isyncyou_agent::SanitizedUsage {
                                        input_tokens: usage.input_tokens,
                                        output_tokens: usage.output_tokens,
                                    }),
                                    unix_now_ms(),
                                ),
                            )
                        });
                        #[cfg(any(
                            feature = "agent-oauth-providers",
                            feature = "agent-subscription-experimental"
                        ))]
                        if persisted.is_ok() {
                            if let (Some(provider_id), Some(usage)) = (provider_id, usage.clone()) {
                                if let Ok(mut last_usage) = last_usage.lock() {
                                    last_usage.insert(provider_id, usage);
                                }
                            }
                        }
                        terminal_persisted = persisted.is_ok();
                        cache_persisted_request_phase(
                            &hot_request_statuses,
                            hot_request_binding.as_ref(),
                            &persisted,
                            isyncyou_agent::RequestPhase::Committed,
                            None,
                        );
                        if terminal_persisted {
                            let _ = durable_admission.complete();
                            drop(admission.take());
                        }
                        for event in terminal_events_after_persistence(
                            persisted,
                            isyncyou_agent::DoneReason::Complete,
                        ) {
                            let _ = hub.emit(&tid, event);
                        }
                    }
                    Ok(isyncyou_agent::TurnOutcome::PendingConfirmation { action, .. }) => {
                        let action = *action;
                        let preview = match agent_ops::preview_for_pending_action(&action) {
                            Ok(preview) => preview,
                            Err(_) => {
                                let cancelled = matches!(
                                    TurnRegistry::begin_terminal(&turn_state, &cancellation),
                                    Ok(TerminalTransition::Cancelled)
                                );
                                let (terminal_status, error_code, phase, done_reason) = if cancelled
                                {
                                    (
                                        isyncyou_agent::TurnTerminalStatus::Cancelled,
                                        None,
                                        isyncyou_agent::RequestPhase::Cancelled,
                                        isyncyou_agent::DoneReason::Cancelled,
                                    )
                                } else {
                                    (
                                        isyncyou_agent::TurnTerminalStatus::Error,
                                        Some("confirmation_unavailable".into()),
                                        isyncyou_agent::RequestPhase::Failed,
                                        isyncyou_agent::DoneReason::Error,
                                    )
                                };
                                let persisted = persist_product_runtime_if_expected(
                                    product_turn.take(),
                                    hot_request_binding.is_some(),
                                    |runtime| {
                                        cache_product_session_context(
                                            &hot_session_history,
                                            runtime.finish_terminal(
                                                terminal_status,
                                                error_code.clone(),
                                                phase,
                                                unix_now_ms(),
                                            ),
                                        )
                                    },
                                );
                                let persisted_ok = persisted.is_ok();
                                cache_persisted_request_phase(
                                    &hot_request_statuses,
                                    hot_request_binding.as_ref(),
                                    &persisted,
                                    phase,
                                    error_code.as_deref(),
                                );
                                if persisted_ok {
                                    let _ = durable_admission.complete();
                                    drop(admission.take());
                                }
                                let events = if cancelled {
                                    terminal_events_after_persistence(persisted, done_reason)
                                } else {
                                    terminal_error_events_after_persistence(
                                        persisted,
                                        "confirmation_unavailable",
                                    )
                                };
                                for event in events {
                                    let _ = if cancelled {
                                        hub.emit_terminal(&tid, event)
                                    } else {
                                        hub.emit(&tid, event)
                                    };
                                }
                                hub.close(&tid);
                                turns.remove(&tid);
                                if let Some(session_id) = history_session_id.as_deref() {
                                    hot_session_history.invalidate(session_id);
                                }
                                return;
                            }
                        };
                        let owner = product_turn
                            .as_ref()
                            .map(|runtime| runtime.pending_owner(&account_id))
                            .unwrap_or_else(|| isyncyou_agent::PendingOwnerBinding {
                                account: account_id.clone(),
                                session_id: "legacy-local".into(),
                                request_id: format!("legacy-{tid}"),
                                turn_id: tid.clone(),
                            });
                        let transition = TurnRegistry::begin_pending(&turn_state, || {
                            let (pending_action, token) = pending
                                .register_bound(
                                    action,
                                    preview.text,
                                    unix_now_ms(),
                                    AGENT_CONFIRM_TTL_MS,
                                    owner,
                                )
                                .map_err(|_| "confirmation_unavailable".to_string())?;
                            let persisted = product_turn.take().map_or(Ok(()), |runtime| {
                                cache_product_session_context(
                                    &hot_session_history,
                                    runtime.finish_pending(unix_now_ms()),
                                )
                            });
                            if let Err(error) = persisted {
                                let _ = pending.cancel(
                                    &pending_action.id,
                                    &pending_action.action_hash,
                                    unix_now_ms(),
                                );
                                return Err(error);
                            }
                            terminal_persisted = true;
                            cache_persisted_request_phase(
                                &hot_request_statuses,
                                hot_request_binding.as_ref(),
                                &Ok(()),
                                isyncyou_agent::RequestPhase::PendingConfirmation,
                                None,
                            );
                            Ok((pending_action.id.clone(), (pending_action, token)))
                        });
                        match transition {
                            Ok(PendingTransition::Committed((pending_action, token))) => {
                                let _ = durable_admission.complete();
                                drop(admission.take());
                                #[cfg(any(
                                    feature = "agent-oauth-providers",
                                    feature = "agent-subscription-experimental"
                                ))]
                                if let (Some(provider_id), Some(usage)) =
                                    (provider_id, usage.clone())
                                {
                                    if let Ok(mut last_usage) = last_usage.lock() {
                                        last_usage.insert(provider_id, usage);
                                    }
                                }
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::ConfirmationRequired {
                                        id: pending_action.id,
                                        action: Box::new(pending_action.action),
                                        preview: pending_action.preview,
                                        action_hash: pending_action.action_hash,
                                        risk: pending_action.risk,
                                        expires_at_ms: pending_action.expires_at_ms,
                                        token,
                                    },
                                );
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::done(
                                        isyncyou_agent::DoneReason::PendingConfirmation,
                                    ),
                                );
                            }
                            Ok(PendingTransition::Cancelled) => {
                                let persisted = product_turn.take().map_or(Ok(()), |runtime| {
                                    cache_product_session_context(
                                        &hot_session_history,
                                        runtime.finish_terminal(
                                            isyncyou_agent::TurnTerminalStatus::Cancelled,
                                            None,
                                            isyncyou_agent::RequestPhase::Cancelled,
                                            unix_now_ms(),
                                        ),
                                    )
                                });
                                terminal_persisted = persisted.is_ok();
                                cache_persisted_request_phase(
                                    &hot_request_statuses,
                                    hot_request_binding.as_ref(),
                                    &persisted,
                                    isyncyou_agent::RequestPhase::Cancelled,
                                    None,
                                );
                                if terminal_persisted {
                                    let _ = durable_admission.complete();
                                    drop(admission.take());
                                }
                                for event in terminal_events_after_persistence(
                                    persisted,
                                    isyncyou_agent::DoneReason::Cancelled,
                                ) {
                                    let _ = hub.emit_terminal(&tid, event);
                                }
                            }
                            Err(error) => {
                                let cancelled = matches!(
                                    TurnRegistry::begin_terminal(&turn_state, &cancellation),
                                    Ok(TerminalTransition::Cancelled)
                                );
                                let safe_code = pending_setup_error_code(&error);
                                let (terminal_status, error_code, phase, done_reason) = if cancelled
                                {
                                    (
                                        isyncyou_agent::TurnTerminalStatus::Cancelled,
                                        None,
                                        isyncyou_agent::RequestPhase::Cancelled,
                                        isyncyou_agent::DoneReason::Cancelled,
                                    )
                                } else {
                                    (
                                        isyncyou_agent::TurnTerminalStatus::Error,
                                        Some(safe_code.into()),
                                        isyncyou_agent::RequestPhase::Failed,
                                        isyncyou_agent::DoneReason::Error,
                                    )
                                };
                                let persisted = persist_product_runtime_if_expected(
                                    product_turn.take(),
                                    hot_request_binding.is_some(),
                                    |runtime| {
                                        cache_product_session_context(
                                            &hot_session_history,
                                            runtime.finish_terminal(
                                                terminal_status,
                                                error_code.clone(),
                                                phase,
                                                unix_now_ms(),
                                            ),
                                        )
                                    },
                                );
                                terminal_persisted = persisted.is_ok();
                                cache_persisted_request_phase(
                                    &hot_request_statuses,
                                    hot_request_binding.as_ref(),
                                    &persisted,
                                    phase,
                                    error_code.as_deref(),
                                );
                                if terminal_persisted {
                                    let _ = durable_admission.complete();
                                    drop(admission.take());
                                }
                                let events = if cancelled {
                                    terminal_events_after_persistence(persisted, done_reason)
                                } else {
                                    terminal_error_events_after_persistence(persisted, safe_code)
                                };
                                for event in events {
                                    let _ = if cancelled {
                                        hub.emit_terminal(&tid, event)
                                    } else {
                                        hub.emit(&tid, event)
                                    };
                                }
                            }
                        }
                    }
                    Err(isyncyou_agent::AgentError::Cancelled) => {
                        let persisted = product_turn.map_or(Ok(()), |runtime| {
                            cache_product_session_context(
                                &hot_session_history,
                                runtime.finish_terminal(
                                    isyncyou_agent::TurnTerminalStatus::Cancelled,
                                    None,
                                    isyncyou_agent::RequestPhase::Cancelled,
                                    unix_now_ms(),
                                ),
                            )
                        });
                        terminal_persisted = persisted.is_ok();
                        cache_persisted_request_phase(
                            &hot_request_statuses,
                            hot_request_binding.as_ref(),
                            &persisted,
                            isyncyou_agent::RequestPhase::Cancelled,
                            None,
                        );
                        if terminal_persisted {
                            let _ = durable_admission.complete();
                            drop(admission.take());
                        }
                        if persisted.is_ok() {
                            let _ = hub.emit_terminal(
                                &tid,
                                isyncyou_agent::StreamEvent::done(
                                    isyncyou_agent::DoneReason::Cancelled,
                                ),
                            );
                        } else {
                            let _ = hub.emit_terminal(
                                &tid,
                                isyncyou_agent::StreamEvent::Error("lease_lost".into()),
                            );
                            let _ = hub.emit_terminal(
                                &tid,
                                isyncyou_agent::StreamEvent::done(
                                    isyncyou_agent::DoneReason::Error,
                                ),
                            );
                        }
                    }
                    Err(error) => {
                        let provider_outcome_ambiguous = provider_outcome_is_ambiguous(
                            &error,
                            product_turn.as_ref().is_some_and(
                                product_session::ProductTurnRuntime::provider_outcome_is_ambiguous,
                            ),
                        );
                        let diagnostic_code = agent_safe_turn_error(&error).to_owned();
                        let safe_error =
                            product_turn_terminal_error(&error, provider_outcome_ambiguous);
                        let (terminal_status, phase) = if safe_error == "turn_outcome_unknown" {
                            (
                                isyncyou_agent::TurnTerminalStatus::OutcomeUnknown,
                                isyncyou_agent::RequestPhase::OutcomeUnknown,
                            )
                        } else {
                            (
                                isyncyou_agent::TurnTerminalStatus::Error,
                                isyncyou_agent::RequestPhase::Failed,
                            )
                        };
                        let terminal_code = if provider_outcome_ambiguous {
                            diagnostic_code.clone()
                        } else {
                            safe_error.clone()
                        };
                        let mut persisted = product_turn.map_or(Ok(()), |runtime| {
                            cache_product_session_context(
                                &hot_session_history,
                                runtime.finish_terminal(
                                    terminal_status,
                                    Some(terminal_code.clone()),
                                    phase,
                                    unix_now_ms(),
                                ),
                            )
                        });
                        if persisted.is_ok() {
                            if provider_outcome_ambiguous {
                                if let Err(error) =
                                    durable_admission.outcome_unknown(&tid, &diagnostic_code)
                                {
                                    persisted = Err(error);
                                }
                            } else {
                                let _ = durable_admission.complete();
                            }
                            drop(admission.take());
                        }
                        terminal_persisted = persisted.is_ok();
                        cache_persisted_request_phase(
                            &hot_request_statuses,
                            hot_request_binding.as_ref(),
                            &persisted,
                            phase,
                            Some(&terminal_code),
                        );
                        let code = if persisted.is_ok() {
                            safe_error
                        } else {
                            "lease_lost".into()
                        };
                        let _ = hub.emit(&tid, isyncyou_agent::StreamEvent::Error(code));
                        let _ = hub.emit(
                            &tid,
                            isyncyou_agent::StreamEvent::done(isyncyou_agent::DoneReason::Error),
                        );
                    }
                }
                if terminal_persisted {
                    let _ = durable_admission.complete();
                    drop(admission.take());
                }
                drop(admission.take());
                hub.close(&tid);
                if let Some(session_id) = history_session_id.as_deref() {
                    hot_session_history.invalidate(session_id);
                }
                turns.remove(&tid);
            });
        if turn_thread.is_err() {
            let product_turn = product_turn
                .lock()
                .unwrap_or_else(|poisoned| poisoned.into_inner())
                .take();
            let _ = product_turn.map_or(Ok(()), |runtime| {
                cache_product_session_context(
                    &self.hot_session_history,
                    runtime.finish_terminal(
                        isyncyou_agent::TurnTerminalStatus::Error,
                        Some("turn_spawn_failed".into()),
                        isyncyou_agent::RequestPhase::Failed,
                        unix_now_ms(),
                    ),
                )
            });
            self.streams.lock().unwrap().remove(&turn_id);
            self.hub.close(&turn_id);
            self.turns.remove(&turn_id);
            return Err("turn_spawn_failed".into());
        }
        Ok(turn_id)
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn emit_product_turn_replay(
        &self,
        reserved_turn_id: &str,
        replay: product_session::ProductTurnReplay,
        pending_owner: Option<&isyncyou_agent::PendingOwnerBinding>,
    ) {
        let mut events = Vec::new();
        match replay.phase {
            isyncyou_agent::RequestPhase::Committed => {
                if let Some(text) = replay.final_text {
                    events.push(isyncyou_agent::StreamEvent::Token(text));
                }
                events.push(isyncyou_agent::StreamEvent::done(
                    isyncyou_agent::DoneReason::Complete,
                ));
            }
            isyncyou_agent::RequestPhase::Cancelled => events.push(
                isyncyou_agent::StreamEvent::done(isyncyou_agent::DoneReason::Cancelled),
            ),
            isyncyou_agent::RequestPhase::ProviderStepStarted
            | isyncyou_agent::RequestPhase::OutcomeUnknown => {
                events.push(isyncyou_agent::StreamEvent::Error(
                    "turn_outcome_unknown".into(),
                ));
                events.push(isyncyou_agent::StreamEvent::done(
                    isyncyou_agent::DoneReason::Error,
                ));
            }
            isyncyou_agent::RequestPhase::Failed => {
                events.push(isyncyou_agent::StreamEvent::Error(
                    replay.error_code.unwrap_or_else(|| "turn_failed".into()),
                ));
                events.push(isyncyou_agent::StreamEvent::done(
                    isyncyou_agent::DoneReason::Error,
                ));
            }
            isyncyou_agent::RequestPhase::PendingConfirmation => {
                let pending = pending_owner
                    .ok_or(isyncyou_agent::ConfirmError::Unavailable)
                    .and_then(|owner| {
                        self.pending
                            .reissue_for_owner(owner, unix_now_ms())
                            .and_then(|value| value.ok_or(isyncyou_agent::ConfirmError::NotFound))
                    });
                match pending {
                    Ok((pending_action, token)) => {
                        events.push(isyncyou_agent::StreamEvent::ConfirmationRequired {
                            id: pending_action.id,
                            action: Box::new(pending_action.action),
                            preview: pending_action.preview,
                            action_hash: pending_action.action_hash,
                            risk: pending_action.risk,
                            expires_at_ms: pending_action.expires_at_ms,
                            token,
                        });
                        events.push(isyncyou_agent::StreamEvent::done(
                            isyncyou_agent::DoneReason::PendingConfirmation,
                        ));
                    }
                    Err(_) => {
                        events.push(isyncyou_agent::StreamEvent::Error(
                            "confirmation_unavailable".into(),
                        ));
                        events.push(isyncyou_agent::StreamEvent::done(
                            isyncyou_agent::DoneReason::Error,
                        ));
                    }
                }
            }
            isyncyou_agent::RequestPhase::Accepted
            | isyncyou_agent::RequestPhase::ProviderStepCompleted => {
                events.push(isyncyou_agent::StreamEvent::Error(
                    "request_resume_required".into(),
                ));
                events.push(isyncyou_agent::StreamEvent::done(
                    isyncyou_agent::DoneReason::Error,
                ));
            }
        }
        for event in events {
            let _ = self.hub.emit(reserved_turn_id, event);
        }
        self.hub.close(reserved_turn_id);
        self.turns.remove(reserved_turn_id);
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn fail_reserved_turn(&self, reserved_turn_id: &str, error: &str) {
        if error == "turn_cancelled" {
            let _ = self.hub.emit_terminal(
                reserved_turn_id,
                isyncyou_agent::StreamEvent::done(isyncyou_agent::DoneReason::Cancelled),
            );
        } else {
            let _ = self.hub.emit_terminal(
                reserved_turn_id,
                isyncyou_agent::StreamEvent::Error(agent_safe_turn_start_error(error).into()),
            );
            let _ = self.hub.emit_terminal(
                reserved_turn_id,
                isyncyou_agent::StreamEvent::done(isyncyou_agent::DoneReason::Error),
            );
        }
        self.hub.close(reserved_turn_id);
        self.turns.remove(reserved_turn_id);
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn recover_durable_turn_admissions(self: &Arc<Self>) -> Result<usize, String> {
        let Some(store) = self.control_store.as_ref() else {
            return Ok(0);
        };
        let admissions = store.recover_agent_turn_admissions(MAX_ACTIVE_TURN_ADMISSIONS)?;
        let mut started = 0usize;
        for admission in admissions {
            if turn_id_from_request_id(&admission.request.request_id)? != admission.turn_id {
                return Err("turn_admission_unavailable".into());
            }
            isyncyou_webui::AgentHandler::start_turn_request(
                Arc::clone(self),
                admission.request,
                admission.identity,
            )?;
            started = started.saturating_add(1);
        }
        Ok(started)
    }

    fn finish_pending_confirmation_state(
        &self,
        pending_id: &str,
        code: &str,
        completed_at_ms: u64,
    ) -> Result<(), String> {
        if !self.pending.is_persistent() {
            return Ok(());
        }
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "confirmation_outcome_unknown".to_string())?;
            store.finish_pending_confirmation(pending_id, code, completed_at_ms)?;
            reconcile_pending_confirm_projections(&self.cfg, &self.oauth_dir, store, 1);
            Ok(())
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (pending_id, code, completed_at_ms);
            Err("confirmation_outcome_unknown".into())
        }
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn load_product_session_history_page(
    cfg: &Config,
    oauth_dir: &Path,
    session_id: &str,
    cursor: Option<&str>,
    limit: usize,
) -> Result<isyncyou_agent::HistoryPageV1, String> {
    let store =
        agent_credential_store(oauth_dir).map_err(|_| "session_store_unavailable".to_string())?;
    let registry = product_session::ProductSessionRegistry::new(&store);
    let account = registry.account_for(session_id)?;
    if registry.remote_initialization_pending(session_id)? {
        return Ok(isyncyou_agent::HistoryPageV1 {
            manifest_generation: 0,
            records: Vec::new(),
            next_cursor: None,
        });
    }
    let token = isyncyou_engine::auth::resolve_cached_sync_token(cfg, &account)
        .map_err(|_| "session_writer_reconnect_required".to_string())?;
    registry
        .open(&token, session_id)?
        .history(session_id, cursor, Some(limit))
        .map_err(product_session::map_session_error)
}

impl isyncyou_webui::AgentHandler for DaemonAgent {
    fn session_create(
        &self,
        request_id: &str,
        display_name: Option<&str>,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let account = self.product_session_account()?;
            let store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let session = product_session::ProductSessionRegistry::new(&store).create(
                account,
                request_id,
                display_name,
                unix_now_ms(),
            )?;
            Ok(serde_json::json!({
                "session": session,
                "selected_session_id": session.session_id,
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (request_id, display_name);
            Err("product_sessions_unavailable".into())
        }
    }

    fn session_list(
        &self,
        cursor: Option<&str>,
        limit: Option<usize>,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let account = self.product_session_account()?;
            let store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let page = product_session::ProductSessionRegistry::new(&store)
                .list_page(account, cursor, limit)?;
            serde_json::to_value(page).map_err(|_| "session_store_unavailable".into())
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (cursor, limit);
            Err("product_sessions_unavailable".into())
        }
    }

    fn session_select(
        &self,
        request_id: &str,
        session_id: &str,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            if self
                .turn_recovery_error
                .lock()
                .map_err(|_| "turn_admission_unavailable".to_string())?
                .is_some()
            {
                return Err("turn_admission_unavailable".into());
            }
            let store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            product_session::ProductSessionRegistry::new(&store).select(request_id, session_id)?;
            Ok(serde_json::json!({ "selected_session_id": session_id }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (request_id, session_id);
            Err("product_sessions_unavailable".into())
        }
    }

    fn session_history(
        &self,
        session_id: &str,
        cursor: Option<&str>,
        limit: Option<usize>,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let limit = limit.unwrap_or(50);
            if limit == 0 || limit > 100 || cursor.is_some_and(|value| value.len() > 2_048) {
                return Err("invalid_cursor".into());
            }
            let key = (
                session_id.to_owned(),
                cursor.unwrap_or_default().to_owned(),
                limit,
            );
            match self.hot_session_history.lookup_or_start(&key) {
                HotSessionHistoryLookup::Ready(page) => Ok(serde_json::json!({
                    "records": page.records,
                    "next_cursor": page.next_cursor,
                    "refreshing": false,
                })),
                HotSessionHistoryLookup::Start(attempt) => {
                    let cache = Arc::clone(&self.hot_session_history);
                    let worker_key = key.clone();
                    let cfg = self.cfg.clone();
                    let oauth_dir = self.oauth_dir.clone();
                    let worker_session_id = session_id.to_owned();
                    let worker_cursor = cursor.map(str::to_owned);
                    let spawn = std::thread::Builder::new()
                        .name("agent-session-history".into())
                        .spawn(move || {
                            let result = std::panic::catch_unwind(|| {
                                load_product_session_history_page(
                                    &cfg,
                                    &oauth_dir,
                                    &worker_session_id,
                                    worker_cursor.as_deref(),
                                    limit,
                                )
                            })
                            .unwrap_or_else(|_| Err("session_transport_unavailable".into()));
                            cache.complete(&worker_key, attempt, result);
                        });
                    if spawn.is_err() {
                        self.hot_session_history.complete(
                            &key,
                            attempt,
                            Err("session_transport_unavailable".into()),
                        );
                        return Err("session_transport_unavailable".into());
                    }
                    Ok(serde_json::json!({
                        "records": [],
                        "next_cursor": null,
                        "refreshing": true,
                    }))
                }
                HotSessionHistoryLookup::Loading => Ok(serde_json::json!({
                    "records": [],
                    "next_cursor": null,
                    "refreshing": true,
                })),
                HotSessionHistoryLookup::Failed(code) => Err(code),
                HotSessionHistoryLookup::Busy => Err("session_history_busy".into()),
            }
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (session_id, cursor, limit);
            Err("product_sessions_unavailable".into())
        }
    }

    fn request_status(
        &self,
        session_id: &str,
        route: &str,
        request_id: &str,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            if route != "agent_turn" {
                return Err("invalid_request_route".into());
            }
            let request_scope = format!("session_id:{session_id}");
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "session_store_unavailable".to_string())?;
            let durable_admission =
                control_store.agent_turn_admission_status(request_id, &request_scope)?;
            if let Some((phase, error_code)) = durable_admission.as_ref() {
                if *phase != isyncyou_agent::RequestPhase::Accepted {
                    self.hot_request_statuses.insert_with_terminal_code(
                        session_id,
                        request_id,
                        *phase,
                        error_code.as_deref(),
                    );
                    return Ok(request_status_json_with_terminal_code(
                        *phase,
                        error_code.as_deref(),
                    ));
                }
            }
            if let Some((phase, terminal_code)) =
                self.hot_request_statuses.get(session_id, request_id)
            {
                return Ok(request_status_json_with_terminal_code(
                    phase,
                    terminal_code.as_deref(),
                ));
            }
            let remote_status = (|| -> Result<Option<isyncyou_agent::RequestStatusV1>, String> {
                let store = agent_credential_store(&self.oauth_dir)
                    .map_err(|_| "session_store_unavailable".to_string())?;
                let registry = product_session::ProductSessionRegistry::new(&store);
                let account = registry.account_for(session_id)?;
                let token = isyncyou_engine::auth::resolve_cached_sync_token(&self.cfg, &account)
                    .map_err(|_| "session_transport_unavailable".to_string())?;
                registry
                    .open(&token, session_id)?
                    .request_status(
                        session_id,
                        isyncyou_agent::RequestRouteDomain::AgentTurn,
                        request_id,
                    )
                    .map_err(|error| match error {
                        isyncyou_agent::SessionV2Error::InvalidRecord
                        | isyncyou_agent::SessionV2Error::InvalidJournal => {
                            "session_state_invalid".to_string()
                        }
                        isyncyou_agent::SessionV2Error::InvalidRequestId => {
                            "invalid_request_id".to_string()
                        }
                        isyncyou_agent::SessionV2Error::ManifestConflict
                        | isyncyou_agent::SessionV2Error::LeaseLost => "lease_lost".to_string(),
                        isyncyou_agent::SessionV2Error::TransportUnavailable => {
                            "session_transport_unavailable".to_string()
                        }
                        isyncyou_agent::SessionV2Error::TransportTimedOut => {
                            "session_transport_timed_out".to_string()
                        }
                        isyncyou_agent::SessionV2Error::TransportResponseInvalid => {
                            "session_storage_response_invalid".to_string()
                        }
                        isyncyou_agent::SessionV2Error::TransportAuthenticationRequired => {
                            "session_writer_reconnect_required".to_string()
                        }
                        isyncyou_agent::SessionV2Error::TransportPermissionDenied => {
                            "session_storage_permission_denied".to_string()
                        }
                        isyncyou_agent::SessionV2Error::TransportRequestRejected => {
                            "session_storage_request_rejected".to_string()
                        }
                        _ => "session_store_unavailable".to_string(),
                    })
            })();
            let status = match remote_status {
                Ok(status) => status,
                Err(error)
                    if durable_admission.is_some()
                        && durable_admission_covers_remote_status_error(&error) =>
                {
                    None
                }
                Err(error) => return Err(error),
            };
            if let Some(status) = status {
                self.hot_request_statuses.insert_with_terminal_code(
                    session_id,
                    request_id,
                    status.phase,
                    status.terminal_code.as_deref(),
                );
                return Ok(request_status_json_with_terminal_code(
                    status.phase,
                    status.terminal_code.as_deref(),
                ));
            }
            if let Some((phase, error_code)) = durable_admission {
                self.hot_request_statuses.insert_with_terminal_code(
                    session_id,
                    request_id,
                    phase,
                    error_code.as_deref(),
                );
                return Ok(request_status_json_with_terminal_code(
                    phase,
                    error_code.as_deref(),
                ));
            }
            Err("request_not_found".into())
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (session_id, route, request_id);
            Err("product_sessions_unavailable".into())
        }
    }

    fn session_archive(
        &self,
        request: isyncyou_webui::AgentSessionArchiveRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "presence_unavailable".to_string())?;
            let binding = control_store.consume_user_presence(
                &request.operation_id,
                "session_archive",
                &request.request_id,
                unix_now_ms(),
            )?;
            let agent_control_store::UserPresenceBinding::Archive { session_id } = binding else {
                return Err("presence_not_authorized".into());
            };
            let credential_store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let registry = product_session::ProductSessionRegistry::new(&credential_store);
            let account = registry.account_for(&session_id)?;
            let token = isyncyou_engine::auth::resolve_cached_sync_token(&self.cfg, &account)
                .map_err(|_| "session_transport_unavailable".to_string())?;
            let archived = registry.archive(&token, &request.request_id, &session_id)?;
            Ok(serde_json::json!({
                "state": "archived",
                "session_id": archived.session_id,
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("product_sessions_unavailable".into())
        }
    }

    fn user_presence_start(
        &self,
        request: isyncyou_webui::AgentUserPresenceStartRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            use agent_control_store::UserPresenceBinding;
            let binding = match (request.kind.as_str(), request.binding) {
                (
                    "session_archive",
                    isyncyou_webui::AgentUserPresenceBinding::SessionArchive(binding),
                ) => UserPresenceBinding::Archive {
                    session_id: binding.session_id,
                },
                (
                    "session_pairing_reveal",
                    isyncyou_webui::AgentUserPresenceBinding::SessionPairingReveal(binding),
                ) => UserPresenceBinding::PairingReveal {
                    session_id: binding.session_id,
                    pair_id: binding.pair_id,
                },
                (
                    "session_pairing_import",
                    isyncyou_webui::AgentUserPresenceBinding::SessionPairingImport(binding),
                ) => {
                    isyncyou_agent::PairingCodeV2::parse(&binding.pairing_code)
                        .map_err(|error| error.to_string())?;
                    UserPresenceBinding::PairingImport {
                        pairing_code: binding.pairing_code,
                    }
                }
                _ => return Err("presence_invalid_request".into()),
            };
            let store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "presence_unavailable".to_string())?;
            let challenge =
                store.start_user_presence(&request.request_id, binding, unix_now_ms())?;
            Ok(serde_json::json!({
                "operation_id": challenge.operation_id,
                "intent_id": challenge.intent_id,
                "token": challenge.token,
                "action_hash": challenge.action_hash,
                "expires_at_ms": challenge.expires_at_ms,
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("presence_unavailable".into())
        }
    }

    fn user_presence_confirm(
        &self,
        request: isyncyou_webui::AgentUserPresenceConfirmRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "presence_unavailable".to_string())?;
            store.confirm_user_presence(
                &request.operation_id,
                &request.intent_id,
                &request.token,
                &request.action_hash,
                unix_now_ms(),
            )?;
            Ok(serde_json::json!({
                "operation_id": request.operation_id,
                "state": "authorized",
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("presence_unavailable".into())
        }
    }

    fn session_pairing_create(
        &self,
        request: isyncyou_webui::AgentSessionPairingCreateRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let credential_store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let registry = product_session::ProductSessionRegistry::new(&credential_store);
            if let Some(control_store) = self.control_store.as_ref() {
                let maintenance_now_ms = unix_now_ms();
                // Pairing creation is a local intent mutation. Remote descriptor cleanup is
                // owned by the startup/interval maintenance worker so this route cannot block
                // behind provider I/O before it returns the source handle.
                let _ = control_store.reap_expired(maintenance_now_ms, 256);
            }
            registry.account_for(&request.session_id)?;
            let payload = registry.pairing_payload(&request.session_id)?;
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "pairing_unavailable".to_string())?;
            let source = control_store.create_pairing_source(
                &request.request_id,
                &request.session_id,
                &payload,
                unix_now_ms(),
            )?;
            Ok(serde_json::json!({
                "pair_id": source.pair_id,
                "expires_at_ms": source.expires_at_ms,
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("pairing_unavailable".into())
        }
    }

    fn session_pairing_reveal(
        &self,
        request: isyncyou_webui::AgentSessionPairingOperationRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "pairing_unavailable".to_string())?;
            let source = control_store.consume_pairing_reveal(
                &request.operation_id,
                &request.request_id,
                unix_now_ms(),
            )?;
            let payload = source
                .pairing_payload()
                .map_err(|error| error.to_string())?;
            let credential_store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let registry = product_session::ProductSessionRegistry::new(&credential_store);
            let account = registry.account_for(payload.session_id.as_str())?;
            let token = isyncyou_engine::auth::resolve_cached_sync_token(&self.cfg, &account)
                .map_err(|_| "pairing_transport_unavailable".to_string())?;
            registry.ensure_remote_session(&token, payload.session_id.as_str())?;
            isyncyou_agent::OneDrivePairingTransportV2::new(token)
                .create_or_adopt(&source)
                .map_err(|error| error.to_string())?;
            Ok(serde_json::json!({
                "pairing_code": source.reveal_code(),
                "expires_at_ms": source.descriptor().expires_at_ms,
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("pairing_unavailable".into())
        }
    }

    fn session_pairing_claim(
        &self,
        request: isyncyou_webui::AgentSessionPairingOperationRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "pairing_unavailable".to_string())?;
            let terminal_state = control_store
                .pairing_claim_state(&request.operation_id, Some(&request.request_id))?;
            if let Some(state @ ("installed" | "consumed")) = terminal_state.as_deref() {
                let session_id = control_store
                    .pairing_claim_result_session(&request.operation_id, &request.request_id)?
                    .ok_or_else(|| "pairing_unavailable".to_string())?;
                return Ok(serde_json::json!({
                    "operation_id": request.operation_id,
                    "state": if state == "consumed" { "consumed" } else { "claimed" },
                    "session_id": session_id,
                }));
            }
            cleanup_pairing_claim_descriptors_once(&self.cfg, control_store, unix_now_ms());
            let account = match control_store.pairing_claim_local_account(&request.operation_id)? {
                Some(account) => account,
                None => self.product_session_account()?.to_owned(),
            };
            let token = isyncyou_engine::auth::resolve_cached_sync_token(&self.cfg, &account)
                .map_err(|_| "pairing_transport_unavailable".to_string())?;
            let repository = account_lifecycle_repository(&self.oauth_dir)?;
            let installation = repository
                .load_existing()
                .map_err(|_| "pairing_identity_unavailable".to_string())?
                .ok_or_else(|| "pairing_identity_unavailable".to_string())?;
            let transport = isyncyou_agent::OneDrivePairingTransportV2::new(token);
            let existing = control_store.load_pairing_claim_for_request(
                &request.operation_id,
                &request.request_id,
                installation.principal(),
                unix_now_ms(),
            );
            let (code, claim) = match existing {
                Ok(existing) => existing,
                Err(error) if error == "pairing_not_found" => {
                    let code = control_store.pairing_import_code(&request.operation_id)?;
                    let current = transport
                        .load(code.pair_id())
                        .map_err(|error| error.to_string())?;
                    control_store.begin_pairing_claim(
                        &request.request_id,
                        &request.operation_id,
                        &account,
                        &current.descriptor,
                        installation.principal(),
                        unix_now_ms(),
                    )?
                }
                Err(error) => return Err(error),
            };
            let current = transport
                .load(code.pair_id())
                .map_err(|error| error.to_string())?;
            if let Some(next) = claim
                .claim_transition(&current.descriptor)
                .map_err(|error| error.to_string())?
            {
                let claimed = transport
                    .compare_and_swap(&current, &next)
                    .map_err(|error| error.to_string())?
                    .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
                if claimed.descriptor != next {
                    return Err("pairing_outcome_unknown".into());
                }
            }
            let credential_store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let session = product_session::ProductSessionRegistry::new(&credential_store)
                .import_pairing_payload(
                    &request.request_id,
                    &account,
                    &claim.payload,
                    unix_now_ms(),
                )?;
            control_store
                .mark_pairing_claim_installed(&request.operation_id, &session.session_id)?;
            Ok(serde_json::json!({
                "operation_id": request.operation_id,
                "state": "claimed",
                "session_id": session.session_id,
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("pairing_unavailable".into())
        }
    }

    fn session_pairing_finalize(
        &self,
        request: isyncyou_webui::AgentSessionPairingOperationRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "pairing_unavailable".to_string())?;
            if control_store.pairing_claim_state(&request.operation_id, None)?
                == Some("consumed".into())
            {
                return Ok(serde_json::json!({
                    "operation_id": request.operation_id,
                    "state": "consumed",
                }));
            }
            let account = control_store
                .pairing_claim_local_account(&request.operation_id)?
                .ok_or_else(|| "pairing_not_found".to_string())?;
            let token = isyncyou_engine::auth::resolve_cached_sync_token(&self.cfg, &account)
                .map_err(|_| "pairing_transport_unavailable".to_string())?;
            let repository = account_lifecycle_repository(&self.oauth_dir)?;
            let installation = repository
                .load_existing()
                .map_err(|_| "pairing_identity_unavailable".to_string())?
                .ok_or_else(|| "pairing_identity_unavailable".to_string())?;
            let (code, claim) = control_store.load_pairing_claim(
                &request.operation_id,
                installation.principal(),
                unix_now_ms(),
            )?;
            let transport = isyncyou_agent::OneDrivePairingTransportV2::new(token);
            if !control_store
                .pairing_claim_remote_consumed(&request.operation_id, &request.request_id)?
            {
                let current = transport
                    .load_optional(code.pair_id())
                    .map_err(|error| error.to_string())?
                    .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
                let consumed = claim
                    .finalize(&current.descriptor)
                    .map_err(|error| error.to_string())?;
                let terminal = if consumed != current.descriptor {
                    let published = transport
                        .compare_and_swap(&current, &consumed)
                        .map_err(|error| error.to_string())?
                        .ok_or_else(|| "pairing_outcome_unknown".to_string())?;
                    if published.descriptor != consumed {
                        return Err("pairing_outcome_unknown".into());
                    }
                    published
                } else {
                    current
                };
                control_store.mark_pairing_claim_remote_consumed(
                    &request.operation_id,
                    &request.request_id,
                )?;
                if transport.delete(&terminal).is_ok_and(|deleted| deleted) {
                    let _ = control_store
                        .mark_pairing_claim_descriptor_cleanup_complete(&request.operation_id);
                }
            } else {
                match transport.load_optional(code.pair_id()) {
                    Ok(None) => {
                        let _ = control_store
                            .mark_pairing_claim_descriptor_cleanup_complete(&request.operation_id);
                    }
                    Ok(Some(current)) => {
                        if claim
                            .finalize(&current.descriptor)
                            .is_ok_and(|descriptor| descriptor == current.descriptor)
                            && transport.delete(&current).is_ok_and(|deleted| deleted)
                        {
                            let _ = control_store.mark_pairing_claim_descriptor_cleanup_complete(
                                &request.operation_id,
                            );
                        }
                    }
                    Err(_) => {}
                }
            }
            control_store.complete_pairing_claim(
                &request.operation_id,
                &request.request_id,
                unix_now_ms(),
            )?;
            Ok(serde_json::json!({
                "operation_id": request.operation_id,
                "state": "consumed",
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("pairing_unavailable".into())
        }
    }

    fn session_pairing_revoke(
        &self,
        request: isyncyou_webui::AgentSessionPairingOperationRequest,
    ) -> Result<serde_json::Value, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let control_store = self
                .control_store
                .as_ref()
                .ok_or_else(|| "pairing_unavailable".to_string())?;
            let source = match control_store
                .begin_pairing_revoke(&request.operation_id, &request.request_id)
            {
                Ok(source) => source,
                Err(error) if error == "pairing_revoked" => {
                    return Ok(serde_json::json!({
                        "operation_id": request.operation_id,
                        "state": "revoked",
                    }));
                }
                Err(error) => return Err(error),
            };
            let payload = source
                .pairing_payload()
                .map_err(|error| error.to_string())?;
            let credential_store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let registry = product_session::ProductSessionRegistry::new(&credential_store);
            let account = registry.account_for(payload.session_id.as_str())?;
            let token = isyncyou_engine::auth::resolve_cached_sync_token(&self.cfg, &account)
                .map_err(|_| "pairing_transport_unavailable".to_string())?;
            let transport = isyncyou_agent::OneDrivePairingTransportV2::new(token);
            let mut descriptor_cleanup_complete = false;
            if let Some(current) = transport
                .load_optional(source.pair_id())
                .map_err(|error| error.to_string())?
            {
                if current.descriptor.state != isyncyou_agent::PairingRemoteStateV2::Revoked {
                    let revoked = current
                        .descriptor
                        .clone()
                        .revoke()
                        .map_err(|error| error.to_string())?;
                    let updated = transport
                        .compare_and_swap(&current, &revoked)
                        .map_err(|error| error.to_string())?;
                    match updated {
                        Some(updated) if updated.descriptor == revoked => {}
                        Some(_) => return Err("pairing_outcome_unknown".into()),
                        None => {
                            let observed = transport
                                .load_optional(source.pair_id())
                                .map_err(|error| error.to_string())?;
                            match observed {
                                None => descriptor_cleanup_complete = true,
                                Some(observed)
                                    if observed.descriptor.state
                                        == isyncyou_agent::PairingRemoteStateV2::Revoked => {}
                                Some(_) => return Err("pairing_outcome_unknown".into()),
                            }
                        }
                    }
                }
                if !descriptor_cleanup_complete {
                    match transport.load_optional(source.pair_id()) {
                        Ok(None) => descriptor_cleanup_complete = true,
                        Ok(Some(current)) => {
                            descriptor_cleanup_complete =
                                transport.delete(&current).is_ok_and(|deleted| deleted);
                        }
                        Err(_) => {}
                    }
                }
            } else {
                descriptor_cleanup_complete = true;
            }
            control_store.complete_pairing_revoke(
                &request.operation_id,
                &request.request_id,
                unix_now_ms(),
            )?;
            if descriptor_cleanup_complete {
                control_store.mark_pairing_source_descriptor_cleanup_complete(source.pair_id())?;
            }
            Ok(serde_json::json!({
                "operation_id": request.operation_id,
                "state": "revoked",
            }))
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = request;
            Err("pairing_unavailable".into())
        }
    }

    fn connectivity_preflight(
        &self,
        request: isyncyou_webui::AgentConnectivityPreflightRequest,
    ) -> Result<isyncyou_webui::AgentConnectivityPreflightResponse, String> {
        self.connectivity_preflight_with_session(request, None, false)
    }

    fn connectivity_preflight_with_session(
        &self,
        request: isyncyou_webui::AgentConnectivityPreflightRequest,
        session_token: Option<&str>,
        mobile_bridge: bool,
    ) -> Result<isyncyou_webui::AgentConnectivityPreflightResponse, String> {
        let provider = isyncyou_agent::ConnectivityProvider::parse(&request.provider)
            .ok_or_else(|| "unknown provider".to_string())?;
        let purpose = isyncyou_agent::ConnectivityPurpose::parse(&request.purpose)
            .ok_or_else(|| "unknown connectivity purpose".to_string())?;
        let snapshot_id =
            connectivity_snapshot_for_transport(&request, session_token, mobile_bridge)?;
        let preflight = match CONNECTIVITY_PROBES.try_acquire() {
            None => isyncyou_agent::classify(None, None),
            Some(_permit) => {
                // Do not consume the single-use mobile handle until the request has passed
                // every local admission check and will actually run a probe.
                let consumed_snapshot = match snapshot_id {
                    Some(snapshot_id) => Some(consume_mobile_connectivity_snapshot(
                        snapshot_id,
                        session_token,
                        purpose,
                    )?),
                    None => None,
                };
                let snapshot = consumed_snapshot.as_ref().map(|value| value.snapshot);
                let forced_observation = consumed_snapshot
                    .as_ref()
                    .and_then(|value| value.forced_observation);
                #[cfg(any(
                    feature = "agent-oauth-providers",
                    feature = "agent-subscription-experimental"
                ))]
                {
                    let observation = forced_observation.unwrap_or_else(|| {
                        isyncyou_agent::http::HttpTransport::probe_shared(
                            isyncyou_agent::target_for(provider, purpose),
                        )
                        .ok()
                        .unwrap_or(isyncyou_agent::ProbeObservation::ConnectFailed)
                    });
                    isyncyou_agent::classify(snapshot, Some(observation))
                }
                #[cfg(not(any(
                    feature = "agent-oauth-providers",
                    feature = "agent-subscription-experimental"
                )))]
                {
                    let _ = (provider, purpose, forced_observation);
                    isyncyou_agent::classify(
                        snapshot,
                        Some(isyncyou_agent::ProbeObservation::ConnectFailed),
                    )
                }
            }
        };
        let (status, settings_hint) = match preflight.code {
            isyncyou_agent::ConnectivityPreflightCode::Ready => ("ready", "none"),
            isyncyou_agent::ConnectivityPreflightCode::NoValidatedNetwork => {
                ("action_required", "internet_panel")
            }
            isyncyou_agent::ConnectivityPreflightCode::RestrictedMeteredBackground => {
                ("action_required", "background_data")
            }
            isyncyou_agent::ConnectivityPreflightCode::ForegroundGuardUnavailable => {
                ("action_required", "app_details")
            }
            _ => ("unavailable", "none"),
        };
        Ok(isyncyou_webui::AgentConnectivityPreflightResponse {
            status: status.into(),
            code: preflight.code.wire().into(),
            retryable: preflight.retryable,
            settings_hint: settings_hint.into(),
        })
    }

    fn credential_refresh(&self, provider: &str) -> Result<String, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            self.refresh_product_credential(provider)
                .map(str::to_string)
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = provider;
            Err("reconnect_required".into())
        }
    }

    fn start_turn(&self, account: &str, prompt: &str) -> Result<String, String> {
        // #639 T7: resolve + gate the provider BEFORE any turn-id / stream-slot / archive
        // resolution. A not-ready product turn returns the closed error here and creates no turn
        // state, no stream, no archive, and makes no provider call.
        let system = format!("{AGENT_SYSTEM_PROMPT}\n\nActive account: {account}.");
        let prepared = self.resolve_turn_provider(&system)?;
        let mut provider = prepared.provider;
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let provider_id = prepared.provider_id;
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let operation_lease = prepared.operation_lease;
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let _session_binding = prepared.session_binding;

        let n = self.seq.fetch_add(1, Ordering::SeqCst);
        let turn_id = format!("turn-{n}-{}", unix_now());
        let rx_events = self.hub.open(&turn_id, 256);
        let (tx_str, rx_str) = std::sync::mpsc::channel::<String>();
        // Forward hub StreamEvents -> JSON strings until the turn closes.
        std::thread::spawn(move || {
            while let Ok(ev) = rx_events.recv() {
                if tx_str.send(agent_event_json(&ev)).is_err() {
                    break;
                }
            }
        });
        let now_ms = unix_now_ms();
        {
            let mut streams = self.streams.lock().unwrap();
            Self::sweep_unopened_streams_locked(&mut streams, now_ms);
            streams.insert(
                turn_id.clone(),
                AgentStreamSlot {
                    rx: rx_str,
                    created_at_ms: now_ms,
                    #[cfg(any(
                        feature = "agent-oauth-providers",
                        feature = "agent-subscription-experimental"
                    ))]
                    provider: provider_id,
                },
            );
        }
        // Run the turn on a background thread streaming events into the hub.
        let hub = self.hub.clone();
        let tid = turn_id.clone();
        let prompt = prompt.to_string();
        // Resolve the account's archive root now (reads config on this thread), so the
        // turn thread can build the real store-backed retrieval executor for it.
        let account_id = account.to_string();
        let archive_root = self.archive_root_for(&account_id);
        let pending = self.pending.clone();
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        let last_usage = Arc::clone(&self.last_usage);
        let turn_thread = std::thread::Builder::new()
            .name(format!("agent-turn-{n}"))
            .spawn(move || {
                #[cfg(any(
                    feature = "agent-oauth-providers",
                    feature = "agent-subscription-experimental"
                ))]
                let _operation_lease = operation_lease;
                let exec = make_executor(&account_id, archive_root);
                let mut history = vec![isyncyou_agent::Message::user(prompt)];
                let outcome = isyncyou_agent::run_turn(
                    provider.as_mut(),
                    exec.as_ref(),
                    &mut history,
                    &mut |ev| {
                        hub.emit(&tid, ev);
                    },
                );
                #[cfg(any(
                    feature = "agent-oauth-providers",
                    feature = "agent-subscription-experimental"
                ))]
                if let Some(usage) = provider.last_usage() {
                    if let Some(provider_id) = provider_id {
                        if let Ok(mut last_usage) = last_usage.lock() {
                            last_usage.insert(provider_id, usage);
                        }
                    }
                }
                match outcome {
                    Ok(isyncyou_agent::TurnOutcome::Final { .. }) => {
                        let _ = hub.emit(
                            &tid,
                            isyncyou_agent::StreamEvent::done(isyncyou_agent::DoneReason::Complete),
                        );
                    }
                    Ok(isyncyou_agent::TurnOutcome::PendingConfirmation { action, .. }) => {
                        let action = *action;
                        let preview = match agent_ops::preview_for_pending_action(&action) {
                            Ok(preview) => preview,
                            Err(e) => {
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::Error(
                                        agent_ops::redact_agent_operation_text(&e),
                                    ),
                                );
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::done(
                                        isyncyou_agent::DoneReason::Error,
                                    ),
                                );
                                hub.close(&tid);
                                return;
                            }
                        };
                        let _risk = preview.risk.as_str();
                        match pending.register_bound(
                            action,
                            preview.text,
                            unix_now_ms(),
                            AGENT_CONFIRM_TTL_MS,
                            isyncyou_agent::PendingOwnerBinding {
                                account: account_id.clone(),
                                session_id: "legacy-local".into(),
                                request_id: format!("legacy-{tid}"),
                                turn_id: tid.clone(),
                            },
                        ) {
                            Ok((pending_action, token)) => {
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::ConfirmationRequired {
                                        id: pending_action.id,
                                        action: Box::new(pending_action.action),
                                        preview: pending_action.preview,
                                        action_hash: pending_action.action_hash,
                                        risk: pending_action.risk,
                                        expires_at_ms: pending_action.expires_at_ms,
                                        token,
                                    },
                                );
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::done(
                                        isyncyou_agent::DoneReason::PendingConfirmation,
                                    ),
                                );
                            }
                            Err(e) => {
                                let _ = e;
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::Error(
                                        "confirmation_unavailable".into(),
                                    ),
                                );
                                let _ = hub.emit(
                                    &tid,
                                    isyncyou_agent::StreamEvent::done(
                                        isyncyou_agent::DoneReason::Error,
                                    ),
                                );
                            }
                        }
                    }
                    Err(e) => {
                        let _ = hub.emit(
                            &tid,
                            isyncyou_agent::StreamEvent::Error(agent_safe_turn_error(&e).into()),
                        );
                        let _ = hub.emit(
                            &tid,
                            isyncyou_agent::StreamEvent::done(isyncyou_agent::DoneReason::Error),
                        );
                    }
                }
                hub.close(&tid);
            });
        if turn_thread.is_err() {
            self.streams.lock().unwrap().remove(&turn_id);
            self.hub.close(&turn_id);
            return Err("turn_spawn_failed".into());
        }
        Ok(turn_id)
    }

    fn start_turn_request(
        self: Arc<Self>,
        request: isyncyou_webui::AgentTurnRequest,
        identity: isyncyou_webui::ProductRequestIdentity,
    ) -> Result<String, String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            if self
                .turn_recovery_error
                .lock()
                .map_err(|_| "turn_admission_unavailable".to_string())?
                .is_some()
            {
                return Err("turn_admission_unavailable".into());
            }
            let store = agent_credential_store(&self.oauth_dir)
                .map_err(|_| "session_store_unavailable".to_string())?;
            let registry = product_session::ProductSessionRegistry::new(&store);
            let bound_account = registry.account_for(&request.session_id)?;
            if bound_account != request.account {
                return Err("session_account_mismatch".into());
            }
            let turn_id = turn_id_from_request_id(&request.request_id)?;
            let digest = turn_admission_digest(&request);
            let control_store = self
                .control_store
                .as_ref()
                .cloned()
                .ok_or_else(|| "session_store_unavailable".to_string())?;
            let admission = match self.turn_admissions.reserve(&turn_id, digest) {
                Ok(Some(admission)) => admission,
                Ok(None) => return Ok(turn_id),
                Err(error) => return Err(error),
            };
            let durable_state =
                control_store.begin_agent_turn_admission_identity(&request, &turn_id, &identity)?;
            let recovered_admission = matches!(
                &durable_state,
                agent_control_store::AgentTurnAdmissionBegin::Existing
            );
            let durable_admission = DurableTurnAdmissionLease {
                store: Arc::clone(&control_store),
                request_id: request.request_id.clone(),
                completed: false,
            };
            let selected_provider = self.agent_settings().map(|settings| settings.provider);
            let reserved = self.reserve_agent_turn(
                turn_id.clone(),
                selected_provider,
                admission,
                durable_admission,
            )?;
            match durable_state {
                agent_control_store::AgentTurnAdmissionBegin::Cancelled => {
                    self.emit_product_turn_replay(
                        &turn_id,
                        product_session::ProductTurnReplay {
                            phase: isyncyou_agent::RequestPhase::Cancelled,
                            final_text: None,
                            error_code: None,
                        },
                        None,
                    );
                    drop(reserved);
                    return Ok(turn_id);
                }
                agent_control_store::AgentTurnAdmissionBegin::Failed(code) => {
                    self.emit_product_turn_replay(
                        &turn_id,
                        product_session::ProductTurnReplay {
                            phase: isyncyou_agent::RequestPhase::Failed,
                            final_text: None,
                            error_code: Some(code),
                        },
                        None,
                    );
                    drop(reserved);
                    return Ok(turn_id);
                }
                agent_control_store::AgentTurnAdmissionBegin::OutcomeUnknown(code) => {
                    self.emit_product_turn_replay(
                        &turn_id,
                        product_session::ProductTurnReplay {
                            phase: isyncyou_agent::RequestPhase::OutcomeUnknown,
                            final_text: None,
                            error_code: Some(code),
                        },
                        None,
                    );
                    drop(reserved);
                    return Ok(turn_id);
                }
                agent_control_store::AgentTurnAdmissionBegin::Inserted
                | agent_control_store::AgentTurnAdmissionBegin::Existing => {}
            }
            self.hot_request_statuses.insert(
                &request.session_id,
                &request.request_id,
                isyncyou_agent::RequestPhase::Accepted,
            );
            let cached_context = self
                .hot_session_history
                .context_snapshot(&request.session_id);
            let worker = Arc::downgrade(&self);
            let worker_turn_id = turn_id.clone();
            let admission_cancellation = reserved.cancellation.clone();
            let preparation = spawn_agent_turn_admission(move || {
                let retry_deadline = std::time::Instant::now() + RECOVERED_TURN_START_RETRY_WINDOW;
                let mut reserved = Some(reserved);
                let prepared_start = prepare_turn_admission(
                    recovered_admission,
                    || {
                        let worker = worker
                            .upgrade()
                            .ok_or_else(|| "daemon_unavailable".to_string())?;
                        if admission_cancellation.is_cancelled() {
                            return Err("turn_cancelled".to_string());
                        }
                        let system = format!(
                            "{AGENT_SYSTEM_PROMPT}\n\nActive account: {}.",
                            request.account
                        );
                        let prepared = worker.resolve_turn_provider(&system)?;
                        if admission_cancellation.is_cancelled() {
                            return Err("turn_cancelled".to_string());
                        }
                        let provider_binding = prepared
                            .session_binding
                            .clone()
                            .ok_or_else(|| "provider_generation_changed".to_string())?;
                        let context_budget = product_model_context_budget(
                            provider_binding.provider,
                            &provider_binding.model,
                        )?;
                        let installation = account_lifecycle_repository(&worker.oauth_dir)
                            .and_then(|repository| {
                                repository
                                    .load_existing()
                                    .map_err(|_| "lifecycle_unavailable".to_string())
                            })?
                            .ok_or_else(|| "lifecycle_unavailable".to_string())?;
                        let token = isyncyou_engine::auth::resolve_cached_sync_token(
                            &worker.cfg,
                            &request.account,
                        )
                        .map_err(|_| "session_writer_reconnect_required".to_string())?;
                        if admission_cancellation.is_cancelled() {
                            return Err("turn_cancelled".to_string());
                        }
                        let store = agent_credential_store(&worker.oauth_dir)
                            .map_err(|_| "session_store_unavailable".to_string())?;
                        let registry = product_session::ProductSessionRegistry::new(&store);
                        let product_turn =
                            registry.begin_turn(product_session::ProductTurnRequest {
                                graph_token: &token,
                                session_id: &request.session_id,
                                request_id: &request.request_id,
                                turn_id: &worker_turn_id,
                                local_account: &request.account,
                                prompt: &request.prompt,
                                provider_binding,
                                installation_principal: installation.principal(),
                                created_at_ms: unix_now_ms(),
                                cached_context: cached_context.clone(),
                                context_budget,
                            })?;
                        Ok((worker, prepared, product_turn))
                    },
                    || std::time::Instant::now() < retry_deadline,
                    || std::thread::sleep(RECOVERED_TURN_START_RETRY_INTERVAL),
                );
                let result = match prepared_start {
                    TurnAdmissionPreparation::Ready((worker, prepared, product_turn)) => {
                        worker
                            .hot_request_statuses
                            .remove(&request.session_id, &request.request_id);
                        (|| -> Result<(), String> {
                            let mut owned_reserved = reserved
                                .take()
                                .ok_or_else(|| "turn_registry_unavailable".to_string())?;
                            let pending_owner = isyncyou_agent::PendingOwnerBinding {
                                account: request.account.clone(),
                                session_id: request.session_id.clone(),
                                request_id: request.request_id.clone(),
                                turn_id: worker_turn_id.clone(),
                            };
                            let mut product_turn = Some(product_turn);
                            if recovered_admission
                                && matches!(
                                    product_turn.as_ref(),
                                    Some(product_session::ProductTurnStart::Started(_))
                                )
                            {
                                let reissued_pending = match worker
                                    .pending
                                    .reissue_for_owner(&pending_owner, unix_now_ms())
                                {
                                    Ok(value) => value,
                                    Err(_) => {
                                        drop(prepared);
                                        worker.fail_reserved_turn(
                                            &worker_turn_id,
                                            "request_resume_required",
                                        );
                                        return Ok(());
                                    }
                                };
                                if let Some((pending_action, token)) = reissued_pending {
                                    let product_session::ProductTurnStart::Started(runtime) =
                                        product_turn.take().ok_or_else(|| {
                                            "session_store_unavailable".to_string()
                                        })?
                                    else {
                                        return Err("session_store_unavailable".into());
                                    };
                                    let pending_id = pending_action.id.clone();
                                    let transition = TurnRegistry::begin_pending(
                                        &owned_reserved.turn_state,
                                        || {
                                            cache_product_session_context(
                                                &worker.hot_session_history,
                                                runtime.finish_pending(unix_now_ms()),
                                            )?;
                                            Ok((pending_id, (pending_action, token)))
                                        },
                                    );
                                    drop(prepared);
                                    match transition {
                                        Ok(PendingTransition::Committed((
                                            pending_action,
                                            token,
                                        ))) => {
                                            worker.hot_request_statuses.insert(
                                                &request.session_id,
                                                &request.request_id,
                                                isyncyou_agent::RequestPhase::PendingConfirmation,
                                            );
                                            let _ = owned_reserved.durable_admission.complete();
                                            drop(owned_reserved.admission.take());
                                            let _ = worker.hub.emit(
                                                &worker_turn_id,
                                                isyncyou_agent::StreamEvent::ConfirmationRequired {
                                                    id: pending_action.id,
                                                    action: Box::new(pending_action.action),
                                                    preview: pending_action.preview,
                                                    action_hash: pending_action.action_hash,
                                                    risk: pending_action.risk,
                                                    expires_at_ms: pending_action.expires_at_ms,
                                                    token,
                                                },
                                            );
                                            let _ = worker.hub.emit(
                                                &worker_turn_id,
                                                isyncyou_agent::StreamEvent::done(
                                                    isyncyou_agent::DoneReason::PendingConfirmation,
                                                ),
                                            );
                                            worker.hub.close(&worker_turn_id);
                                            worker.turns.remove(&worker_turn_id);
                                            worker
                                                .hot_session_history
                                                .invalidate(&request.session_id);
                                            return Ok(());
                                        }
                                        Ok(PendingTransition::Cancelled) | Err(_) => {
                                            worker.fail_reserved_turn(
                                                &worker_turn_id,
                                                "request_resume_required",
                                            );
                                            return Ok(());
                                        }
                                    }
                                }
                            }
                            let product_turn = product_turn
                                .take()
                                .ok_or_else(|| "session_store_unavailable".to_string())?;
                            if matches!(&product_turn, product_session::ProductTurnStart::Replay(_))
                            {
                                owned_reserved.durable_admission.complete()?;
                                drop(owned_reserved.admission.take());
                            }
                            dispatch_prepared_product_turn(
                                prepared,
                                Ok(product_turn),
                                |prepared, product_turn| {
                                    worker.launch_prepared_turn(
                                        &request.account,
                                        &request.prompt,
                                        prepared,
                                        Some(*product_turn),
                                        owned_reserved,
                                    )
                                },
                                |replay| {
                                    worker.emit_product_turn_replay(
                                        &worker_turn_id,
                                        replay,
                                        Some(&pending_owner),
                                    );
                                    Ok(worker_turn_id.clone())
                                },
                            )?;
                            Ok(())
                        })()
                    }
                    TurnAdmissionPreparation::Deferred => {
                        if let Some(worker) = worker.upgrade() {
                            worker.fail_reserved_turn(&worker_turn_id, "request_resume_required");
                        }
                        drop(reserved.take());
                        return;
                    }
                    TurnAdmissionPreparation::Terminal(error) => Err(error),
                };
                if let Err(error) = result {
                    let Some(worker) = worker.upgrade() else {
                        drop(reserved.take());
                        return;
                    };
                    let safe_error = agent_safe_turn_start_error(&error);
                    let terminal =
                        control_store.fail_agent_turn_admission(&worker_turn_id, safe_error);
                    let emitted_error = match terminal {
                        Ok(agent_control_store::AgentTurnAdmissionFailure::Cancelled) => {
                            "turn_cancelled"
                        }
                        Ok(agent_control_store::AgentTurnAdmissionFailure::Failed)
                        | Ok(agent_control_store::AgentTurnAdmissionFailure::Completed) => {
                            safe_error
                        }
                        Err(_) => "turn_admission_unavailable",
                    };
                    if emitted_error != "turn_cancelled" {
                        worker.hot_request_statuses.insert(
                            &request.session_id,
                            &request.request_id,
                            isyncyou_agent::RequestPhase::Failed,
                        );
                    }
                    worker.fail_reserved_turn(&worker_turn_id, emitted_error);
                }
            });
            if preparation.is_err() {
                self.streams.lock().unwrap().remove(&turn_id);
                self.hub.close(&turn_id);
                self.turns.remove(&turn_id);
                return Err("turn_spawn_failed".into());
            }
            Ok(turn_id)
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        {
            let _ = (request, identity);
            Err("product_sessions_unavailable".into())
        }
    }

    fn pending_binding(
        &self,
        pending_id: &str,
        action_hash: &str,
    ) -> Result<isyncyou_webui::AgentPendingBinding, String> {
        let binding = self
            .pending
            .binding(pending_id, action_hash, unix_now_ms())
            .map_err(|e| format!("{e:?}"))?;
        Ok(isyncyou_webui::AgentPendingBinding {
            op: binding.op,
            account: binding.account,
            service: binding.service,
            item: binding.item,
        })
    }

    fn confirm(&self, pending_id: &str, token: &str, action_hash: &str) -> Result<String, String> {
        let action = self
            .pending
            .confirm(pending_id, token, action_hash, unix_now_ms())
            .map_err(|e| format!("{e:?}"))?;
        self.turns.remove_pending(pending_id);
        if let Err(error) = agent_ops::preview_for_pending_action(&action) {
            self.finish_pending_confirmation_state(pending_id, "failed", unix_now_ms())?;
            return Err(format!(
                "invalid_confirmed_action: {}",
                agent_ops::redact_agent_operation_text(&error)
            ));
        }
        let action_summary = agent_action_summary(&action);
        if self
            .audit_sink
            .record_confirm(&action, "started", &action_summary)
            .is_err()
        {
            self.finish_pending_confirmation_state(pending_id, "failed", unix_now_ms())?;
            return Err("audit_start_failed".into());
        }
        match self.confirmed_executor.execute_confirmed(&action) {
            Ok(result) => {
                let safe_summary = agent_ops::redact_agent_operation_text(&result.summary);
                let audit_result = self
                    .audit_sink
                    .record_confirm(&action, "ok", &format!("{action_summary} ok"))
                    .map_err(|_| "audit_finish_failed".to_string());
                self.finish_pending_confirmation_state(pending_id, "completed", unix_now_ms())?;
                audit_result?;
                serde_json::to_string(&serde_json::json!({
                    "status": "ok",
                    "op": action.op(),
                    "summary": safe_summary,
                }))
                .map_err(|e| e.to_string())
            }
            Err(e) => {
                let safe = agent_safe_executor_error(&e);
                let audit_result = self
                    .audit_sink
                    .record_confirm(&action, "error", &format!("{action_summary} error={safe}"))
                    .map_err(|_| "audit_finish_failed".to_string());
                self.finish_pending_confirmation_state(pending_id, "failed", unix_now_ms())?;
                audit_result?;
                Err(format!("{} failed: {safe}", action.op()))
            }
        }
    }

    fn cancel(&self, turn_id: &str) {
        let _ = self.cancel_turn(turn_id);
    }

    fn cancel_turn(&self, turn_id: &str) -> Result<(), String> {
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        {
            let control_store = self.control_store.clone();
            cancel_turn_with_pending_guard(
                &self.turns,
                &self.pending,
                &self.hub,
                turn_id,
                unix_now_ms(),
                || {
                    control_store
                        .as_ref()
                        .ok_or_else(|| "turn_admission_unavailable".to_string())?
                        .cancel_agent_turn_admission(turn_id)
                },
            )
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        cancel_turn_with_pending_guard(
            &self.turns,
            &self.pending,
            &self.hub,
            turn_id,
            unix_now_ms(),
            || Ok(()),
        )
    }

    fn cancel_pending(&self, pending_id: &str, action_hash: &str) -> Result<(), String> {
        let owner = self
            .pending
            .cancel(pending_id, action_hash, unix_now_ms())
            .map_err(|error| format!("{error:?}"))?;
        self.turns.remove_pending(pending_id);
        #[cfg(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        ))]
        if owner.session_id != "legacy-local" {
            let cfg = self.cfg.clone();
            let oauth_dir = self.oauth_dir.clone();
            if let Some(store) = self.control_store.clone() {
                // Authority reduction is already durable in AgentControlStore. Session projection
                // may require slow Graph manifest I/O, so it runs outside the bridge response and
                // is retried by lifecycle maintenance after a transport failure or process crash.
                let _ = std::thread::Builder::new()
                    .name("agent-pending-cancel-projection".into())
                    .spawn(move || {
                        reconcile_pending_cancel_projections(&cfg, &oauth_dir, &store, 8);
                    });
            }
        }
        #[cfg(not(any(
            feature = "agent-oauth-providers",
            feature = "agent-subscription-experimental"
        )))]
        let _ = owner;
        Ok(())
    }

    fn open_stream(&self, turn_id: &str) -> Option<std::sync::mpsc::Receiver<String>> {
        self.streams.lock().unwrap().remove(turn_id).map(|s| s.rx)
    }

    /// Begin the Claude device OAuth login: PKCE + state, with the
    /// manual (copy-paste) redirect — claude.ai shows a code instead of redirecting to a
    /// loopback server. The app opens the returned URL in the system browser. Robust on
    /// mobile (no loopback host/port/IPv6 fragility).
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_start_with_attempt(
        &self,
        provider: &str,
        redirect_uri: &str,
    ) -> Result<isyncyou_webui::AgentOAuthStartResponse, String> {
        match ProductProviderId::parse(provider) {
            Some(ProductProviderId::Codex) => Err("lifecycle_operation_required".into()),
            Some(ProductProviderId::Claude) => {
                let mut attempts = self
                    .oauth_attempts
                    .lock()
                    .map_err(|_| "oauth_start_failed".to_string())?;
                let expired = reap_oauth_attempts(&mut attempts, &self.oauth_dir);
                if let Ok(mut bindings) = self.oauth_lifecycle_bindings.lock() {
                    for attempt_id in expired {
                        bindings.remove(&attempt_id);
                    }
                }
                if attempts
                    .values()
                    .any(|attempt| matches!(attempt, OAuthAttempt::Claude { .. }))
                {
                    return Err("Claude sign-in is already in progress".into());
                }
                let cfg = self.load_oauth_config()?;
                // Loopback-primary (matches the real claude client): use the client's loopback
                // redirect when supplied; fall back to the manual (copy-paste) redirect otherwise.
                let redirect = if redirect_uri.is_empty() {
                    cfg.manual_redirect_url.as_str()
                } else {
                    redirect_uri
                };
                let started = self
                    .oauth
                    .start(&cfg, redirect)
                    .map_err(|e| e.to_string())?;
                let attempt_id = mint_cap_token();
                attempts.insert(
                    attempt_id.clone(),
                    OAuthAttempt::Claude {
                        state: started.state,
                        expires_at: std::time::Instant::now() + OAUTH_ATTEMPT_TTL,
                    },
                );
                // #639 T8: record the official sign-in start into the attempt-keyed journal.
                record_onboarding_attempt_transition(
                    &self.oauth_dir,
                    ProductProviderId::Claude,
                    &attempt_id,
                    ProductOnboardingState::OfficialSignInStarted,
                    None,
                );
                Ok(isyncyou_webui::AgentOAuthStartResponse {
                    authorize_url: started.authorize_url,
                    attempt_id,
                    lifecycle_operation_id: None,
                })
            }
            None => Err("unknown provider".into()),
        }
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_start_request(
        &self,
        request: isyncyou_webui::AgentOAuthStartRequest,
    ) -> Result<isyncyou_webui::AgentOAuthStartResponse, String> {
        let provider = ProductProviderId::parse(&request.provider)
            .ok_or_else(|| "unknown provider".to_string())?;
        let repository = account_lifecycle_repository(&self.oauth_dir)?;
        let operation_id = if let Some(operation_id) = request.lifecycle_operation_id.as_deref() {
            let active = repository
                .active_operation(provider)
                .map_err(|error| error.wire().to_string())?
                .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
            let journal = repository
                .load_journal(&active.journal_record_id)
                .map_err(|error| error.wire().to_string())?
                .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
            if active.prepared.operation_id != operation_id
                || !matches!(
                    active.prepared.mode,
                    account_lifecycle::AccountLifecycleMode::Connect
                        | account_lifecycle::AccountLifecycleMode::Reconnect
                        | account_lifecycle::AccountLifecycleMode::Switch
                )
                || journal.phase != account_lifecycle::AccountLifecyclePhase::AwaitingOAuthLogin
            {
                return Err("lifecycle_operation_mismatch".into());
            }
            operation_id.to_string()
        } else {
            self.begin_connect_lifecycle(provider, &request.request_id)?
                .operation_id
                .ok_or_else(|| "lifecycle_operation_missing".to_string())?
        };

        if let (Ok(attempts), Ok(bindings)) = (
            self.oauth_attempts.lock(),
            self.oauth_lifecycle_bindings.lock(),
        ) {
            if let Some((attempt_id, binding)) = bindings.iter().find(|(attempt_id, binding)| {
                binding.provider == provider
                    && binding.operation_id == operation_id
                    && attempts.contains_key(*attempt_id)
            }) {
                return Ok(isyncyou_webui::AgentOAuthStartResponse {
                    authorize_url: binding.authorize_url.clone(),
                    attempt_id: attempt_id.clone(),
                    lifecycle_operation_id: Some(operation_id),
                });
            }
        }

        let mut response = match provider {
            ProductProviderId::Claude => self.oauth_start_with_attempt(provider.wire(), "")?,
            ProductProviderId::Codex => self.codex_oauth_start(operation_id.clone())?,
        };
        self.oauth_lifecycle_bindings
            .lock()
            .map_err(|_| "oauth_start_failed".to_string())?
            .insert(
                response.attempt_id.clone(),
                OAuthLifecycleAttemptBinding {
                    provider,
                    operation_id: operation_id.clone(),
                    authorize_url: response.authorize_url.clone(),
                },
            );
        response.lifecycle_operation_id = Some(operation_id);
        Ok(response)
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_logout(
        &self,
        request: isyncyou_webui::AgentOAuthLogoutRequest,
    ) -> Result<isyncyou_webui::AgentAccountLifecycleResponse, String> {
        let provider = ProductProviderId::parse(&request.provider)
            .ok_or_else(|| "unknown provider".to_string())?;
        let mode =
            lifecycle_mode(&request.mode).ok_or_else(|| "lifecycle_mode_invalid".to_string())?;
        let transport = isyncyou_agent::http::HttpTransport::shared()
            .map_err(|_| "provider_unavailable".to_string())?;

        let result = if let Some(resume) = request.resume {
            let repository = account_lifecycle_repository(&self.oauth_dir)?;
            let active = repository
                .active_operation(provider)
                .map_err(|error| error.wire().to_string())?
                .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
            if active.prepared.operation_id != resume.operation_id
                || active.operation_etag != resume.operation_etag
                || active.prepared.mode != mode
            {
                return Err("lifecycle_operation_mismatch".into());
            }
            let journal = repository
                .load_journal(&active.journal_record_id)
                .map_err(|error| error.wire().to_string())?
                .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
            let action = match journal.phase {
                account_lifecycle::AccountLifecyclePhase::RevokeOutcomeUnknown => "retry_revoke",
                account_lifecycle::AccountLifecyclePhase::RevokedPendingCleanup => "resume_cleanup",
                account_lifecycle::AccountLifecyclePhase::AwaitingOAuthLogin => "continue_oauth",
                account_lifecycle::AccountLifecyclePhase::ExchangeOutcomeUnknown => {
                    "retry_exchange"
                }
                _ => return Err("lifecycle_phase_mismatch".into()),
            };
            self.resume_lifecycle_operation_with_transport(
                provider,
                &resume.operation_id,
                &resume.operation_etag,
                action,
                transport.as_ref(),
            )?
        } else {
            let credential_etag = request
                .credential_etag
                .as_deref()
                .ok_or_else(|| "credential_etag_mismatch".to_string())?;
            let (_, meta) = self
                .lifecycle_credential(provider)?
                .ok_or_else(|| "already_disconnected".to_string())?;
            let expected = account_lifecycle_repository(&self.oauth_dir)?
                .projected_credential_etag(provider, &meta.generation)
                .map_err(|error| error.wire().to_string())?;
            if credential_etag != expected {
                return Err("credential_etag_mismatch".into());
            }
            // Both reviewed providers currently classify as ObservedTokenSession. Keep the
            // acknowledgement gate explicit so a future FullGrant contract cannot mutate before
            // the user accepted the larger blast radius.
            require_revoke_scope_acknowledgement(
                isyncyou_agent::oauth::RevokeScopeGuarantee::ObservedTokenSession,
                request.acknowledge_full_grant,
            )?;
            match mode {
                account_lifecycle::AccountLifecycleMode::Disconnect => self
                    .disconnect_product_provider_with_transport(
                        provider,
                        &request.request_id,
                        transport.as_ref(),
                    )?,
                account_lifecycle::AccountLifecycleMode::Reconnect
                | account_lifecycle::AccountLifecycleMode::Switch => self
                    .begin_reconnect_or_switch_with_transport(
                        provider,
                        mode,
                        &request.request_id,
                        transport.as_ref(),
                    )?,
                account_lifecycle::AccountLifecycleMode::Connect => {
                    return Err("lifecycle_mode_invalid".into())
                }
            }
        };
        Ok(lifecycle_api_response(provider, mode, result))
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_lifecycle_resume(
        &self,
        request: isyncyou_webui::AgentOAuthLifecycleResumeRequest,
    ) -> Result<isyncyou_webui::AgentAccountLifecycleResponse, String> {
        let provider = ProductProviderId::parse(&request.provider)
            .ok_or_else(|| "unknown provider".to_string())?;
        let repository = account_lifecycle_repository(&self.oauth_dir)?;
        let active = repository
            .active_operation(provider)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "lifecycle_operation_missing".to_string())?;
        if active.prepared.operation_id != request.operation_id
            || active.operation_etag != request.operation_etag
        {
            return Err("lifecycle_operation_mismatch".into());
        }
        let mode = active.prepared.mode;
        let journal = repository
            .load_journal(&active.journal_record_id)
            .map_err(|error| error.wire().to_string())?
            .ok_or_else(|| "lifecycle_journal_missing".to_string())?;
        let candidate_revoke = matches!(
            journal.phase,
            account_lifecycle::AccountLifecyclePhase::OAuthCandidateCleanup
        ) || matches!(
            journal.revoked_grant.as_ref(),
            Some(account_lifecycle::RevokedGrantRef::OAuthCandidate { .. })
        );
        let candidate_revoke_target = if candidate_revoke {
            let candidate_id = repository
                .candidate_record_id(provider, &request.operation_id)
                .map_err(|error| error.wire().to_string())?;
            repository
                .load_candidate(&candidate_id)
                .map_err(|error| error.wire().to_string())?
                .map(|candidate| {
                    if candidate.refresh_token.is_empty() {
                        "access_token"
                    } else {
                        "refresh_token"
                    }
                })
        } else {
            None
        };
        let candidate_revoke_leg = if candidate_revoke {
            Some(journal.revoke_leg.saturating_add(u32::from(matches!(
                journal.phase,
                account_lifecycle::AccountLifecyclePhase::OAuthCandidateCleanup
            ))))
        } else {
            None
        };
        let transport = isyncyou_agent::http::HttpTransport::shared()
            .map_err(|_| "provider_unavailable".to_string())?;
        let result = self.resume_lifecycle_operation_with_transport(
            provider,
            &request.operation_id,
            &request.operation_etag,
            &request.action,
            transport.as_ref(),
        )?;
        let mut response = lifecycle_api_response(provider, mode, result);
        if let Some(revoke_leg) = candidate_revoke_leg {
            response.revoke_leg = revoke_leg;
            response.revoked_grant = Some("oauth_candidate".into());
            response.revoke_request_target = candidate_revoke_target.map(str::to_string);
            response.revoke_scope_guarantee = Some("observed_token_session".into());
        }
        Ok(response)
    }

    fn oauth_start(&self, provider: &str, redirect_uri: &str) -> Result<String, String> {
        self.oauth_start_with_attempt(provider, redirect_uri)
            .map(|result| result.authorize_url)
    }

    // Gated like the other OAuth methods: without the product/experimental features the trait's
    // default (login-not-enabled) applies, so the app-host compiles without agent-oauth-providers.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_cancel(&self, provider: &str, attempt_id: &str) -> Result<(), String> {
        // Validate and remove under one lock. A mismatched provider never creates the old
        // remove/reinsert race where a concurrent callback could observe the attempt as absent.
        let attempt = {
            let mut attempts = self
                .oauth_attempts
                .lock()
                .map_err(|_| "oauth attempt store is unavailable".to_string())?;
            let matches_provider = matches!(
                (provider, attempts.get(attempt_id)),
                ("claude", Some(OAuthAttempt::Claude { .. }))
                    | ("codex", Some(OAuthAttempt::Codex { .. }))
            );
            if !matches_provider {
                return Err(if attempts.contains_key(attempt_id) {
                    "oauth attempt does not match provider"
                } else {
                    "oauth attempt is not active"
                }
                .into());
            }
            attempts
                .remove(attempt_id)
                .ok_or_else(|| "oauth attempt is not active".to_string())?
        };
        if let Ok(mut bindings) = self.oauth_lifecycle_bindings.lock() {
            bindings.remove(attempt_id);
        }
        match (provider, attempt) {
            ("claude", OAuthAttempt::Claude { state, .. }) => {
                let _ = self.oauth.cancel(&state);
                // #639 T8: a cancelled in-flight attempt is a terminal, redacted transition.
                record_onboarding_attempt_transition(
                    &self.oauth_dir,
                    ProductProviderId::Claude,
                    attempt_id,
                    ProductOnboardingState::ErrorRedacted,
                    Some("cancelled".to_string()),
                );
                Ok(())
            }
            ("codex", OAuthAttempt::Codex { cancelled, .. }) => {
                cancelled.store(true, Ordering::Release);
                record_onboarding_attempt_transition(
                    &self.oauth_dir,
                    ProductProviderId::Codex,
                    attempt_id,
                    ProductOnboardingState::ErrorRedacted,
                    Some("cancelled".to_string()),
                );
                Ok(())
            }
            _ => Err("oauth attempt does not match provider".into()),
        }
    }

    /// Complete the Claude manual login: the operator pastes the
    /// `code#state` shown by claude.ai. Look up the PKCE verifier by state, exchange, and
    /// persist the token.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_complete(&self, attempt_id: &str, pasted: &str) -> Result<String, String> {
        let (code, state_opt) = isyncyou_agent::oauth::parse_pasted_code(pasted);
        let state = state_opt.ok_or("the pasted code is missing its #state part")?;
        let fail = |closed_code: &str, wire_error: &str| -> Result<String, String> {
            record_onboarding_attempt_transition(
                &self.oauth_dir,
                ProductProviderId::Claude,
                attempt_id,
                ProductOnboardingState::ErrorRedacted,
                Some(closed_code.to_string()),
            );
            Err(wire_error.to_string())
        };
        // #639 T9: bind the pasted code to the named attempt — the attempt must exist, be a Claude
        // attempt, and its server-side state must equal the embedded #state (no cross-attempt reuse).
        // Claim the OAuth-manager entry and remove the attempt while holding the attempt lock, using
        // the same attempts -> OAuth-manager lock order as start/cancel. Cancel and completion now
        // have one linearization point and cannot consume/reinsert each other's state.
        let pending = {
            let mut attempts = self
                .oauth_attempts
                .lock()
                .map_err(|_| "the sign-in state is unavailable".to_string())?;
            let bound = matches!(
                attempts.get(attempt_id),
                Some(OAuthAttempt::Claude { state: pending, .. }) if pending == &state
            );
            if !bound {
                return Err("the pasted code does not match this sign-in".into());
            }
            let pending = self.oauth.take(&state);
            attempts.remove(attempt_id);
            pending
        };
        let (verifier, redirect_uri) = match pending {
            Some(pending) => pending,
            None => return fail("interrupted", "provider_connect_failed"),
        };
        let binding = self
            .oauth_lifecycle_bindings
            .lock()
            .ok()
            .and_then(|mut bindings| bindings.remove(attempt_id));
        let Some(binding) = binding.filter(|binding| binding.provider == ProductProviderId::Claude)
        else {
            return fail("lifecycle_binding_missing", "oauth_commit_failed");
        };
        if prepare_product_oauth_exchange(
            &self.cfg,
            &self.oauth_dir,
            &self.provider_leases,
            ProductProviderId::Claude,
            &binding.operation_id,
            attempt_id,
            (self.credential_now_ms)(),
        )
        .is_err()
        {
            return fail("exchange_intent_failed", "oauth_commit_failed");
        }
        let fail_exchange = |closed_code: &str, wire_error: &str| {
            let _ = mark_product_oauth_exchange_unknown(
                &self.cfg,
                &self.oauth_dir,
                &self.provider_leases,
                ProductProviderId::Claude,
                &binding.operation_id,
                "exchange_outcome_unknown",
                (self.credential_now_ms)(),
            );
            fail(closed_code, wire_error)
        };
        // #639 (F5): once the attempt is consumed, ANY failure of the exchange/commit is a terminal,
        // redacted transition for this attempt (the manual Claude flow has no callback thread to do
        // it), so a failed sign-in is durably recorded as error_redacted and is never resumed.
        let cfg = match self.load_oauth_config() {
            Ok(cfg) => cfg,
            Err(_) => return fail_exchange("policy_unavailable", "provider_connect_failed"),
        };
        let http = match isyncyou_agent::http::HttpTransport::shared() {
            Ok(http) => http,
            Err(_) => {
                return fail_exchange("transport_unavailable", "provider_connect_failed");
            }
        };
        let token = match isyncyou_agent::oauth::exchange(
            &http,
            &cfg,
            &code,
            &verifier,
            &redirect_uri,
            &state,
        ) {
            Ok(token) => token,
            Err(_) => return fail_exchange("exchange_failed", "oauth_exchange_failed"),
        };
        let candidate = OAuthCandidateMaterial {
            provider: ProductProviderId::Claude,
            access_token: token.access_token,
            refresh_token: token.refresh_token,
            expires_at_ms: (self.credential_now_ms)().saturating_add(token.expires_in * 1_000),
            provider_account_id: None,
        };
        let committed = self.process_oauth_candidate_with_transport(
            ProductProviderId::Claude,
            &binding.operation_id,
            candidate,
            CandidateIdentityDecision::Unavailable,
            http.as_ref(),
        );
        match committed {
            Ok(result) if result.state == "connected" => {}
            Ok(result) if result.state == "candidate_cleanup" => {
                return fail(result.code, "oauth_candidate_cleanup_required");
            }
            Ok(_) => return fail("commit_failed", "oauth_commit_failed"),
            Err(error) => return fail_exchange("commit_failed", &error),
        }
        Ok("connected".to_string())
    }

    /// The loopback callback path (kept for the auto flow); exchange
    /// the code with the stored verifier + state and persist the token, then show a page.
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn oauth_callback(&self, code: &str, state: &str) -> Result<String, String> {
        // The loopback callback must name a currently active Claude attempt, not merely a state
        // that happens to remain in the OAuth manager. This gives failures a durable attempt-keyed
        // terminal journal entry and prevents a stale callback from consuming another flow.
        let (attempt_id, pending) = {
            let mut attempts = self
                .oauth_attempts
                .lock()
                .map_err(|_| "oauth_callback_failed".to_string())?;
            let attempt_id = attempts
                .iter()
                .find_map(|(attempt_id, attempt)| {
                    matches!(attempt, OAuthAttempt::Claude { state: pending, .. } if pending == state)
                        .then(|| attempt_id.clone())
                })
                .ok_or_else(|| "oauth_callback_failed".to_string())?;
            let pending = self.oauth.take(state);
            attempts.remove(&attempt_id);
            (attempt_id, pending)
        };
        let fail = |closed_code: &str, wire_error: &str| -> Result<String, String> {
            record_onboarding_attempt_transition(
                &self.oauth_dir,
                ProductProviderId::Claude,
                &attempt_id,
                ProductOnboardingState::ErrorRedacted,
                Some(closed_code.to_string()),
            );
            Err(wire_error.to_string())
        };
        let (verifier, redirect_uri) = match pending {
            Some(pending) => pending,
            None => return fail("interrupted", "oauth_callback_failed"),
        };
        let binding = self
            .oauth_lifecycle_bindings
            .lock()
            .ok()
            .and_then(|mut bindings| bindings.remove(&attempt_id));
        let Some(binding) = binding.filter(|binding| binding.provider == ProductProviderId::Claude)
        else {
            return fail("lifecycle_binding_missing", "oauth_commit_failed");
        };
        if prepare_product_oauth_exchange(
            &self.cfg,
            &self.oauth_dir,
            &self.provider_leases,
            ProductProviderId::Claude,
            &binding.operation_id,
            &attempt_id,
            (self.credential_now_ms)(),
        )
        .is_err()
        {
            return fail("exchange_intent_failed", "oauth_commit_failed");
        }
        let fail_exchange = |closed_code: &str, wire_error: &str| {
            let _ = mark_product_oauth_exchange_unknown(
                &self.cfg,
                &self.oauth_dir,
                &self.provider_leases,
                ProductProviderId::Claude,
                &binding.operation_id,
                "exchange_outcome_unknown",
                (self.credential_now_ms)(),
            );
            fail(closed_code, wire_error)
        };
        let cfg = match self.load_oauth_config() {
            Ok(cfg) => cfg,
            Err(_) => return fail_exchange("policy_unavailable", "provider_connect_failed"),
        };
        let http = match isyncyou_agent::http::HttpTransport::shared() {
            Ok(http) => http,
            Err(_) => {
                return fail_exchange("transport_unavailable", "provider_connect_failed");
            }
        };
        let token = match isyncyou_agent::oauth::exchange(
            &http,
            &cfg,
            code,
            &verifier,
            &redirect_uri,
            state,
        ) {
            Ok(token) => token,
            Err(_) => return fail_exchange("exchange_failed", "oauth_exchange_failed"),
        };
        let candidate = OAuthCandidateMaterial {
            provider: ProductProviderId::Claude,
            access_token: token.access_token,
            refresh_token: token.refresh_token,
            expires_at_ms: (self.credential_now_ms)().saturating_add(token.expires_in * 1_000),
            provider_account_id: None,
        };
        let committed = self.process_oauth_candidate_with_transport(
            ProductProviderId::Claude,
            &binding.operation_id,
            candidate,
            CandidateIdentityDecision::Unavailable,
            http.as_ref(),
        );
        match committed {
            Ok(result) if result.state == "connected" => {}
            Ok(result) if result.state == "candidate_cleanup" => {
                return fail(result.code, "oauth_candidate_cleanup_required");
            }
            Ok(_) | Err(_) => return fail_exchange("commit_failed", "oauth_commit_failed"),
        }
        Ok(Self::OAUTH_SUCCESS_HTML.to_string())
    }

    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn status_json(&self) -> String {
        let revision = agent_status_store_revision(&self.oauth_dir);
        let mut status = if let Some(status) =
            revision.and_then(|revision| self.hot_agent_status.get(revision))
        {
            status
        } else {
            // #639 (F2): take the ENTIRE status snapshot — credential_state, per-provider readiness,
            // the selected provider, and the onboarding projection — under ONE product-runtime-gate hold,
            // so a concurrent set_model / OAuth completion / turn build can never make status report a
            // mix of two revisions. (Readiness is host-verified: Active policy-bound bundle + matching
            // activation + static attestation, not credential presence; experimental never qualifies.)
            let (claude_state, codex_state, settings, claude, codex, onboarding) = {
                match self.product_runtime_gate.lock() {
                    Ok(_gate) => match acquire_product_runtime_file_lock(&self.oauth_dir) {
                        Ok(_file_gate) => {
                            let claude_state = self
                                .product_credential_status("claude")
                                .unwrap_or("reconnect_required");
                            let codex_state = self
                                .product_credential_status("codex")
                                .unwrap_or("reconnect_required");
                            let settings = self.agent_settings();
                            let selected = settings.as_ref().map(|settings| settings.provider);
                            (
                                claude_state,
                                codex_state,
                                settings,
                                self.provider_ready(ProductProviderId::Claude),
                                self.provider_ready(ProductProviderId::Codex),
                                self.onboarding_projection(selected),
                            )
                        }
                        Err(_) => failed_product_status_snapshot(),
                    },
                    Err(_) => failed_product_status_snapshot(),
                }
            };
            fn failed_product_status_snapshot() -> (
                &'static str,
                &'static str,
                Option<AgentSettingsSnapshot>,
                bool,
                bool,
                serde_json::Value,
            ) {
                let failed_provider = || {
                    serde_json::json!({
                        "state": "error_redacted",
                        "error_code": "onboarding_failed",
                        "steps": ONBOARDING_SUCCESS_CHAIN.iter().map(|step| {
                            serde_json::json!({ "key": step.wire(), "complete": false })
                        }).collect::<Vec<_>>(),
                    })
                };
                (
                    "reconnect_required",
                    "reconnect_required",
                    None,
                    false,
                    false,
                    serde_json::json!({
                        "selected_provider": serde_json::Value::Null,
                        "selected_state": "error_redacted",
                        "providers": {
                            "claude": failed_provider(),
                            "codex": failed_provider(),
                        },
                    }),
                )
            }
            let reconnect_required =
                claude_state == "reconnect_required" || codex_state == "reconnect_required";
            // The selected provider alone drives `connected` + `provider`; there is no fall-back to
            // the other provider, and an unparseable selection reads not-connected (fail-closed).
            let selected_id = settings.as_ref().map(|settings| settings.provider);
            let connected = match selected_id {
                Some(ProductProviderId::Claude) => claude,
                Some(ProductProviderId::Codex) => codex,
                None => false,
            };
            let provider = match selected_id {
                Some(id) => id.wire(),
                None => "",
            };
            let model = settings
                .as_ref()
                .map(|settings| settings.model.clone())
                .unwrap_or_default();
            let reasoning_effort = settings
                .as_ref()
                .and_then(|settings| settings.reasoning_effort)
                .map(isyncyou_agent::CodexReasoningEffort::as_str)
                .unwrap_or("");
            let selected_provider = selected_id.map(ProductProviderId::wire).unwrap_or("");
            let model_list = |models: &[ProductModelSpec]| -> serde_json::Value {
                models
                    .iter()
                    .map(|spec| serde_json::json!({ "id": spec.id, "label": spec.label }))
                    .collect()
            };
            let option_list = |options: &[(&str, &str)]| -> serde_json::Value {
                options
                    .iter()
                    .map(|(id, label)| serde_json::json!({ "id": id, "label": label }))
                    .collect()
            };
            let mut status = serde_json::json!({
                "connected": connected,
                "enabled": true,
                "provider": provider,
                "selected_provider": selected_provider,
                "model": model,
                "reasoning_effort": reasoning_effort,
                "claude": claude,
                "codex": codex,
                "credential_state": { "claude": claude_state, "codex": codex_state },
                "control_store_state": self.control_store_state,
                "reconnect_required": reconnect_required,
                "models": {
                    "claude": model_list(CLAUDE_MODELS),
                    "codex": model_list(CODEX_MODELS)
                },
                "reasoning_efforts": option_list(CODEX_REASONING_EFFORTS),
            });
            if let Some(usage) = selected_id.and_then(|provider| {
                self.last_usage
                    .lock()
                    .ok()
                    .and_then(|usage| usage.get(&provider).cloned())
            }) {
                status["usage"] = usage.to_public_json();
            }
            // #639 T9: the per-provider onboarding projection drives the first-run wizard. It survives
            // journal TTL (a ready provider reports all steps complete from the durable activation).
            status["onboarding"] = onboarding;
            status["account_lifecycle"] = serde_json::json!({
                "claude": account_lifecycle_projection(
                    self,
                    ProductProviderId::Claude,
                    claude_state,
                    claude,
                ),
                "codex": account_lifecycle_projection(
                    self,
                    ProductProviderId::Codex,
                    codex_state,
                    codex,
                ),
            });
            if let Some(revision) = revision {
                self.hot_agent_status.replace(revision, status.clone());
            }
            status
        };

        if let Some(object) = status.as_object_mut() {
            object.remove("usage");
        }
        let selected_id = status
            .get("selected_provider")
            .and_then(serde_json::Value::as_str)
            .and_then(ProductProviderId::parse);
        if let Some(usage) = selected_id.and_then(|provider| {
            self.last_usage
                .lock()
                .ok()
                .and_then(|usage| usage.get(&provider).cloned())
        }) {
            status["usage"] = usage.to_public_json();
        }
        for provider in [ProductProviderId::Claude, ProductProviderId::Codex] {
            let counts = self.provider_leases.counts(provider);
            let node = &mut status["account_lifecycle"][provider.wire()];
            let active_operation = node
                .get("resume_operation_id")
                .is_some_and(serde_json::Value::is_string);
            node["busy"] =
                serde_json::json!(active_operation || counts.shared > 0 || counts.exclusive > 0);
        }
        status.to_string()
    }

    /// Persist the switcher's provider+model selection (validated against the offered lists).
    #[cfg(any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    ))]
    fn set_model(
        &self,
        provider: &str,
        model: &str,
        reasoning_effort: Option<&str>,
    ) -> Result<(), String> {
        // Selection may change while existing turns hold shared leases, but it cannot overtake a
        // provider refresh or lifecycle mutation. Acquire both shared leases in fixed provider order
        // before the short runtime snapshot lock so a refresh can revalidate selection after I/O.
        let claude_operation =
            account_lifecycle::mint_operation_id().map_err(|_| "product_busy".to_string())?;
        let _claude = self
            .provider_leases
            .acquire_shared(
                &self.oauth_dir,
                ProductProviderId::Claude,
                claude_operation,
                account_lifecycle::ProviderOperationKind::Turn,
            )
            .map_err(|_| "product_busy".to_string())?;
        let codex_operation =
            account_lifecycle::mint_operation_id().map_err(|_| "product_busy".to_string())?;
        let _codex = self
            .provider_leases
            .acquire_shared(
                &self.oauth_dir,
                ProductProviderId::Codex,
                codex_operation,
                account_lifecycle::ProviderOperationKind::Turn,
            )
            .map_err(|_| "product_busy".to_string())?;
        let _gate = self
            .product_runtime_gate
            .try_lock()
            .map_err(|_| "product_busy".to_string())?;
        let _file_gate = acquire_product_runtime_file_lock(&self.oauth_dir)?;
        self.set_agent_settings_with_effort(provider, model, reasoning_effort)
    }
}

/// Web-UI archive integrity verify (#528): re-hash every archived body and
/// persist per-item status. Local-only (reads on-disk bodies, writes the store),
/// so it needs no token/network and is always available.
pub struct DaemonVerify {
    cfg: Config,
}
impl isyncyou_webui::VerifyHandler for DaemonVerify {
    fn verify(&self, account: &str) -> Result<String, String> {
        isyncyou_engine::verify_account(&self.cfg, account).map(|r| r.summary())
    }
}

/// Web-UI mutable settings (#559): persist the cloud-poll interval to the config
/// file AND update the live value the sync loop reads, so a change takes effect
/// without a daemon restart.
pub struct DaemonSettings {
    config_path: PathBuf,
    live_interval: Arc<AtomicU64>,
}
impl isyncyou_webui::SettingsHandler for DaemonSettings {
    fn set_poll_interval_secs(&self, secs: u64) -> Result<(), String> {
        let secs = secs.clamp(1, 3600);
        // apply to the running loop immediately, then persist for the next start
        self.live_interval.store(secs, Ordering::Relaxed);
        let mut cfg = Config::load(&self.config_path)?;
        cfg.sync.poll_interval_secs = secs;
        cfg.save(&self.config_path)
    }
}

/// Web-UI OneDrive per-folder mode (#651): reads the account's mode policy **fresh** from
/// the config file (so a prior POST is reflected — the Router holds `config` by value) and
/// persists a folder set/clear back to it (`load → mutate → validate → save`, like
/// `DaemonSettings`).
pub struct DaemonOneDriveMode {
    config_path: PathBuf,
}
impl isyncyou_webui::OneDriveModeHandler for DaemonOneDriveMode {
    fn modes(&self, account: &str) -> Result<OneDriveModes, String> {
        Ok(Config::load(&self.config_path)?
            .onedrive_modes
            .get(account)
            .cloned()
            .unwrap_or_default())
    }
    fn set_folder(
        &self,
        account: &str,
        folder_id: &str,
        mode: Option<OneDriveMode>,
    ) -> Result<(), String> {
        let mut cfg = Config::load(&self.config_path)?;
        let modes = cfg.onedrive_modes.entry(account.to_string()).or_default();
        match mode {
            Some(m) => {
                modes.folder_modes.insert(folder_id.to_string(), m);
            }
            None => {
                modes.folder_modes.remove(folder_id);
            }
        }
        cfg.validate().map_err(|errs| errs.join("; "))?;
        cfg.save(&self.config_path)
    }
}

/// Web-UI live-mail write (#561): each verb resolves the full write token
/// (`Mail.ReadWrite` + `Mail.Send`) from the cached `login --write` and pushes the
/// change to Microsoft 365 via the engine `MailWriter`. Trait calls are fully
/// qualified so they hit the engine layer, never the inherent `GraphClient`
/// methods that share their names. The UI for these lands in #563.
pub struct DaemonMailWrite {
    cfg: Config,
}
impl isyncyou_webui::MailWriteHandler for DaemonMailWrite {
    #[allow(clippy::too_many_arguments)]
    fn send(
        &self,
        account: &str,
        subject: &str,
        body_html: &str,
        to: &[String],
        cc: &[String],
        bcc: &[String],
        importance: Option<&str>,
        request_read_receipt: bool,
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::send_new(
            &w,
            subject,
            body_html,
            to,
            cc,
            bcc,
            importance,
            request_read_receipt,
        )
    }
    fn reply(
        &self,
        account: &str,
        message_id: &str,
        comment: &str,
        all: bool,
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::reply(&w, message_id, comment, all)
    }
    fn forward(
        &self,
        account: &str,
        message_id: &str,
        comment: &str,
        to: &[String],
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::forward(&w, message_id, comment, to)
    }
    fn reply_html(
        &self,
        account: &str,
        message_id: &str,
        body_html: &str,
        all: bool,
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::reply_html(&w, message_id, body_html, all)
    }
    fn forward_html(
        &self,
        account: &str,
        message_id: &str,
        body_html: &str,
        to: &[String],
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::forward_html(&w, message_id, body_html, to)
    }
    fn move_to(
        &self,
        account: &str,
        message_id: &str,
        destination_id: &str,
    ) -> Result<String, String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::move_to(&w, message_id, destination_id)
    }
    fn set_read(&self, account: &str, message_id: &str, is_read: bool) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::set_read(&w, message_id, is_read)
    }
    fn set_flag(
        &self,
        account: &str,
        message_id: &str,
        flag_status: &str,
        due: Option<&str>,
        tz: &str,
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::set_flag(&w, message_id, flag_status, due, tz)
    }
    fn set_categories(
        &self,
        account: &str,
        message_id: &str,
        categories: &[String],
    ) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::set_categories(&w, message_id, categories)
    }
    fn create_draft(
        &self,
        account: &str,
        subject: &str,
        body_html: &str,
        to: &[String],
    ) -> Result<String, String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::create_draft(&w, subject, body_html, to)
    }
    fn send_draft(&self, account: &str, message_id: &str) -> Result<(), String> {
        let w = isyncyou_engine::mail_writer(&self.cfg, account)?;
        isyncyou_engine::MailWriter::send_draft(&w, message_id)
    }
}

