#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(serde::Deserialize)]
#[serde(deny_unknown_fields)]
struct TodoDeleteBatchItem {
    list: String,
    id: String,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
#[derive(serde::Deserialize)]
#[serde(deny_unknown_fields)]
struct TodoDeleteBatchPayload {
    items: Vec<TodoDeleteBatchItem>,
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn execute_todo_delete_batch(
    handler: &dyn isyncyou_webui::TaskWriteHandler,
    account: &str,
    expected: usize,
    bytes: &[u8],
) -> Result<serde_json::Value, String> {
    let payload: TodoDeleteBatchPayload =
        serde_json::from_slice(bytes).map_err(|_| "mutation_intent_invalid".to_string())?;
    if payload.items.len() != expected || expected == 0 || expected > 1_000 {
        return Err("mutation_intent_invalid".into());
    }
    let mut unique = std::collections::HashSet::with_capacity(expected);
    for item in &payload.items {
        if item.list.is_empty()
            || item.list.len() > 512
            || item.id.is_empty()
            || item.id.len() > 512
            || !unique.insert((item.list.as_str(), item.id.as_str()))
        {
            return Err("mutation_intent_invalid".into());
        }
    }
    let items = payload
        .items
        .into_iter()
        .map(|item| (item.list, item.id))
        .collect::<Vec<_>>();
    handler.delete_batch(account, &items)?;
    Ok(serde_json::json!({ "ok": true, "deleted": expected }))
}

#[cfg(all(
    test,
    any(
        feature = "agent-oauth-providers",
        feature = "agent-subscription-experimental"
    )
))]
mod todo_delete_batch_tests {
    use super::*;

    #[derive(Default)]
    struct RecordingTaskWrite {
        items: std::sync::Mutex<Vec<(String, String, String)>>,
        batch_calls: std::sync::atomic::AtomicUsize,
    }

    impl isyncyou_webui::TaskWriteHandler for RecordingTaskWrite {
        fn create(
            &self,
            _account: &str,
            _list_id: &str,
            _task: &serde_json::Value,
        ) -> Result<String, String> {
            unreachable!()
        }

        fn update(
            &self,
            _account: &str,
            _list_id: &str,
            _task_id: &str,
            _task: &serde_json::Value,
        ) -> Result<(), String> {
            unreachable!()
        }

        fn complete(&self, _account: &str, _list_id: &str, _task_id: &str) -> Result<(), String> {
            unreachable!()
        }

        fn delete(&self, account: &str, list_id: &str, task_id: &str) -> Result<(), String> {
            self.items.lock().unwrap().push((
                account.to_string(),
                list_id.to_string(),
                task_id.to_string(),
            ));
            Ok(())
        }

        fn delete_batch(&self, account: &str, items: &[(String, String)]) -> Result<(), String> {
            self.batch_calls
                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            self.items.lock().unwrap().extend(
                items
                    .iter()
                    .map(|(list, task)| (account.to_string(), list.clone(), task.clone())),
            );
            Ok(())
        }

        fn checklist_add(
            &self,
            _account: &str,
            _list_id: &str,
            _task_id: &str,
            _title: &str,
        ) -> Result<String, String> {
            unreachable!()
        }

        fn checklist_toggle(
            &self,
            _account: &str,
            _list_id: &str,
            _task_id: &str,
            _item_id: &str,
            _checked: bool,
        ) -> Result<(), String> {
            unreachable!()
        }

        fn checklist_delete(
            &self,
            _account: &str,
            _list_id: &str,
            _task_id: &str,
            _item_id: &str,
        ) -> Result<(), String> {
            unreachable!()
        }

        fn list_create(&self, _account: &str, _name: &str) -> Result<String, String> {
            unreachable!()
        }

        fn list_delete(&self, _account: &str, _list_id: &str) -> Result<(), String> {
            unreachable!()
        }
    }

    #[test]
    fn todo_delete_batch_validates_all_items_before_executing_once() {
        let handler = RecordingTaskWrite::default();
        let payload =
            br#"{"items":[{"list":"list-a","id":"task-1"},{"list":"list-a","id":"task-2"}]}"#;
        assert_eq!(
            execute_todo_delete_batch(&handler, "controlled", 2, payload).unwrap(),
            serde_json::json!({ "ok": true, "deleted": 2 })
        );
        assert_eq!(handler.items.lock().unwrap().len(), 2);
        assert_eq!(
            handler
                .batch_calls
                .load(std::sync::atomic::Ordering::Relaxed),
            1
        );

        let duplicate =
            br#"{"items":[{"list":"list-a","id":"task-1"},{"list":"list-a","id":"task-1"}]}"#;
        assert_eq!(
            execute_todo_delete_batch(&handler, "controlled", 2, duplicate),
            Err("mutation_intent_invalid".into())
        );
        assert_eq!(
            execute_todo_delete_batch(&handler, "controlled", 3, payload),
            Err("mutation_intent_invalid".into())
        );
        assert_eq!(handler.items.lock().unwrap().len(), 2);
        assert_eq!(
            handler
                .batch_calls
                .load(std::sync::atomic::Ordering::Relaxed),
            1
        );
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
impl isyncyou_webui::MutationIntentHandler for DaemonMutationIntents {
    fn create(
        &self,
        request: isyncyou_webui::MutationIntentCreate,
    ) -> Result<isyncyou_webui::MutationIntentInfo, String> {
        self.store.create_mutation_intent(&request, unix_now_ms())
    }

    fn put_chunk(&self, chunk: isyncyou_webui::MutationIntentChunk) -> Result<(), String> {
        self.store.put_mutation_chunk(
            &chunk.owner,
            &chunk.request_id,
            &chunk.intent_id,
            chunk.index,
            chunk.offset,
            &chunk.chunk_sha256,
            &chunk.bytes,
            unix_now_ms(),
        )
    }

    fn commit(
        &self,
        owner: &str,
        request_id: &str,
        intent_id: &str,
        total_bytes: u64,
        sha256: &str,
    ) -> Result<serde_json::Value, String> {
        use isyncyou_webui::{MailWriteHandler as _, OneNoteWriteHandler as _};
        let material = self.store.begin_mutation_commit(
            owner,
            request_id,
            intent_id,
            total_bytes,
            sha256,
            unix_now_ms(),
        )?;
        let (purpose, source) = match material {
            agent_control_store::MutationCommitStart::Completed => {
                return Err("mutation_intent_already_completed".into())
            }
            agent_control_store::MutationCommitStart::Execute { purpose, source } => {
                (*purpose, source)
            }
        };
        let result = match purpose {
            isyncyou_webui::MutationPurpose::OnedriveUpload {
                account,
                parent,
                name,
            } => isyncyou_engine::upload_streaming_via_ledger(
                &self.onedrive.cfg,
                &account,
                &parent,
                &name,
                source.len(),
                sha256,
                |offset, len| source.read_range(offset, len),
            )
            .map(|id| serde_json::json!({ "ok": true, "id": id })),
            isyncyou_webui::MutationPurpose::OnedriveReplace { account, id, etag } => {
                match isyncyou_engine::replace_streaming_via_ledger(
                    &self.onedrive.cfg,
                    &account,
                    &id,
                    &etag,
                    source.len(),
                    sha256,
                    |offset, len| source.read_range(offset, len),
                )? {
                    isyncyou_engine::WriteOutcome::Applied(_) => {
                        Ok(serde_json::json!({ "ok": true }))
                    }
                    isyncyou_engine::WriteOutcome::Conflict => {
                        Err("mutation_intent_conflict".into())
                    }
                }
            }
            isyncyou_webui::MutationPurpose::MailBody {
                account,
                operation,
                target,
                recipients,
                cc,
                bcc,
                subject,
                importance,
                read_receipt,
                all,
            } => {
                let bytes = source.read_range(
                    0,
                    usize::try_from(source.len())
                        .map_err(|_| "mutation_intent_invalid".to_string())?,
                )?;
                let body = std::str::from_utf8(&bytes)
                    .map_err(|_| "mutation_intent_invalid".to_string())?;
                match operation.as_str() {
                    "send" => self.mail.send(
                        &account,
                        &subject,
                        body,
                        &recipients,
                        &cc,
                        &bcc,
                        importance.as_deref(),
                        read_receipt,
                    ),
                    "reply" => self.mail.reply_html(&account, &target, body, all),
                    "forward" => self.mail.forward_html(&account, &target, body, &recipients),
                    "draft" => self
                        .mail
                        .create_draft(&account, &subject, body, &recipients)
                        .map(|_| ()),
                    _ => Err("mutation_intent_invalid".into()),
                }
                .map(|()| serde_json::json!({ "ok": true }))
            }
            isyncyou_webui::MutationPurpose::OnenoteBody {
                account,
                operation,
                section_or_page,
                title,
            } => {
                let bytes = source.read_range(
                    0,
                    usize::try_from(source.len())
                        .map_err(|_| "mutation_intent_invalid".to_string())?,
                )?;
                let body = std::str::from_utf8(&bytes)
                    .map_err(|_| "mutation_intent_invalid".to_string())?;
                match operation.as_str() {
                    "create" => {
                        let html = onenote_page_html(&title, body);
                        self.onenote
                            .create(&account, &section_or_page, &html)
                            .map(|id| serde_json::json!({ "ok": true, "id": id }))
                    }
                    "append" => self
                        .onenote
                        .append(&account, &section_or_page, body)
                        .map(|()| serde_json::json!({ "ok": true })),
                    _ => Err("mutation_intent_invalid".into()),
                }
            }
            isyncyou_webui::MutationPurpose::TodoDeleteBatch {
                account,
                item_count,
            } => {
                let bytes = source.read_range(
                    0,
                    usize::try_from(source.len())
                        .map_err(|_| "mutation_intent_invalid".to_string())?,
                )?;
                let expected = usize::try_from(item_count)
                    .map_err(|_| "mutation_intent_invalid".to_string())?;
                execute_todo_delete_batch(&self.todo, &account, expected, &bytes)
            }
        }
        .map_err(|_| "mutation_intent_outcome_unknown".to_string())?;
        self.store.complete_mutation_commit(
            owner,
            request_id,
            intent_id,
            &result,
            unix_now_ms(),
        )?;
        Ok(result)
    }

    fn cancel(&self, owner: &str, request_id: &str, intent_id: &str) -> Result<(), String> {
        self.store
            .cancel_mutation_intent(owner, request_id, intent_id)
    }
}

#[cfg(any(
    feature = "agent-oauth-providers",
    feature = "agent-subscription-experimental"
))]
fn onenote_page_html(title: &str, body: &str) -> Vec<u8> {
    let escape = |value: &str| {
        value
            .replace('&', "&amp;")
            .replace('<', "&lt;")
            .replace('>', "&gt;")
    };
    let title = if title.is_empty() { "Untitled" } else { title };
    format!(
        "<!DOCTYPE html><html><head><title>{}</title></head><body><p>{}</p></body></html>",
        escape(title),
        escape(body).replace('\n', "</p><p>")
    )
    .into_bytes()
}

/// A short-lived account-private staging file holding an in-app upload/replace body (#657).
/// The cloud-write ledger reads the body from a local path (fresh, and on crash recovery), so a
/// WebUI request's in-memory bytes are staged here and removed on drop — even on an error path.
/// On Android, the active body key makes [`isyncyou_core::envelope::write_body_atomic`] persist a
/// sealed envelope instead of plaintext; desktop keeps its no-key plaintext compatibility.
struct TempBody(PathBuf);
impl TempBody {
    const DIR: &'static str = "upload-staging";
    const PREFIX: &'static str = "isyncyou-upload-";
    const STALE_AFTER: Duration = Duration::from_secs(24 * 60 * 60);

    fn write(cfg: &Config, account: &str, bytes: &[u8]) -> Result<Self, String> {
        let acc = cfg
            .accounts
            .iter()
            .find(|a| a.id == account)
            .ok_or_else(|| format!("no account '{account}'"))?;
        Self::write_in_dir(&acc.effective_cache_root().join(Self::DIR), bytes)
    }

    fn write_in_dir(dir: &std::path::Path, bytes: &[u8]) -> Result<Self, String> {
        static SEQ: AtomicU64 = AtomicU64::new(0);
        std::fs::create_dir_all(dir).map_err(|e| format!("create upload staging: {e}"))?;
        Self::cleanup_stale(dir);
        let n = SEQ.fetch_add(1, Ordering::Relaxed);
        let path = dir.join(format!("{}{}-{n}.bin", Self::PREFIX, std::process::id()));
        isyncyou_core::envelope::write_body_atomic(&path, bytes)
            .map_err(|e| format!("stage upload body: {e}"))?;
        Ok(Self(path))
    }

    fn cleanup_stale(dir: &std::path::Path) {
        let Ok(entries) = std::fs::read_dir(dir) else {
            return;
        };
        for entry in entries.flatten() {
            let path = entry.path();
            let Some(name) = path.file_name().and_then(|s| s.to_str()) else {
                continue;
            };
            if !name.starts_with(Self::PREFIX) {
                continue;
            }
            let stale = entry
                .metadata()
                .and_then(|m| m.modified())
                .ok()
                .and_then(|m| m.elapsed().ok())
                .is_some_and(|age| age >= Self::STALE_AFTER);
            if stale {
                let _ = std::fs::remove_file(path);
            }
        }
    }

    fn path(&self) -> &std::path::Path {
        self.0.as_path()
    }
}
impl Drop for TempBody {
    fn drop(&mut self) {
        let _ = std::fs::remove_file(&self.0);
    }
}

fn onedrive_ancestry<'a>(by_id: &HashMap<&'a str, &'a Item>, it: &'a Item) -> Vec<&'a str> {
    let mut out = Vec::new();
    let mut cur = it;
    for _ in 0..256 {
        let Some(parent) = cur.parent_remote_id.as_deref() else {
            break;
        };
        out.push(parent);
        match by_id.get(parent) {
            Some(next) => cur = next,
            None => break,
        }
    }
    out
}

fn onedrive_effective_mode(
    cfg: &Config,
    account: &str,
    by_id: &HashMap<&str, &Item>,
    it: &Item,
) -> OneDriveMode {
    let modes = cfg.onedrive_modes.get(account).cloned().unwrap_or_default();
    let ancestry = onedrive_ancestry(by_id, it);
    modes.effective_mode(&it.remote_id, &ancestry)
}

const OFFLINE_BULK_FILE_THRESHOLD: usize = 2;
const OFFLINE_LARGE_BYTE_THRESHOLD: u64 = 256 * 1024 * 1024;

fn onedrive_ancestry_with_self<'a>(
    by_id: &HashMap<&'a str, &'a Item>,
    it: &'a Item,
) -> Vec<&'a str> {
    let mut out = Vec::with_capacity(1 + 8);
    out.push(it.remote_id.as_str());
    out.extend(onedrive_ancestry(by_id, it));
    out
}

fn onedrive_offline_scope_owner(
    modes: Option<&OneDriveModes>,
    ancestry: &[&str],
) -> Option<String> {
    let scopes = isyncyou_connectors::scopes_from_modes(modes);
    let offline_ids: BTreeSet<&str> = scopes
        .iter()
        .filter(|s| s.mode == isyncyou_connectors::Mode::Offline)
        .map(|s| s.folder_id.as_str())
        .collect();
    isyncyou_connectors::owning_scope(ancestry, &offline_ids).map(str::to_string)
}

fn classify_onedrive_move_risk_from_items(
    modes: Option<&OneDriveModes>,
    by_id: &HashMap<&str, &Item>,
    source_id: &str,
    destination_parent_id: &str,
) -> OneDriveMoveRisk {
    let Some(source) = by_id.get(source_id) else {
        return OneDriveMoveRisk::Unknown {
            reason: "missing_source".into(),
        };
    };
    let source_ancestry = onedrive_ancestry_with_self(by_id, source);
    let Some(source_scope) = onedrive_offline_scope_owner(modes, &source_ancestry) else {
        return OneDriveMoveRisk::Low;
    };

    let destination_scope = if destination_parent_id.is_empty() {
        None
    } else {
        let Some(destination) = by_id.get(destination_parent_id) else {
            return OneDriveMoveRisk::Unknown {
                reason: "missing_destination".into(),
            };
        };
        let destination_ancestry = onedrive_ancestry_with_self(by_id, destination);
        onedrive_offline_scope_owner(modes, &destination_ancestry)
    };

    if destination_scope.as_deref() == Some(source_scope.as_str()) {
        OneDriveMoveRisk::Low
    } else {
        OneDriveMoveRisk::MoveOutOfProtected {
            source_scope,
            destination_scope,
        }
    }
}

fn offline_mode_risk(
    requires_confirmation: bool,
    file_count: usize,
    known_bytes: u64,
    unknown_size_files: usize,
    reason: &str,
) -> OfflineModeRisk {
    OfflineModeRisk {
        requires_confirmation,
        file_count,
        known_bytes,
        unknown_size_files,
        reason: reason.into(),
    }
}

fn estimate_onedrive_offline_mode_risk_from_items(
    by_id: &HashMap<&str, &Item>,
    folder_id: &str,
) -> OfflineModeRisk {
    let Some(folder) = by_id.get(folder_id) else {
        return offline_mode_risk(true, 0, 0, 0, "unknown_folder");
    };
    if folder.item_type != "folder" {
        return offline_mode_risk(true, 0, 0, 0, "not_folder");
    }

    let mut file_count = 0usize;
    let mut known_bytes = 0u64;
    let mut unknown_size_files = 0usize;
    for item in by_id.values().copied() {
        if item.item_type != "file" {
            continue;
        }
        let ancestry = onedrive_ancestry(by_id, item);
        if !ancestry.contains(&folder_id) {
            continue;
        }
        file_count += 1;
        match item.size {
            Some(size) if size >= 0 => known_bytes = known_bytes.saturating_add(size as u64),
            _ => unknown_size_files += 1,
        }
    }

    if file_count >= OFFLINE_BULK_FILE_THRESHOLD {
        offline_mode_risk(
            true,
            file_count,
            known_bytes,
            unknown_size_files,
            "bulk_files",
        )
    } else if known_bytes >= OFFLINE_LARGE_BYTE_THRESHOLD {
        offline_mode_risk(
            true,
            file_count,
            known_bytes,
            unknown_size_files,
            "large_bytes",
        )
    } else if unknown_size_files > 0 && file_count > 0 {
        offline_mode_risk(
            true,
            file_count,
            known_bytes,
            unknown_size_files,
            "unknown_size",
        )
    } else {
        offline_mode_risk(false, file_count, known_bytes, unknown_size_files, "small")
    }
}

fn onedrive_body_bytes(
    acc: &isyncyou_core::AccountConfig,
    by_id: &HashMap<&str, &Item>,
    it: &Item,
) -> Result<Option<Vec<u8>>, String> {
    if it.body_state.as_deref() != Some("available") {
        return Ok(None);
    }
    let Some(rel) = isyncyou_connectors::local_rel_path(by_id, it) else {
        return Ok(None);
    };
    let root = if it.body_location.as_deref() == Some("cache") {
        acc.effective_cache_root()
    } else {
        acc.sync_root.clone()
    };
    let path = root.join(rel);
    let body = if isyncyou_core::envelope::body_envelope_required_for_process() {
        isyncyou_core::envelope::read_sealed_body_required(&path)
    } else {
        isyncyou_core::envelope::read_body(&path)
    };
    match body {
        Ok(bytes) => Ok(Some(bytes)),
        Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
        Err(e) => Err(format!("read cached OneDrive body: {e}")),
    }
}

/// Live on-demand OneDrive content fetch for the web UI (#649, Mode 1 online), plus
/// Mode-2 lazy body caching (#660): local bodies win first, sync-mode misses download into
/// `cache_root`, and online-mode misses stay live/no-store.
pub struct DaemonOneDriveOpen {
    config_path: PathBuf,
    progress: isyncyou_connectors::SharedProgress,
}
impl DaemonOneDriveOpen {
    fn cfg(&self) -> Result<Config, String> {
        Config::load(&self.config_path).map_err(|e| format!("load config: {e}"))
    }
}
impl isyncyou_webui::OneDriveOpenHandler for DaemonOneDriveOpen {
    fn download(&self, account: &str, id: &str) -> Result<Vec<u8>, String> {
        let cfg = self.cfg()?;
        let acc = cfg
            .accounts
            .iter()
            .find(|a| a.id == account)
            .ok_or_else(|| format!("no account '{account}'"))?;
        let store = isyncyou_store::Store::open(acc.archive_root.join(".isyncyou-store.db")).ok();
        if let Some(store) = store.as_ref() {
            let items = store
                .items_by_service(account, "onedrive")
                .map_err(|e| format!("query OneDrive store: {e}"))?;
            let by_id: HashMap<&str, &Item> =
                items.iter().map(|it| (it.remote_id.as_str(), it)).collect();
            if let Some(it) = by_id.get(id) {
                if let Some(bytes) = onedrive_body_bytes(acc, &by_id, it)? {
                    return Ok(bytes);
                }
                if it.item_type == "file"
                    && onedrive_effective_mode(&cfg, account, &by_id, it) == OneDriveMode::Sync
                {
                    let Some(rel) = isyncyou_connectors::local_rel_path(&by_id, it) else {
                        return Err("sync-mode open: no local path".into());
                    };
                    let full = acc.effective_cache_root().join(&rel);
                    if let Some(parent) = full.parent() {
                        std::fs::create_dir_all(parent)
                            .map_err(|e| format!("create cache parent: {e}"))?;
                    }
                    let client = isyncyou_engine::onedrive_lister(&cfg, account)?;
                    store
                        .set_content_state(
                            account,
                            "onedrive",
                            id,
                            Some("cached"),
                            Some("cache"),
                            Some("downloading"),
                            None,
                        )
                        .map_err(|e| format!("mark sync download: {e}"))?;
                    let name = rel.file_name().and_then(|s| s.to_str()).unwrap_or("file");
                    let total = it.size.unwrap_or(0).max(0) as u64;
                    self.progress.begin(id, name, total);
                    let downloaded = client
                        .download_content_with_progress(id, &mut |done| {
                            self.progress.advance(id, done);
                        })
                        .map_err(|e| e.to_string());
                    match downloaded {
                        Ok(bytes) => {
                            let result = (|| {
                                isyncyou_core::envelope::write_body_atomic(&full, &bytes)
                                    .map_err(|e| format!("write cache body: {e}"))?;
                                store
                                    .set_sync_state(account, "onedrive", id, "clean")
                                    .map_err(|e| format!("mark sync clean: {e}"))?;
                                store
                                    .set_content_state(
                                        account,
                                        "onedrive",
                                        id,
                                        Some("cached"),
                                        Some("cache"),
                                        Some("available"),
                                        Some(&unix_now()),
                                    )
                                    .map_err(|e| format!("mark cache available: {e}"))?;
                                Ok::<(), String>(())
                            })();
                            self.progress.finish(id);
                            result?;
                            return Ok(bytes);
                        }
                        Err(e) => {
                            let _ = store.set_content_state(
                                account,
                                "onedrive",
                                id,
                                Some("cached"),
                                Some("cache"),
                                Some("failed"),
                                None,
                            );
                            self.progress.finish(id);
                            return Err(e);
                        }
                    }
                }
            }
        }
        let client = isyncyou_engine::onedrive_lister(&cfg, account)?;
        isyncyou_graph::GraphClient::download_content(&client, id).map_err(|e| e.to_string())
    }
}

